eiten für Veranstaltungen (optional auch per Scannen eines QR-Codes).&#10;&#10;Es werden Gruppen innerhalb der Veranstaltung berücksichtigt und die Anzeige kann auch umgestellt werden, dass die Teilnehmenden nach Gruppen unterteilt werden.&#10;&#10;ChangeLog:&#10;&#10;###### Version 1.7 (25. Oktober 2024)&#10;&#10;- Eingaben können durch gleichzeitige Bearbeitung nicht mehr überschrieben werden&#10;- Bei gleichzeitiger Eingabe werden die Daten nachgeladen, so dass man immer den aktuellen Stand sieht&#10;- Neue Funktionen und Darstellung für Admins auf der Verwaltungsseite. Im Adminbereich kann die Anwesenheitsliste und deren Optionen nun für mehrere Veranstaltungen auf einmal eingestellt werden.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/ed93ec8f611acbd961267001fb67f7c7\">\n    <release version=\"1.9.3\" studipMinVersion=\"5.1\" studipMaxVersion=\"6.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2b3e5671632158cb42e4f6a6030d2088\"/>\n    <release version=\"1.8.6.1\" studipMinVersion=\"5.1\" studipMaxVersion=\"6.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/90df1aea1f3699e9d8617f18d9e1ed1f\"/>\n    <release version=\"1.8.3\" studipMinVersion=\"5.1\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4174b5eba75b32e4525e00a7d9a9b4d8\"/>\n    <release version=\"1.8\" studipMinVersion=\"5.1\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4f70ee7bb988e354a2d1389813893713\"/>\n    <release version=\"1.8\" studipMinVersion=\"5.1\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/cd5a0171c4ddc356a9ecde7117bf0ad4\"/>\n    <release version=\"1.7.2\" studipMinVersion=\"5.1\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e319b4e31b868cb62bbd2fb4bb54cac5\"/>\n    <release version=\"1.7\" studipMinVersion=\"5.1\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/74357bc101b19e295a690a9f20fe69d4\"/>\n    <release version=\"1.6\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c8072d735fbca7c3d97ac0f4dc4f0fd8\"/>\n    <release version=\"1.5.2\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c7573e0e5c0e7108f0889776a8ba1157\"/>\n    <release version=\"1.5.1\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8b24f7433652b99b7f5910d5e513c50c\"/>\n  </plugin>\n  <plugin displayname=\"Anwesenheitsliste\" name=\"ParticipantsAttendancePlugin\" homepage=\"https://develop.studip.de\" short_description=\"Die Anwesenheitsliste kann in der Druckansicht gezeigt werden, oder als Excel Tabelle heruntergeladen werden. Durch den globalen Schalter PARTICIPANTS_ATTENDANCE_PLUGIN_AUTO_ENABLE kann gesteuert werden, ob sich das Plugin automatisch aktiviert/deaktiviert bei allen Veranstaltungen, in Abhängikeit von Teilnehmerseite und Ablaufplan.\" description=\"\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/1f5b833aef57aa6563139f93b97d0c4b\" score=\"9.1165086152983\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/b35ba641b73cfdae1bd2b2b86cf98f8f\">\n    <release version=\"3\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/43a5fabfc0885b9c32d7b2057bda9190\"/>\n    <release version=\"124\" studipMinVersion=\"5.3\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/90bcd18065ca93a175f10eec53384760\"/>\n    <release version=\"120\" studipMinVersion=\"5.3\" studipMaxVersion=\"5.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/aa99f7ef4992280d5c06482928f52867\"/>\n    <release version=\"118.2.1\" studipMinVersion=\"5.3.99\" studipMaxVersion=\"5.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/220e36be3217f8367d95f4327e09e67f\"/>\n    <release version=\"118.1\" studipMinVersion=\"4.9.99\" studipMaxVersion=\"5.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/09aa266215d587ce4d2ba2d4291387d5\"/>\n    <release version=\"113\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.99.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/935195b47d7c015486109629dfc3c69e\"/>\n    <release version=\"110\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/baff97aea34815babf84d5036bd29f5a\"/>\n    <release version=\"108\" studipMinVersion=\"3.2\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/821749befce3a6265e67bb4ad771e216\"/>\n    <release version=\"107\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4bf12d8d1dbd720af66c732158c11c8b\"/>\n    <release version=\"105\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b2482a53fe47e1b2e7db5a7eeb5d21b4\"/>\n    <release version=\"103\" studipMinVersion=\"2.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/41453e8c02ffc4a3464a3c7d08560884\"/>\n  </plugin>\n  <plugin displayname=\"Arbeitsplatzvergabe [deprecated]\" name=\"Arbeitsplatzvergabe\" homepage=\"https://github.com/tubraunschweig/studip-WorkplaceAllocation\" short_description=\"Werkzeug für die Vergabe von Arbeitsplätzen an Studierende\" description=\"Das Plug-in erlaubt es Einrichtungen die Buchung von Zeitslots auf ihren studentischen Arbeitsplätzen im Stud.IP System zu organisieren. Nach Aktivierung des Plug-ins auf der Seite der Einrichtung können im Menüpunkt &amp;quot;Verwaltung&amp;quot; Arbeitsplätze erstellt und konfiguriert werden.&#10;&#10;Die Anmeldung für Zeitslots auf Arbeitsplätzen erfolgt über den Menüpunkt &amp;quot;Arbeitsplätze&amp;quot; auf der Seite der Einrichtung.&#10;&#10;&#10;&#10;  &#10;Featureliste:  &#10;  &#10;Erstellung von Arbeitsplätzen mit umfassenden Optionen für Zeitslots. Einstellungen für Tage, Öffnungszeiten, Pausen, Slotlänge, Limitierung des Anmeldezeitraums,   &#10;Besondere Optionen wie &amp;quot;Ein Termin pro Tag und Nutzer&amp;quot; oder &amp;quot;Termine nur für Mitglieder der Einrichtung&amp;quot;&#10;&#10;&#10;&#10;Zeitslots mit Link auf Profilseite des Nutzers, variabler Länge, Kommentarfunktion und nachträglicher Modifikationsmöglichkeit.  Blockingliste zur temporären Sperrung von Nutzern von den Arbeitsplätzen. Standardzeitspanne von 7 Tagen. Individuell modifizierbar.  &#10;&#10;Versendung von Stud.IP Nachrichten mit modifizierbaren Texten bei Erstellung, Modifizierung und Löschung von Zeitslots sowie Veränderungen der Blockingliste an Betroffene. &#10;&#10;Mailingliste zur Benachrichtigung einer frei zusammenstellbaren Gruppe von Nutzern bei Erstellung, Modifizierung und Löschung von Zeitslots. &#10;&#10;Druckfunktion für Öffnungszeiten aller Arbeitsplätze im PDF Format.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/4e373244e9cfa61071dafb2be1e6e9b7\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/a19ab7994feece51d30188cf5d797c1e\">\n    <release version=\"1.0\" studipMinVersion=\"4.1\" studipMaxVersion=\"4.6\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/0a148da12a79161940dddc5a2f7481b1\"/>\n  </plugin>\n  <plugin displayname=\"Archivierungsplugin\" name=\"ArchivierungsPlugin\" homepage=\"\" short_description=\" Massenarchivierungen von Veranstaltungen\" description=\"**Zu beachten:**&#10;&#10;Da das Archivieren von Veranstaltungen in Stud.IP seit Version 4.2 nicht mehr angeboten wird: https://develop.studip.de/trac/ticket/8538, wird dieses Plugin auch nicht mehr gepflegt.&#10;&#10;- Archivieren von vielen Veranstaltungen optional nach Semester und Institutionen&#10;- Übersicht über archivierte Veranstaltungen&#10;- Weitere Funktionen:- Rückgängig machen von unsauberem Archivieren&#10;- Schützen von Veranstaltungen\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/31cc3b4011020b8743ade7810d1e4302\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/1ffa543ca9e0f7bdfb4dea8ba686626e\">\n    <release version=\"4.0\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/997e447e348a7603aa7e2c3e3117dc00\"/>\n    <release version=\"3.2.1\" studipMinVersion=\"3.5\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/94debb0e477a822d81a35cb95857b3ef\"/>\n    <release version=\"3.2\" studipMinVersion=\"3.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e6826cfc7f30c68614eabd9d1e700d3c\"/>\n    <release version=\"3.0\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4d6c4845bc4e116967557abfa8f8a8ee\"/>\n  </plugin>\n  <plugin displayname=\"ArchivierungsPlugin\" name=\"ArchivierungsPlugin\" homepage=\"https://develop.studip.de\" short_description=\"Zentrale Archivierung/Löschung von Veranstaltungen durch Admins. Die Veranstaltungen können nach verschiedenen Kriterien eingeschränkt werden.\" description=\"\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/5c6b989378b09deb4b5a79b32a0aa0bc\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/6ef28963f759da5c036561a4cd783f7d\">\n    <release version=\"1.381\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/943476546f5558adde4792a19b3bff00\"/>\n    <release version=\"1.371\" studipMinVersion=\"2.5\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/36e4e884bca092e58a9122406b594463\"/>\n    <release version=\"1.37\" studipMinVersion=\"2.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4c570049a2b861f29527ffa9659bcf0e\"/>\n    <release version=\"1.36\" studipMinVersion=\"2.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/0976827c49ca1c2d08a947acaf6b9dc5\"/>\n    <release version=\"1.35\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/69c25377f64eab159e1d4eb456c16eb6\"/>\n  </plugin>\n  <plugin displayname=\"AskALotPlugin\" name=\"AskALotPlugin\" homepage=\"\" short_description=\"Mit diesem Plugin ist es möglich, mehrere Fragebögen mehreren Veranstaltungen zuzuweisen.\" description=\"Mit diesem Plugin ist es möglich, mehrere Fragebögen mehreren Veranstaltungen zuzuweisen. Das Plugin hängt sich unter Tools -&amp;gt; Fragebögen ein und stellt dort unter der Hauptansicht einen weiteren Navigationspunkt für Root- und Admin-Nutzer zur Verfügung.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/acab5552c7e6cbee9834a93a8c4260c1\">\n    <release version=\"1.1.1\" studipMinVersion=\"3.99\" studipMaxVersion=\"4.99.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8e7a59b1b0300ea22375a877f520baae\"/>\n    <release version=\"1.1\" studipMinVersion=\"3.99\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/30affb9fe166ef92bd767725221e809d\"/>\n    <release version=\"1.0.2\" studipMinVersion=\"3.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f2586a7fce808177e1e6d7821cf733c5\"/>\n    <release version=\"1.0.1\" studipMinVersion=\"3.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a6e67d86e4ac764cd0b685dceae8ac24\"/>\n    <release version=\"1.0\" studipMinVersion=\"3.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/99902332cd74101836a9e47577825cd6\"/>\n  </plugin>\n  <plugin displayname=\"Aufgaben\" name=\"AufgabenPlugin\" homepage=\"https://github.com/elan-ev/studip-aufgaben\" short_description=\"Aufgabentool für Stud.IP, welches ermöglicht zeitgesteuert Aufgaben für Teilnehmende einer Veranstaltung zu stellen. Teilnehmende können Antworttexte eingeben und bequem Dateien einreichen. Das Feedback kann ebenfalls in Textform oder mittels Dateien erfolgen. Der spezielle Uploader erlaubt das Hochladen von beliebig vielen Dateien auf einen Knopfdruck!\" description=\"Das neue Aufgabentool für Stud.IP!&#10;==================================&#10;&#10;Ein einfaches Plugin für zeitgesteuerte Aufgaben mit Text- und Dateiabgabe in Stud.IP.&#10;&#10;Was kann es?&#10;------------&#10;&#10;- Zeitgesteuert Aufgaben für Teilnehmende einer Veranstaltung stellen.&#10;- Teilnehmende können Antworttexte eingeben und bequem Dateien einreichen.&#10;- Es kann Feedback ebenfalls in Textform oder mittels Dateien erfolgen.&#10;- Der spezielle Uploader erlaubt das Hochladen von beliebig vielen Dateien auf einen Knopfdruck!&#10;&#10; &#10;&#10;Changelog&#10;=========&#10;&#10;Alle Änderungen und Releases unter:   &#10;https://github.com/elan-ev/studip-aufgaben/releases&#10;&#10; &#10;&#10;Kontakt&#10;=======&#10;&#10;Bei Fragen wenden Sie sich gerne an gloeggler@elan-ev.de\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/7a55b2ec8bd3d00efd7e02fe3dfef544\" score=\"9.7968166707008\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/a80c04ab1b073963effaa4cbb2a9a76f\">\n    <release version=\"1.7\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/15f5dc119aa13830b02aec649cf7286c\"/>\n    <release version=\"1.6\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.4.*\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f1e1ec5fa4e74afd190771142fd33a2a\"/>\n    <release version=\"1.5.9\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/689a5f24337cf607e80b2135af846eca\"/>\n    <release version=\"1.5.4\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c7cfc6ecb00ef3e08604701242e4d0a1\"/>\n    <release version=\"1.5.14\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.3\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/453ade8e403f0a9dd02b54220af6fdce\"/>\n    <release version=\"1.5.13\" studipMinVersion=\"4.0\" studipMaxVersio