rsion=\"1.13\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/525952165afeb296f83f41edea45d825\"/>\n    <release version=\"1.11\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/207e05edfd09e8c5b8fd5f7f88d72edc\"/>\n    <release version=\"1.10\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4bba07294463ea8a09d7978853f0e592\"/>\n  </plugin>\n  <plugin displayname=\"Ausleihe\" name=\"Ausleihe\" homepage=\"https://gitlab.studip.de/studip/plugins/Bookable\" short_description=\"Ressourcen Buchungen Verwaltung\" description=\"Mit dem “Ausleihe-Plugin&amp;quot; können Studierende oder Lehrende Ressourcen buchen.&#10;&#10;### Funktionen:&#10;&#10;- **Set-Buchungen:** Mehrere Ressourcen können gemeinsam als Set gebucht werden.&#10;- **Keine BuchungKollision:** Es ist nicht möglich, dass dasselbe Ressource gleichzeitig buchen.&#10;- **Buchungsbelegungsplan:** Für ein spezifische Ressourcen, Kategorien oder Sets.&#10;- **Benachrichtigungen:** Lehrende erhalten StudIP-Benachrichtigungen, wenn Studierende eine neue Buchungsanfrage erstellt – die Benachrichtigungs-Einstellungen sind pro Veranstaltung konfigurierbar.&#10;- **Buchungsstatus-Log:** Das Plugin nutzt die StudIP-Logs, um Änderungen am Buchungsstatus zu speichern.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/159d19f0813b65097131752811c6236c\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/6f627e9f1a7cdc2270e1fddece97816b\">\n    <release version=\"1.1.2\" studipMinVersion=\"5.4\" studipMaxVersion=\"6.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/512e2bbd35e14825798461ccc6060218\"/>\n    <release version=\"1.1.1\" studipMinVersion=\"5.4\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b7b34e4a48a24481354619d6a2033646\"/>\n    <release version=\"1.1\" studipMinVersion=\"5.4\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/7c07300c8221b34c44553fb39031b85e\"/>\n    <release version=\"1.0\" studipMinVersion=\"5.4\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8c07b709c44e89ce466d6abedddbced9\"/>\n  </plugin>\n  <plugin displayname=\"Auto Logout\" name=\"Auto Logout\" homepage=\"https://github.com/tleilax/studip-autologout\" short_description=\"Loggt den Nutzer nach einer definierbaren Anzahl von Minuten aus.Dieses Plugin stellt letztendlich den AutoLogout-Mechanismus wieder her, der zur 2.4 aus dem Kern entfernt wurde.Dabei wird in aktuellen Browsern der Zeitpunkt des Logouts über alle Tabs synchronisiert, so dass kein vergessener Tab zu einem frühzeitigen und unerwarteten Logout führen kann.\" description=\"\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"8.1337507745645\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/419d506a159524f47a78116bc3649a67\">\n    <release version=\"1.1.1\" studipMinVersion=\"2.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/cf2ae3ac83f9f2289b07320254bfed56\"/>\n    <release version=\"1.1\" studipMinVersion=\"2.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/21967b46815909b0120eab5ae7d67bfe\"/>\n    <release version=\"1.0\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/64d9a77ca764f81589417dea75d17059\"/>\n  </plugin>\n  <plugin displayname=\"Automatische Anmeldung\" name=\"CookieAuth\" homepage=\"https://gitlab.studip.de/studip/plugins/CookieAuth\" short_description=\"Ermöglicht optionale Anmeldung über einen dauerhaften Cookie\" description=\"CookieAuth&#10;==========&#10;&#10;adds optional authentication with persistent cookie to Stud.IP\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/36bd68dd98a729c5dfc2ca4947fceb61\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/53acfccb68bb0ba4465491633330769d\">\n    <release version=\"7\" studipMinVersion=\"4.0\" studipMaxVersion=\"5.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4955fb047b3c3ac2425fa5556bbcbb6a\"/>\n    <release version=\"6\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/540dc3b404bbe925491c82d70965a867\"/>\n    <release version=\"4\" studipMinVersion=\"2.4\" studipMaxVersion=\"3.5\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/3d62c8e893a961a1614f5fa3dbb77f33\"/>\n  </plugin>\n  <plugin displayname=\"BabelFish\" name=\"BabelFish\" homepage=\"https://github.com/Krassmus/BabelFish\" short_description=\"Ein Übersetzungstool für Stud.IP, mit dem man Nutzer-Inhalte in einem Klick übersetzen kann.\" description=\"Auch wenn Stud.IP und auch die Plugins oft in Deutsch und Englisch vorliegen, gibt es immer noch etliche Inhalte, die nie übersetzt werden: Nutzerinhalte. Wenn ein Lehrender eine Nachricht an die Studierenden schreibt, schreibt er/sie meist auf Deutsch. Aber wie kann man sicherstellen, dass Nichtmuttersprachler diese Nachricht auch korrekt verstehen?  &#10;  &#10; Mit diesem Plugin kann man etliche Inhalte, die von Nutzern stammen, übersetzen. Neben dem Inhalt taucht ein Fisch-Symbol (wie der BabelFisch aus Per Anhalter Durch Die Galaxis) auf. Und mit einem Klick sieht man an Ort und Stelle die Übersetzung in die Sprache, die man in Stud.IP eingestellt hat.  &#10;  &#10; Übersetzt werden&#10;&#10;- Ankündigungen&#10;- Forumsbeiträge&#10;- Stud.IP-Nachrichten&#10;- Wikiseiten&#10;&#10;  &#10; Damit die Übersetzungen funktionieren, muss man zudem einen Übersetzungsservice anmieten. Das Plugin unterstützt bisher nur DeepL, der in Deutschland ansässig ist und hinreichend guten Datenschutz bietet, sodass alle Informationen vertraulich behandelt werden. Andere Übersetzungsengines im Internet können auf Wunsch nachgerüstet werden.  &#10;  &#10; Man muss auf DeepL ein Konto erstellen, mit dem man deren API nutzen kann. Der API-Auth-Key muss dann noch unter Admin -&amp;gt; System -&amp;gt; Konfiguration BABELFISCH im Wert****BABELFISH_AUTHKEY gespeichert werden. Danach läuft das Plugin.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/7ed9b05a4a162eca0bb8658769102970\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/a1c6e02c2d74a44d2e9dcb4a9082cd40\">\n    <release version=\"1.0\" studipMinVersion=\"\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/273c745001d1b72e37d65d3bcc6b9a0c\"/>\n  </plugin>\n  <plugin displayname=\"BBB Sprechstunden\" name=\"BBBConsultation\" homepage=\"\" short_description=\"Erweitert die Sprechstundenverwaltung um die Möglichkeit BBB Räume für Termine anzulegen\" description=\"\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/f8a3ae9d2960f37bc2e878b905caa04d\">\n    <release version=\"1.1.27\" studipMinVersion=\"4.4\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f74d8de57be7b593b9e8bbc98f292cfa\"/>\n    <release version=\"1.1.26\" studipMinVersion=\"4.4\" studipMaxVersion=\"5.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/870fce59fa992feec592776638c0469f\"/>\n    <release version=\"1.1.21\" studipMinVersion=\"4.4\" studipMaxVersion=\"5.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8a5d1e420e69d27374d1e19889824edf\"/>\n    <release version=\"1.1.20\" studipMinVersion=\"4.4\" studipMaxVersion=\"5.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/777f68181cb25c71dd825b474a88fc25\"/>\n    <release version=\"1.1.19\" studipMinVersion=\"4.4\" studipMaxVersion=\"5.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/840c165fe2b50ec2841801b74bcca817\"/>\n  </plugin>\n  <plugin displayname=\"BeautifyLogin\" name=\"BeautifyLogin\" homepage=\"\" short_description=\"Statt dass die Seite bei einem Klick auf &amp;quot;Login&amp;quot; neu lädt, wird der Logindialog in einem Popup angezeigt. Dadurch soll er Login &amp;quot;flüssiger&amp;quot; wirken mit weniger Seitenwechseln.Theoretisch einsetzbar für alle Singlesignlogins und Standard-Login aber nicht intensiv getestet.\" description=\"****Hinweis für alle meine Plugin: Getestet bis Stud.IP 2.3.1, Support für künftige Versionen ungeklärt****&#10;&#10;  &#10;&#10; Solange die Login-Seite lädt, wird Ladebalken angezeigt, der ausgeblendet wird, sobald die Seite zur Verfügung steht.&#10;&#10; Dem Plugin ist eine Config-Datei beigelegt, mit der sich Größe und Aussehen des Iframes noch konfigurieren lassen.&#10;&#10; Hinweis:  Das Plugin bietet auch Hilfestellung bei fehlgeschlagenem Login. Das müsste bei einem Einsatz **auf jeden Fall angepasst werden**, bei Interesse kann man das eventuell generisch machen  In der Version 0.9.9.2 sind alle Variablen und Beschreibungen in der globalen Konfiguration. Das heißt, das Plugin ist komplett generisch.&#10;&#10;**Das Plugin muss logischerweise für nobody freigegeben werden!**&#10;&#10;  &#10;&#10; Hinweis: Sollte innerhalb von Stud.IP in einem Frame / IFrame eine andere Stud.IP-Seite geladen werden, so führt dies dazu, dass der Frame zerstört wird. Wäre eh eine seltsame Konstellation, aber ich sags ja nur :)&#10;&#10;  &#10;&#10; In Verbindung mit [StudipMobile ](?dispatch=show_plugin_details&amp;amp;plugin_id=471b30219c7cd1a4ded203fb80737ed6)ist das Plugin bei mobilen Geräten deaktiviert.&#10;&#10;  &#10;&#10; Version 0.2: Bugfix in Kombination mit MarkItUp-Plugin&#10;&#10; Version 0.8: Nun ueber die Stud.IP-globale Konfiguration konfigurierbar&#10;&#10; Version 0.9.9.2: Nun komplett generisch. Beschreibungen und Variablen befinden sich komplett in der Config. Nach der Installation müssen diese unter &amp;quot;globale Einstellungen&amp;quot; geändert werden. Ein Update des Plugins ist möglich ohne vorherige Deinstallation.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/e24005e896d61dd700789f2c5ca2f48f\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/434adfaaa7e9fd1609302a2637312465\">\n    <release version=\"0.9.9.9\" studipMinVersion=\"2.3\" studipMaxVersion=\"2.5\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/40fcf753c67a90180ed52e62b7fc27a0\"/>\n    <release version=\"0.9.9.3\" studipMinVersion=\"2.3\" studipMaxVersion=\"2.5\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f8e353d064097f68b75f1ba6d06c2cb3\"/>\n    <release version=\"0.9.9.2\" studipMinVersion=\"1.11.0\" studipMaxVersion=\"2.3\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/170430ce97a47e316fba1c29d734b0af\"/>\n    <release version=\"0.8\" studipMinVersion=\"1.11.0\" studipMaxVersion=\"2.3\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fafb562718d20e7f2fed5d71b0aab28f\"/>\n    <release version=\"0.2\" studipMinVersion=\"1.11.0\" studipMaxVersion=\"2.3\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b072b76a9b5f6671df3d6d8acd006cae\"/>\n    <release version=\"0.1\" studipMinVersion=\"1.11.0\" studipMaxVersion=\"\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8e12d91d8306ef7943d1574a29c89994\"/>\n  </plugin>\n  <plugin displayname=\"Benutzungsstatistik\" name=\"Benutzerstatistik\" homepage=\"\" short_description=\" Erfassen und Darstellen grundlegender Nutzungs- und Systemstatistiken\" description=\"- Tägliche Erfassung von Zugriffsdaten -- Besucher / Seitenaufrufe (Standort-intern/extern, AJAX) -- Berechtigungen -- Mobile Endgeräte/Tablets -- Browserinformationen -- Bildschirmgrößen -- API-Zugriffe / Hilfelaschen-Klicks - Monatliche Aggregation / Statistiken\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/5f7c00eb5c83ab7ea6d76db795e62da2\" score=\"4.9233139692236\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/2192749d245491e6ed812611a131e669\">\n    <release version=\"4.4.2\" studipMinVersion=\"5.0\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5272848b5e43081099676829de6d6ac8\"/>\n    <release version=\"4.4.1\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/3d1ba7da6b91e034ad2e7587843df84a\"/>\n    <release version=\"4.4\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/aeca0ce74507a8f0ddcd29ed2f38ada6\"/>\n    <release version=\"4.3.2\" studipMinVersion=\"4.3\" studipMaxVersion=\"5.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2bd72d02def58837331c3b030daecd5d\"/>\n    <release version=\"4.3.1\" studipMinVersion=\"4.3\" studipMaxVersion=\"5.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/305612e46affe39b5b5d3cbfa0b05fe4\"/>\n    <release version=\"4.3\" studipMinVersion=\"4.3\" studipMaxVersion=\"5.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/383ee19c14358cf1787cdf6c5941a7cf\"/>\n    <release version=\"4.2.8.2\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/343ea9339ef7c3fbd2067d18a0bd20a1\"/>\n    <release version=\"4.2.8\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/43d8a13fdde1bd43634cd19c3d348431\"/>\n    <release version=\"4.2.4\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/0eec5f6f30afb533aefce600194433aa\"/>\n    <release version=\"4.2.3\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f8928f752c50a08726778754c84dba2f\"/>\n    <release version=\"4.2\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ec95c716336c98a541b57c28b1d24cd0\"/>\n    <release version=\"4.1.3\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f220e257f5e04908551b172e01d2d9da\"/>\n    <release version=\"4.1.1\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e86d6d7e1b64572e53e629539045b6a2\"/>\n    <release version=\"3.4\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f92688603742704be58ead2cbab68bb0\"/>\n    <release version=\"3.3.2\" studipMinVersion=\"3.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/03a1208a0b977453528b3f67c4a75ac1\"/>\n    <release version=\"3.1.7\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f0f3c2926dbcb9b8c3de42ffcbd26619\"/>\n    <release version=\"3.1.6\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c251c00d182915d7e447d7a3ed538aa6\"/>\n    <release version=\"3.1.10\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/9da0f60488c53f21efef02c8baea0dcb\"/>\n  </plugin>\n  <plugin displayname=\"Bibliotheksanfragen Verwaltung\" name=\"BibOPlugin\" homepage=\"\" short_description=\"Bibliothek-Anfragen Verwaltung\" description=\"Mit dem Plugin wird die Möglichkeit geschaffen, aus dem Dateibereich einer Veranstaltung Anfragen zur Bereitstellung von Literatur an die Bibliothek zu stellen (z.B. PDF Scans). Die Lehrenden erhalten die Möglichkeit  zu einer Suche oder einem vorhandenem Literaturobjekt eine Anfrage zustellen. Anfragen verbleiben im Dateibereich, sind dort aber nur für Lehrende sichtbar.  &#10;  &#10; Diese Anfragen werden in der Art eines Ticketsystems für die speziellen Rollen &amp;quot;Bibliotheks-Mitarbeiter&amp;quot; und &amp;quot;Bibliotheks-Supervisor&amp;quot; über einen neuen Hauptnavigationspunkt angezeigt. Hier können die Anfragen bearbeitet werden, Metadaten ergänzt und Links oder gescannte Dokumente hinzugefügt werden. Es besteht die Möglichkeit, direkt im Kontext der Anfrage eine Nachricht an den Fragenden zu stellen. Wird die Anfrage positiv geschlossen, wird die Anfrage automatisch im Dateibereich als Literaturobjekt für Studierende sichtbar und erreichbar.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/df0ca3594fcfc98257fe7241164eff34\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/10ac08f7915458d842bea5501d6c53d9\">\n    <release version=\"0.4.3\" studipMinVersion=\"4.6\" studipMaxVersion=\"5.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e625d694e100ef47b7dfe67bd3c1f478\"/>\n    <release version=\"0.4.2\" studipMinVersion=\"4.6\" studipMaxVersion=\"5.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/d47d8c7a6587e2c86b1ec042d911c78a\"/>\n    <release version=\"0.4.1.9\" studipMinVersion=\"4.6\" studipMaxVersion=\"5.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/87665f42ac426336a402d47522050f16\"/>\n    <release version=\"0.4.1.8\" studipMinVersion=\"4.6\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ed1fb461a4c701394573e3863370d4e7\"/>\n  </plugin>\n  <plugin displayname=\"Big Image Handler\" name=\"Big Image Handler\" homepage=\"https://github.com/tleilax/studip-big-image-handler\" short_description=\"Das Plugin dient dazu, dem Nutzer bei übergroßen eingebundenen Bildern eine Hilfestellung zu geben, wie er diese Bilder in Originalgröße betrachten kann. Dazu wird per JavaScript eine entsprechende Info beim Bild angezeigt und bei Klick auf das Bild wird dieses in einem neuen Browserfenster in Originalgröße geöffnet.\" description=\"Das Plugin dient dazu, dem Nutzer bei übergroßen eingebundenen Bildern eine Hilfestellung zu geben, wie er diese Bilder in Originalgröße betrachten kann. Dazu wird per JavaScript eine entsprechende Info beim Bild angezeigt und bei Klick auf das Bild wird dieses in einem neuen Browserfenster in Originalgröße geöffnet.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/37df2d5e37cede628fd2e00ab35d788d\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/2e53b878d580fec6540636c87c466ef0\">\n    <release version=\"1.3.5\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/dd4c9be99dbf1783f676e6bd47768fdd\"/>\n    <release version=\"1.3.4.1\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5db616b01bef5c0888be0c5d6e9010d6\"/>\n    <release version=\"1.3.4\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/99d04d6bba3cc1d42e2e9b99d38fecb1\"/>\n    <release version=\"1.1.1\" studipMinVersion=\"2.0\" studipMaxVersion=\"2.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/0540e8486cb796127410e2fbad37ba6c\"/>\n  </plugin>\n  <plugin displayname=\"BigBlueButtonPlugin\" name=\"BigBlueButtonPlugin\" homepage=\"\" short_description=\"Plugin zum Einbinden von BigBlueButton Videokonferenzen\" description=\"Willkommen auf der Erde BigBlueButton-Plugin!&#10;&#10;Mit diesem Plugin können Sie Ihr Stud.IP mit einem BigBlueButton Konferenzsystem verbinden. BigBlueButton ist free open source software und exzellent. Einmal angebunden können Sie in jeder Veranstaltung das Plugin aktivieren und beliebig viele Konferenzräume hinzufügen. Ihnen stehen etliche Optionen für die Konferenzräume zur Verfügung. Das Plugin ist speziell für die Zusammenarbeit mit BigBlueButton optimiert.&#10;&#10;- Sie sehen, ob und wieviele Leute gerade online sind in dem Raum.&#10;- Links für Gäste zu dem Raum kopieren - schneller geht es nicht.&#10;- Standardoptionen für die Räume sind konfigurierbar: Wieviele Personen dürfen hinein, wer hat Moderationsrechte, kann man Teilnehmende stummschalten, und und und.&#10;- Präsentationen hochladen.&#10;&#10; \" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/c7ddac14c418d8c9a275c7deec2a5633\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/7bf9f86667b3d79205709ab35272843f\">\n    <release version=\"1.0.39\" studipMinVersion=\"5.5\" studipMaxVersion=\"6.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fe39d04d0c84eb898fcc0a22cf961519\"/>\n  </plugin>\n  <plugin displayname=\"Blubber\" name=\"Blubber\" homepage=\"https://github.com/Krassmus/blubberforum\" short_description=\"Ein gaaaanz kleines Forum mit nur den allernötigsten Funktionen. Dafür ist es in Echtzeit und fühlt sich wie ein Chat an. Ab 2.4 ist Blubber 2.0 im Kernsystem integriert. Blubber 1.0 (dieses Plugin) kann als Vorbereitung darauf schon in Stud.IP 2.3 installiert werden.\" description=\"Blubberforum&#10;============&#10;&#10;A veeery small forum for Stud.IP, which is kinda more facebooky. You don&amp;#039;t need any reloading of the forum-page to see new entries. They just appear infront of you - even while you&amp;#039;re typing. It is a forum, but feels like a chat. And it is 100% compatible with the standard-forum of Stud.IP.&#10;&#10;Features&#10;--------&#10;&#10;- Instant posting-pulling. No page-reload needed to get new postings.&#10;- Everything ajax.&#10;- Formatted postings! That means you can write lists, tables, LaTeX, smileys with the normal Stud.IP-syntax.&#10;- Drag &amp;amp; Drop fileupload into the textareas. Files will be stored in the filesystem of the course.&#10;- Compatibility with the old forum. You can switch to old forum or back to blubber-forum at any time.&#10;- Old postings will get back on top of discussion, when a new comment is posted.&#10;- Re-editing of your postings - to fix typos. Your changes will appear directly to the screens of the other users.&#10;- When you edit a posting to a string with zero length, the posting will be deleted.&#10;- You get a notice for each posting of you that has been edited by another person.&#10;- Permalinks to threads.&#10;- Mentioning other users with @username or @&amp;quot;firstname lastname&amp;quot;. The mentioned person will get a Stud.IP-message and can join the discussion.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/6a72cf937796f42af6477b8e9dc36c4e\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/c784f1e6cbdf2438fd8f64173c2995a0\">\n    <release version=\"1.0\" studipMinVersion=\"1.0\" studipMaxVersion=\"2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/3c7838c91dd905d19b361778e356c02c\"/>\n  </plugin>\n  <plugin displayname=\"BlubberMail\" name=\"BlubberMail\" homepage=\"https://github.com/Krassmus/BlubberMail\" short_description=\"Blubbern über Email. Man bekommt Mails, wenn die Diskussion weiter geht, man kann per Mail darauf antworten und man kann Blubberstreams per Mail abonnieren.\" description=\"BlubberMail&#10;===========&#10;&#10;Blubbern ist eine schicke Kommunikationsform. Sie ist schnell wie ein Chat, persistent wie eine Mail und man kann bequem mit vielen Teilnehmern diskutieren. Aber eine Sache ist leider immer notwendig für Blubber: alle Teilnehmer der Diskussion müssen gerade in Stud.IP angemeldet sein. In der Praxis ist das ein echtes Problem. Manche melden sich selten in Stud.IP an, eigentlich nur dann, wenn sie es müssen.&#10;&#10;Dieses Plugin ändert das.&#10;&#10;- Wenn ich mich abgemeldet habe von Stud.IP, aber gerade in einer Blubberdiskussion war, bekomme ich ganz selbstverständlich Mails, wenn die Diskussion weiter geht. Sitze ich zum Beispiel in einem Zug und rufe nur die Mails über ein Smartphone ab, melde mich aber nicht in Stud.IP an, so sehe ich sofort, was sich getan hat. Das gesamte Gespräch kann ich quasi in Echtzeit per Mail zugeschickt bekommen.&#10;- Wenn ich das alles gelesen habe, auf eine mir per Blubber gestellte Frage fix antworten möchte, kann ich das dann auch bequem tun - per Mail. Ich klicke auf &amp;quot;antworten&amp;quot; in meinem Mailprogramm, wo ich die Blubbermail gelesen habe, schreibe meinen Text und schicke ihn ab. Im Hintergrund landet die Mail beim Mailserver, der erkennt den speziellen Adressaten und schiebt die Mail sofort an Stud.IP weiter, wo sie dann als Blubber auftaucht. Im Grunde ist es also so, als ob ich komplett per Mail weiter blubbern kann, auch wenn ich nicht mehr in Stud.IP angemeldet sein sollte. Und trotzdem passiert auch alles noch in Echtzeit.&#10;- Aber nicht nur Diskussionen, an denen ich teilgenommen habe, kann ich per Mail zugeschickt bekommen. Über eine Einstellungsseite kann ich sogenannte Blubberstreams abonnieren. Die kann man ab der Stud.IP-version 2.5 selbst zusammen stellen, aber zumindest den &amp;quot;globalen Stream&amp;quot; kennt vermutlich jeder, der schonmal geblubbert hat. Wenn es dann neue Blubber-Threads in dem abonnierten Stream gibt, bekomme ich die (per Cronjob) ebenfalls per Mail. Und wieder kann ich einen Kommentar zu einem solchen Blubber schreiben, indem ich einfach auf &amp;quot;antworten&amp;quot; in meinem Mailprogramm klicke. Dieses Feature ist leider erst ab Stud.IP 3.0 verfügbar. Das Plugin läuft aber auch auf einem Stud.IP 2.5.&#10;&#10;Installation&#10;------------&#10;&#10;Das Plugin wird nur richtig gut laufen, wenn man einen Mailserver installiert hat, der in der Lage ist, Nachrichten aus dem Internet zu empfangen und an Stud.IP weiter zu pipen. Wenn das gegeben ist:&#10;&#10;1. Installieren Sie dieses Plugin&#10;2. Konfigurieren Sie das Weiterleiten in Ihrem Mailserver. Bei Postfix kann man das über einen Alias machen, der die Anweisung (in /etc/aliases) bekommt: blubb: |&amp;quot;php /usr/share/studip/public/plugins_packages/RasmusFuhse/BlubberMail/PipeHere.cli.php&amp;quot; Damit werden alle Mails, die an blubb@ihrserver verschickt werden an Stud.IP weiter gepiped. Eine Zeile an Konfiguration reicht hier also schon aus.&#10;3. Falls Sie eine 3.0 von Stud.IP haben, sollten Sie noch einen Cronjob aktivieren, der das verschicken neuer Blubberthreads regelt.&#10;&#10;Fertig.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/a1d85f695cfe506241d398d272ae43f0\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/3bedb4d2ab70ed0d9d130344c3ac6f46\">\n    <release version=\"1.1\" studipMinVersion=\"2.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/6eb939bf0a74c42cdc0d12ef41deacab\"/>\n  </plugin>\n  <plugin displayname=\"BookedRoomsWebservice\" name=\"BookedRoomsWebservice\" homepage=\"\" short_description=\"Fügt einen Webservice (SOAP/XMLRPC) hinzu, der alle in einem anzugebenen Zeitraum gebuchten Räume zurückgibt\" description=\"Kann als Vorlage benutzt werden, wenn man eigene Webserviceplugins basteln will.  &#10;  &#10; Hier noch eine kurze Anleitung:  &#10;  &#10; Ein Webserviceplugin hat genau eine relevante Methode:  &#10;**::getWebServices()**  &#10; die soll ein Array mit Klassennamen liefern, die zusätzliche Webservices enthalten.  &#10; Ein Webservice selbst ist eine Klasse, die von AccessControlledService abgeleitet wird. Die eigentlichen aufrufbaren Services sind die in dieser Klasse erstellten öffentlichen **&amp;lt;name des service&amp;gt;_action()** Methoden. Der erste Parameter ist immer der api key.  &#10; Man muss die erstellten Methoden noch beschreiben, das macht man im Konstruktor, indem man die interne Methode **::add_api_method() **aufruft. Der wird übergeben:&#10;&#10;1. der Name der Methode (ohne _action)&#10;2. ein Array mit den Typen der Paramter&#10;3. ein Wert für den Typ des Rückgabeparameter&#10;4. optional eine kurze Beschreibung, die auch in die wsdl Datei übernommen wird&#10;&#10; Welche Typen es gibt, kann man in  &#10;**vendor/studip_ws/type.php** nachschauen.  &#10; Da gibt es die besonderen Typen struct und array, array ist immer ein numerisches eindimensionales Array. Wenn man ein Array zurückgeben will, schreibt man bei add_api_method() nicht &amp;#039;array&amp;#039;, sondern übergibt ein echtes PHP Array mit einem Element, das Element wiederum beschreibt den Typ der enthaltenen Elemente. D.h. wenn man ein  &#10; Array von Strings zurückgeben will, schreibt man array(&amp;#039;string&amp;#039;).  &#10; Theoretisch könnte man das auch beliebig verschalten, um mehrdimensionale Arrays zu ermöglichen. Hat noch keiner ausprobiert. Für den Typ &amp;#039;struct&amp;#039; muss man immer den Namen einer existierenden Klasse angeben. Man kann das von der Klasse Studip_Ws_Struct ableiten, diese Klasse hat eine init() Methode, in der man die Elemente des Structs mit einem Aufruf von ::add_element() beschreiben kann.  &#10; Alternativ kann man auch eine beliebige Klasse angeben, es werden dann alle öffentlichen Eigenschaften der Klasse zu struct Elementen vom Typ string. Also für einfache POPOs wie&#10;&#10;&#10;    class mystruct {&#10;      public $id;&#10;      public $name;&#10;    }&#10;&#10;&#10; Wegen eines Fehlers in nusoap.php muss eine solche Struct Klasse IMMER  &#10; eine __toString() Methode enthalten!  &#10;  &#10; Alle diese Webservices sind dann über die Endpunkte soap.php, xmlrpc.php und jsonrpc.php aufrufbar. Über soap.php?wsdl gibt es die wsdl Datei. Über xmlrpc.php im Browser aufgerufen, kann man die Services direkt testen (nach Eingabe eines API-KEYs)&#10;&#10; Es bietet sich an in vendor/nusoap/nusoap.php in Zeile 74 ein  &#10;&#10;&#10;    $GLOBALS[&amp;#039;_transient&amp;#039;][&amp;#039;static&amp;#039;][&amp;#039;nusoap_base&amp;#039;][&amp;#039;globalDebugLevel&amp;#039;] = 0; &#10;&#10;&#10; ​zu setzen. Sonst zieht das Ding Unmengen an Speicher. &#10;&#10;  \" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/252b973a49949de6d9468afac8539035\">\n    <release version=\"2\" studipMinVersion=\"\" studipMaxVersion=\"\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/27c8648bb53cf39755f3c894ff96ad52\"/>\n  </plugin>\n  <plugin displayname=\"Browser Update Erinnerung\" name=\"Browser-Update!\" homepage=\"\" short_description=\"Nutzer, die einen veralteten Browser verwenden, werden über eine Information am oberen Rand der Seite dazu aufgefordert, Ihren Browser zu aktualisieren.\" description=\"Dieses Plugin prüft, ob der Nutzer einen veralteten Browser verwendet. Falls dies der Fall ist, wird er mittels einer Information am oberen Rand der Seite dazu aufgefordert, seinen Browser zu aktualisieren. Diese Information kann vom Nutzer dauerhaft ausgeblendet werden.&#10;&#10; Um zu Testzwecken diese Information auch in modernen Browsern einzublenden, muss an eine beliebige URL der Stud.IP-Installation lediglich der Parameter **?buforce** angehängt werden.&#10;&#10; Momentan gelten folgende Browserversionen als veraltet:&#10;&#10;- Chrome &amp;lt; 14.0&#10;- Firefox &amp;lt; 6.0&#10;- Internet Explorer &amp;lt; 8.0&#10;- Opera &amp;lt; 11.0&#10;- Safari &amp;lt; 5.1&#10;&#10; Das Plugin nutzt Texte von und verweist auf browser-update.org: http://browser-update.org.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/20f54af20f942ac8733346c2cb305bb8\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/273481817320626f266c55fb8ed17c34\">\n    <release version=\"1.0\" studipMinVersion=\"2.0\" studipMaxVersion=\"2.2\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e0003bdfefe527316c5879156d9eb7cb\"/>\n    <release version=\"0.9\" studipMinVersion=\"2.0\" studipMaxVersion=\"2.2\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e0ae29066b7d7269a68934880214c450\"/>\n  </plugin>\n  <plugin displayname=\"CachePlugin\" name=\"CachePlugin\" homepage=\"\" short_description=\"Das Cache-Plugin ist ein API-Plugin.Es erleichtert den Zugriff auf den Stud.IP-Cache und wird teilweise von den Augsburger Plugins genutzt oder sogar vorausgesetzt.\" description=\"****Hinweis für alle meine Plugin: Getestet bis Stud.IP 2.3.1, Support für künftige Versionen ungeklärt****&#10;&#10;Die Funktionen, die zur Verfügung gestellt werden sind:&#10;&#10;SimpleCache::cacheString($string_to_cache, $cache_title, $cache_duration)  &#10; SimpleCache::getStringCache($cache_title)  &#10; SimpleCache::cacheThis($cache_duration)&#10;&#10; &#10;&#10;Das Plugin muss vor anderen Plugins geladen werden. Es sollte also in der Plugin-Übersicht als Position die 1 eingetragen werden.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/4b04ca092fb32799f3ca4cb3a58d9591\">\n    <release version=\"0.7.2\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/1307622d85cb4e3cda4327810a82e004\"/>\n    <release version=\"0.7.1\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/bfcd800ccfac3cb6d2e9e13f177ab754\"/>\n    <release version=\"0.7\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/aea18301036d6db362c25783422a67f2\"/>\n  </plugin>\n  <plugin displayname=\"CampusConnect\" name=\"CampusConnect\" homepage=\"https://github.com/data-quest/CampusConnect\" short_description=\"Konnektor zwischen Stud.IP und dem ECS\" description=\"CampusConnect plugin for Stud.IP&#10;================================&#10;&#10;CampusConnect is a project to connect various elearning-service-platforms with each other. You can find further information about the project here:&#10;&#10;- http://freeit.de/de/campusconnect/index.html&#10;- http://freeit.de/de/ecsa/ecs.html&#10;&#10;Installation of this plugin in Stud.IP&#10;--------------------------------------&#10;&#10;Here is a comprehensive tutorial in german with all necessary steps and a small cheat-sheet you can use as a checklist for your installation:&#10;&#10;- Tutorial for this plugin (german): https://github.com/data-quest/CampusConnect/wiki/tutorial_de&#10;- Cheat-sheet for installing (german): https://github.com/data-quest/CampusConnect/wiki/cheatsheet_de\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/31427e447c1ba8ee1c94bd5b9e885c64\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/ab3f48ba294c8c08b861b0a522d56d13\">\n    <release version=\"0.9.7\" studipMinVersion=\"2.4\" studipMaxVersion=\"3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/adde9d248a05630e899aaa99a9667b6e\"/>\n  </plugin>\n  <plugin displayname=\"CheckStudip\" name=\"CheckStudip\" homepage=\"https://gitlab.data-quest.de/studip-plugins-oeffentlich/CheckStudip\" short_description=\"Testet das eigene Stud.IP auf Fehler und zeigt diese an.\" description=\"Mit diesem Plugin kann ein Root-User das eigene Stud.IP testen. So wird zum Beispiel geschaut, ob die data-Verzeichnisse schreibfähig sind, ob Plugins eigene SCSS-Dateien kompilieren können, ob generell noch genug Speicher bzw. im TMP-Ordner noch genug Speicher vorhanden ist, und ob man noch Profilbilder hochladen kann.  &#10;  &#10;Diese Daten könnte man auch als JSON-Objekt für Nutzer von außen abrufbar machen, um ein eigenes Monitoring zu machen.  &#10;  &#10;Das Plugin ist zu finden unter Admin -&amp;gt; Standort -&amp;gt; Stud.IP überprüfen.  &#10;  &#10;Man kann dort auch SOAP-Aufrufe und den Mailversand aus Stud.IP heraus testen.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/3bbacbd7be0bad666463c4c929af5b64\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/ea4e7e0846a260509982dbf1d4cf19b0\">\n    <release version=\"1.9\" studipMinVersion=\"\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/74b5163c86f304758d08dd20a8af82bd\"/>\n    <release version=\"1.8\" studipMinVersion=\"\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ab081dd059ccc7062ee6ed16ae1ac76c\"/>\n    <release version=\"1.6.1\" studipMinVersion=\"\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/28cc78916b21f89da742282fa3cd9915\"/>\n    <release version=\"1.6\" studipMinVersion=\"\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ae9db86ebba2d620a8730503331f15a1\"/>\n    <release version=\"1.5\" studipMinVersion=\"\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/3e5796f2fce4efcb1bcec02b109ff56e\"/>\n    <release version=\"1.2.1\" studipMinVersion=\"\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/0edf13cfcbefd1caad8fa677ba0fc44c\"/>\n    <release version=\"1.11\" studipMinVersion=\"\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/9ae80068fdf6c3839b0671f550ce7dc5\"/>\n  </plugin>\n  <plugin displayname=\"Cliqr\" name=\"Cliqr\" homepage=\"https://github.com/elan-ev/CliqrPlugin/\" short_description=\"eine Software-Clicker-Lösung, die für Lehrende und Lernende einfach zu verwenden ist\" description=\"Mit Cliqr haben Sie die Möglichkeit, während Ihrer Veranstaltung Live-Abstimmungen und Quiz durchzuführen. Gerade in großen Vorlesungen können Sie auf diese Weise die Studierenden motivieren, sich aktiv mit einer Fragestellung auseinanderzusetzen.&#10;&#10;### Warum sollte ich Cliqr einsetzen?&#10;&#10;Sie kennen das sicher: Sie stellen eine Frage, und es melden sich, wenn überhaupt, immer wieder nur die »üblichen Verdächtigen«. Die große Mehrheit ist währenddessen offensichtlich eher mit dem Gedanken beschäftigt, nicht drangenommen zu werden, anstatt über die Frage nachzudenken. Mit Cliqr können Sie dafür sorgen, dass sich **alle Studierenden aktiv** mit der gestellten Frage auseinandersetzen.&#10;&#10;Das liegt zum großen Teil daran, dass die Abstimmung **anonym** ist und die Studierenden dadurch deutlich weniger gehemmt sind, eine Antwort abzugeben, auch wenn sie sich vielleicht nicht ganz sicher sind.&#10;&#10;Und schließlich ist eine Live-Abstimmung für die Studierenden eine willkommene **Abwechslung**, wenn die Vorlesung ansonsten stark von Lehrvorträgen geprägt ist.&#10;&#10;### Wie funktioniert Cliqr?&#10;&#10;Cliqr ist ein Stud.IP-Plugin, das Sie in Ihrer Veranstaltung aktivieren können. In Cliqr können Sie dann Fragen (incl. Antwortmöglichkeiten) formulieren, die Sie während der Veranstaltung stellen möchten. Während der Vorlesung starten Sie dann die Abstimmung. Cliqr erzeugt einen QR-Code, den die Studierenden mit ihren Smartphones oder Tablet-PCs einscannen können. (Alternativ können die Studierenden auch eine Kurz-URL eingeben). Die Studierenden bekommen auf ihrem Gerät dann die Frage und die Antwortmöglichkeiten angezeigt und geben ihre Stimme ab. Wenn Sie die Umfrage wieder beenden, können Sie das Ergebnis der Abstimmung über den Beamer für alle sichtbar machen.&#10;&#10;### Wofür kann ich Cliqr einsetzen?&#10;&#10;Cliqr lässt sich für ganz verschiedene Zwecke einsetzen. Hier einige Beispiele:&#10;&#10;- **Wissensfragen**  &#10;Stellen Sie eine Wissensfrage und überprüfen Sie den Lernfortschritt Ihrer Studierenden.&#10;- **Peer Instruction**  &#10;Stellen Sie knifflige Fagen, bei denen die Studierenden meistens die falsche Antwortalternative wählen. Lassen Sie die Studierenden nach der ersten Abstimmung miteinander diskutieren und sich gegenseitig von ihrer eigenen Antwort überzeugen. Stimmen Sie erneut ab und stellen Sie (hoffentlich) fest, dass nun sehr viel mehr Studierende die richtige Antwort auswählen.Das Gelernte bleibt so viel besser in Gedächtnis haften, als wenn Sie einfach nur die richtige Antwort vorgegeben hätten.&#10;- **Meinungsbild**  &#10;Fragen Sie die Studierenden am Ende der Veranstaltung z. B. danach, wie ihnen die heutige Sitzung gefallen hat.&#10;- **Klärung organisatorischer Fragen**  &#10;Lassen Sie z. B. über den Termin einer Sondersitzung abstimmen.&#10;- **Demografische Statistiken**  &#10;Ermitteln Sie das Geschlechterverhältnis Ihrer Zuhörerschaft, oder finden Sie heraus, aus welcher Region Ihre Studierenden stammen, wie viele Links- und Rechtshänder oder wie viele Farbfehlsichtige unter Ihren Studierenden sind.&#10;- **Replikation von Experimenten**  &#10;Stellen Sie Fragen, die schon bekannte Forscherinnen und Forscher vor Ihnen gestellt haben, und lassen Sie Ihre Studierenden bekannte soziologische oder psychologische Befunde am eigenen Leib erfahren.&#10;&#10;  &#10;Eine gute Anleitung zur Benutzung wird von der TU Clausthal angeboten: https://www.elearning.tu-clausthal.de/lernplattformen/studip/plug-in-cliqr/. Über den Alltag mit Cliqr berichten die Campusnews der Universität Trier: http://campusnews.uni-trier.de/?p=5847.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/16f7d0ad70904e0a93f58ee08b68b1ef\" score=\"9.5739338740957\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/9c0c61218d7ce2c556417563f9e64220\">\n    <release version=\"6.0.0\" studipMinVersion=\"5.4.dev\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ed130c764296cc6938e2b958dcb16ee2\"/>\n    <release version=\"5.4.0\" studipMinVersion=\"5.4.dev\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e462c541a8aef5e563ca05ae39932f24\"/>\n    <release version=\"5.3.1\" studipMinVersion=\"5.3.dev\" studipMaxVersion=\"5.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c76ff034b774e7fe8c3b3a186ddfde0f\"/>\n    <release version=\"3.2.1\" studipMinVersion=\"4.5\" studipMaxVersion=\"5.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/7a3cb21aebaae22995cb202c4dae8b3a\"/>\n    <release version=\"3.2.0\" studipMinVersion=\"4.5\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/126d6d449327a93c825588a5f968f20e\"/>\n    <release version=\"3.1.0\" studipMinVersion=\"3.4\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/23fa02672e59d25a8de1247455735aac\"/>\n    <release version=\"3.0.7\" studipMinVersion=\"3.4\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/10fe5c22370263855928057f92f67ea1\"/>\n    <release version=\"3.0.6\" studipMinVersion=\"3.4\" studipMaxVersion=\"4.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2b5a91794e368de18dfc3ca90a8a4bac\"/>\n    <release version=\"3.0.5\" studipMinVersion=\"3.4\" studipMaxVersion=\"4.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/037b43708d997b872528dd01cbc3d143\"/>\n    <release version=\"3.0.4\" studipMinVersion=\"3.4\" studipMaxVersion=\"4.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/47a257ca14020f908768430d7474e42c\"/>\n    <release version=\"3.0.3\" studipMinVersion=\"3.4\" studipMaxVersion=\"4.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2d5d8c0ce2e73344bf00a67776a29ed0\"/>\n    <release version=\"3.0.2\" studipMinVersion=\"3.4\" studipMaxVersion=\"4.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2eeae26d1175249783689bd50abd570e\"/>\n    <release version=\"3.0.1\" studipMinVersion=\"3.4\" studipMaxVersion=\"4.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/958995645d5cbfb5fdd817d12a6c61c8\"/>\n    <release version=\"2.0.0\" studipMinVersion=\"3.4\" studipMaxVersion=\"4.2\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/91a4d48f45bd829624a214d2a1c42a48\"/>\n    <release version=\"0.6.1\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5cbe75f4ccb196c7f5050497b8c99946\"/>\n  </plugin>\n  <plugin displayname=\"Clock.IP\" name=\"Clock.IP\" homepage=\"\" short_description=\"Eine einfache Uhr für Stud.IP.\" description=\"Eine einfache Uhr für Stud.IP, die dem Nutzer immer die aktuelle Serverzeit anzeigt und bei aktiviertem Javascript diese laufend aktualisiert.&#10;&#10; Das Plugin ist aus der Situation heraus entstanden, dass Studierende zu Anmeldezeiten ziemliche Last erzeugt haben, da sie die Seiten permanent neu geladen haben, um den Zeitpunkt der Freischaltung der Anmeldung abzupassen. Um eine (wenn auch nur kleine) Hilfestellung zu geben und so eventuell etwas Last zu nehmen, haben wir dieses Plugin entwickelt, damit die Studierenden eine verlässliche Zeitangabe des Servers haben.&#10;&#10; Anpassungen an Stil und Position sind in der enthaltenen Datei *clock.css* vorzunehmen, das Verhalten wird entweder in der *ClockIP.class.php* bzw. der *clock.js* gesteuert.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/a24010542d7c9b4a0149859919592598\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/25db560867c73d8ba0bb760423de978f\">\n    <release version=\"1.1\" studipMinVersion=\"1.1\" studipMaxVersion=\"2.2\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e1baf8e92745673bfd070f6095334419\"/>\n    <release version=\"1.0.1\" studipMinVersion=\"2.0\" studipMaxVersion=\"2.2\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e2fadf7666fc0c14c36ff11451526d52\"/>\n    <release version=\"1.0\" studipMinVersion=\"1.0\" studipMaxVersion=\"3.0\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fcf762902025e754724725eb632ad41c\"/>\n  </plugin>\n  <plugin displayname=\"CMSIntegration\" name=\"CMSIntegration\" homepage=\"\" short_description=\"Eine Alternative zu den externen Seiten. Administratoren können Javascript-Code-Schnipsel erzeugen, um Daten aus dem Digicampus in ihren Webauftritten einzupflegen. Mögliche Exporte sind: Nutzerprofil, News einer Einrichtung, Veranstaltungen einer Einrichtung in einem Semester\" description=\"****Hinweis für alle meine Plugins: Getestet bis Stud.IP 2.3.1, Support für künftige Versionen ungeklärt****&#10;&#10;Intern nutzt das Plugin die Stud.IP-Exportschnittstelle um XMLs zu erzeugen. Diese werden dann per XSLT-Dateien in HTML-Dateien konvertiert. Für jede Exportvariante lassen sich beliebige XSLTs hinterlegen (benötigt Code-Änderung)&#10;&#10; &#10;&#10;**Hinweis:**&#10;&#10;In der aktuellen Browsergeneration (Ende 2013) ist standardmäßig ein Mixed-Content-Filter aktiviert. Das heißt, wenn Ihr Stud.IP verschlüsselt ist, muss die CMS-Integration auch verschlüsselt übertragen werden, auch wenn unverschlüsselt Performance eingespart werden könnte. Anderenfalls ist eine Generierung der Exportkonfigurationen nur durch Anpassung des Browsers (Deaktivierung des Mixed-Content-Filters) möglich.&#10;&#10; &#10;&#10;**Abhängigkeiten**:  &#10; CachePlugin&#10;&#10; &#10;&#10;**Installation**&#10;&#10;die Datei config-dist.php muss nach config.php kopiert werden. Der Ordner compiled und seine Unterordner müssen für den Webserver beschreibbar sein.&#10;&#10;Htaccess-Dateien muss der Webserver unterstützen.&#10;&#10; &#10;&#10; \" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/34122f9da3e2737814a122e3e48a22cb\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/700efaf1192809ad598c45f0c7cf3aa8\">\n    <release version=\"0.6.3\" studipMinVersion=\"2.3\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/44a8c95319f04f9d43acc1c09ffca789\"/>\n  </plugin>\n  <plugin displayname=\"CodeInjector\" name=\"CodeInjector\" homepage=\"\" short_description=\"Der Code-Injector ermöglicht es, zentral Aktionen zu definieren, die auf Stud.IP-Seiten ausgeführt werden.\" description=\"****Hinweis für alle meine Plugin: Getestet bis Stud.IP 2.3.1, Support für künftige Versionen ungeklärt****&#10;&#10; In der mitgelieferten Config ist eine Beispiel-Aktion eingepflegt: Wenn man auf die Suche geht, wird ein Javascript-Alert mit dem Inhalt „test“ angezeigt.&#10;&#10;  &#10;&#10; Dieses Plugin wird hauptsächlich dazu genutzt, um an verschiedenen Stellen per Javascript Hinweise einzuzblenden, die die lokale Installation betreffen.&#10;&#10; Es ist aber auch möglich, PHP-Code zu definieren, der beim Aufruf verschiedener Seiten ausgeführt wird.&#10;&#10;  &#10;&#10; Damit wird vermieden, dass Dateien im Stud.IP-Trunk verändert werden müssen.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/86d6a4bcbd5e779aab9ded00226c2780\">\n    <release version=\"0.7.5\" studipMinVersion=\"1.11.0\" studipMaxVersion=\"\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b9eb5649a70ab02af2ee4dd53cb33cb4\"/>\n  </plugin>\n  <plugin displayname=\"coLearn!\" name=\"Kooperationsskripts\" homepage=\"\" short_description=\"coLearn! unterstützt Lehrende dabei, Kleingruppenkooperationsphasen in Veranstaltungen didaktisch sinnvoll zu planen, zu gestalten und umzusetzen.\" description=\"Das Lernen in Kleingruppen bietet hervorragende Möglichkeiten zur Förderung des Lernens. Empirische Befunde zum computergestützten kooperativen Lernen zeigen allerdings, dass unstrukturierte Zusammenarbeit von Studierenden oft weniger effektiv ist als individuelles Lernen. Mit coLearn! können Kleingruppenkooperationsphasen in Vorlesungen, Seminaren oder Übungen strukturiert geplant und umgesetzt werden. &#10;&#10;coLearn! erlaubt es Lehrpersonen insbesondere, &#10;&#10;- Aufgaben anzulegen, die von studentischen Kleingruppen bearbeitet werden sollen, &#10;- den Kooperationsprozess in beliebig viele Phasen zu unterteilen, &#10;- zwischen den Lernenden einer Kleingruppe unterschiedliche Rollen zu verteilen und &#10;- die Studierenden bei der Ausübung ihrer Rollen in den unterschiedlichen Phasen durch zusätzliche Hilfestellungen zu unterstützen.&#10;&#10;Zudem bietet coLearn! der Lehrperson vielfältige Möglichkeiten, den Kooperationsprozess der Gruppen zu überwachen und den Studierenden bei Bedarf weitere Hilfestellungen zu geben.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/262fe427572747a9820a4f04772f3ca6\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/d783ac2f2787f1bc3a17d5e48016a2db\">\n    <release version=\"0.8.5\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/6c02ff91ab21d28347da8020b31bd235\"/>\n    <release version=\"0.7.2\" studipMinVersion=\"4.3\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/dfb2e5d03ea9275db7f494de6f14cdf0\"/>\n  </plugin>\n  <plugin displayname=\"CourseCopy\" name=\"CourseCopy\" homepage=\"https://gitlab.studip.de/studip/plugins/CourseCopy\" short_description=\"Kopiert mehrere Veranstaltungen in ein neues Semester\" description=\"Es gibt schon einige Kopier-Plugins. Die meisten dieser Plugins sind etwas in die Jahre gekommen. Und ab der 3.x hat Stud.IP einen schicken neuen Administrationsbereich für Veranstaltungen. Dieses Plugin hängt sich dort herein. Man kann deshalb Veranstaltungen filtern nach&#10;&#10;- Semester&#10;- Fakultät/Einrichtung&#10;- Lehrenden&#10;- Suchtext&#10;- Veranstaltungstyp&#10;- Datenfelder&#10;&#10;  &#10;Danach erhält man die gesuchten Veranstaltungen, wählt die betreffenden aus und drückt auf &amp;quot;Kopieren&amp;quot;. Ein Dialogfenster öffnet sich, in dem man einstellen kann ...&#10;&#10;- In welches Semester sollen die Veranstaltungen kopiert werden?&#10;- Sollen die Lehrenden durch einen Dummy-Dozenten ersetzt werden?&#10;- Sollen die regelmäßigen Termine mit kopiert werden?&#10;- Sollen Tutor/-innen mit kopiert werden?&#10;- Welche Start- und Endwoche sollen die regelmäßigen Termine anfangen bzw. enden?&#10;- Soll versucht werden die Raumbuchungen gleich mit zu übernehmen (Doppelbuchungen werden aber verhindert)?&#10;- Sollen die neuen Veranstaltungen gleich gesperrt sein?&#10;- Sollen die neuen Veranstaltungen unsichtbar sein?&#10;&#10;  &#10;Das mögen zwar viele Optionen sein, aber das Plugin merkt sich, welche Optionen man als letztes ausgewählt hatte und behält die als Vorauswahl bei, sodass man nicht so viel klicken muss.&#10;&#10;Release-Notes&#10;-------------&#10;&#10;- 1.5: Unterstützung von Veranstaltungsgruppen. Man kann einstellen, ob man die Kindveranstaltungen mitkopieren möchte oder nicht.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/ecd762bf85830e024325526eed7a4683\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/8d4bfdd8c1b8ed75ec8da7c298bf9394\">\n    <release version=\"1.9.7\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/9721de64d6296cf28b132cc884fb7e26\"/>\n    <release version=\"1.9.5\" studipMinVersion=\"4.0\" studipMaxVersion=\"5.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/311140984bb4719c653e3f326fa18631\"/>\n    <release version=\"1.9.4\" studipMinVersion=\"4.0\" studipMaxVersion=\"5.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/58c58774c265ac86ef984832818c5c1e\"/>\n    <release version=\"1.9.1\" studipMinVersion=\"4.0\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c1cbbbc59c710b49dc61a7a4e5620263\"/>\n    <release version=\"1.6\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.99.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/9aa4e07f30536ab82d08b5802ddaf354\"/>\n    <release version=\"1.5\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.99.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/13f5165b4ea68d601fb66080ed6030fb\"/>\n    <release version=\"1.3.1\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.99.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b4de62a11ecdcbfcbc7f91c7ad7fd98d\"/>\n    <release version=\"1.3.0\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.99.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5c15cb180875ffb833680bfd12039ef9\"/>\n    <release version=\"1.1\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/1ca7e60de07e58e6f7f2cae2d770c157\"/>\n  </plugin>\n  <plugin displayname=\"CourseDatabase\" name=\"CourseDatabase\" homepage=\"https://github.com/Krassmus/CourseDatabase\" short_description=\"Stellen Sie echte Datenbanken zur Verfügung, die mit einem granularen Rechtemanagement entweder nur für Sie als DozentIn, für alle Teilnehmer des Kurses oder einzelne Teilnehmergruppen freigegeben werden. Damit können Noten erfasst werden, man kann statistische Daten zusammen tragen oder einfach einen Einsteigerkurs zum Thema relationale Datenbanken halten.\" description=\"Datenbanken in Veranstaltungen&#10;------------------------------&#10;&#10;Wozu kann man in Veranstaltungen Datenbanken nutzen? Ist das nicht furchtbar kompliziert?&#10;&#10;Ja, Datenbanken sind kompliziert. Aber sie sind auch ein ungeheuer nützliches Allzweckwerkzeug. Wannimmer man eine Excel-Tabelle öffnet, um Daten zu sammeln, macht man im Grunde schon etwas falsch und wäre besser mit einer kleinen Datenbank bedient. Spätestens, wenn man die zweite Exceltabelle im selben Dokument öffnet, stellt man fest, dass man auf Probleme stößt; oft muss man dann Daten redundant mehrfach eingeben, verhaspelt sich und bekommt am Ende Fehler in dem Datenbestand. Dabei ist Excel gar nicht für Datenbestände gemacht sondern für Berechnungen.&#10;&#10;Eine Datenbank hat dagegen viele Vorteile. Man kann in verschiedenen Tabellen einheitliche IDs verwenden, die sich auch gegenseitig referenzieren. Dadurch bekommt man Sicherheit in den Daten. Und am Ende kann man sich aus allen Tabellen einen View zusammen stellen, der einem auf einen Blick alle Informationen gibt, die man braucht. Dann noch einmal diese Daten exportiert und voila, man hat, was man will.&#10;&#10;Das schöne an diesem Modul für Stud.IP ist, dass die Datenbank über jeden Webbrowser verfügbar ist und man die Datenbanken flexibel freigeben kann für alle Teilnehmer einer Veranstaltung oder nur bestimmten Teilnehmern oder niemandem außer Ihnen selbst. Das Werkzeug ist also kollaborativ. Sie müssen sich keine Gedanken machen um das Zusammenführen von Daten (passiert ja im Server automatisch) oder ein Backup der Daten (das sollte auch automatisch auf dem Server geschehen).&#10;&#10;Use case 1: Notenvergabe&#10;----------------------------------------------------------------------------------------------&#10;&#10;Sie haben eine Veranstaltung mit drei Übungsgruppen, die jede von einem Tutor/HiWi gehalten wird. Die Tutoren sollen eine Anwesenheitsliste führen ihrer Studenten. Zudem werden jede Woche Punkte für Übungszettel vergeben, die die Studenten lösen mussten, und jeder Student muss einmal pro Semester an der Tafel eine Aufgabe vorrechnen. Ach ja, und während des Semesters soll es noch zwei Klausuren geben, aus denen dann eine Gesamtnote berechnet wird.&#10;&#10;Im Normalfall bräuchte man dazu ein komplexes Modul oder man stell mehrere Excel-Dokumente in eine Dropbox, die Sie Ihren Tutoren frei geben. Wuarg! Sie können aber auch eine Datenbank erstellen, die nur Sie und Ihre Tutoren sehen und bearbeiten dürfen. Da gibt es dann drei Tabellen: Anwesenheitsliste, Tafelrechnen und Klausurnoten. Sie weisen Ihre Tutoren an, jede Woche einmal die Anwesenheitsliste und die Tafelliste zu aktualisieren. Dazu erstellen Sie ein View, die Ihnen ausgibt, welche Studenten dreimal oder mehr gefehlt haben und wer noch nicht vorgerechnet hat. So sind Sie immer auf dem Laufenden. Ihre Klausurergebnisse können Sie hier ebenfalls eingeben und bekommen in einem weiteren View die Endnote berechnet.&#10;&#10;Views kann man also neben den Tabellen erstellen, um aus den Tabellen bestimmte Informationen zu destillieren wie die Endnote.&#10;&#10;Use case 2: Statistische Umfragen&#10;----------------------------------------------------------------------------------------------------------------&#10;&#10;In einem Kurs werden in Arbeitsgruppen statistische Umfragen entworfen, durchgeführt und ausgewertet.&#10;&#10;Sie können Ihren Studenten dabei helfen, indem Sie pro Arbeitsgruppe eine Datenbank anlegen, die dann nur diese Arbeitsgruppe (und Sie als Dozent) sehen und bearbeiten darf. Dort sollen die Mitglieder der Gruppe dann die erhobenen Daten eingeben. Das schöne ist, dass jeder Student selbstständig die Befragungen durchführen und die Daten eingeben kann. Man braucht zum Eingeben dann nur einen Webbrowser. Die Daten sind anschließend zentral gespeichert und können entweder in einem View ausgewertet werden oder exportiert werden, um sie in SPSS weiter auszuwerten.&#10;&#10;Use case 3: Ressourcenmanagement&#10;--------------------------------------------------------------------------------------------------------------&#10;&#10;An Ihrer Uni gibt es eine Stelle, die den Studenten Videokameras und Videoschnittwerkzeuge ausleiht. Es müssen dazu Listen geführt werden, was gerade ausgliehen ist, wo es sich derzeitig befinden und wann es danach wieder ausgeliehen sein wird. Dazu kann in einer Veranstaltung in Stud.IP eine Datenbank erstellt werden, in der jedes Equipment erfasst und jeder Verleihvorgang protokolliert bzw. vorgemerkt wird. Das kann dezentral geschehen, die Mitarbeiter der Einrichtung können auch Vormerkungen erledigen, wenn sie nicht im Büro sind.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/1ad0ae214626cc33f73d06c9035d5f59\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/9f479033195174ac56b0ae9e8f515822\">\n    <release version=\"1.0\" studipMinVersion=\"2.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f7bd87317e11137cccc97ca0425ad6f1\"/>\n  </plugin>\n  <plugin displayname=\"CourseDateMassCancellationPlugin\" name=\"CourseDateMassCancellationPlugin\" homepage=\"\" short_description=\"Ein Plugin zum massenweisen Löschen von Veranstaltungsterminen an einem bestimmten Tag.\" description=\"\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/2afee5deb6f4c11a0d66f004a47a0461\">\n    <release version=\"1.2.0\" studipMinVersion=\"4.5\" studipMaxVersion=\"5.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/9aa1c2913d7c2667a5c62c4d051a8434\"/>\n    <release version=\"1.1.0\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/39f01fa100a61a3cbe2d1519279def30\"/>\n    <release version=\"1.0.2\" studipMinVersion=\"3.3\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ccf99ae3e32c4ad0477cdeacbeec37e3\"/>\n    <release version=\"1.0.1\" studipMinVersion=\"3.3\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5a9418f5bb6d0d2d71f5d56956b945ed\"/>\n    <release version=\"1.0\" studipMinVersion=\"3.3\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2551bf232d0d102b2de71848e7098e00\"/>\n  </plugin>\n  <plugin displayname=\"CourseGroupPatchRoute\" name=\"API Extension: Course Group Patch Route\" homepage=\"\" short_description=\"Erweitert die API um eine Route, um die Gruppenzuweisung von Veranstaltungen für Teilnehmer zu verändern\" description=\"Stellt die Route ##PATCH /user/:user_id/courses/:course_id## bereit, der ein JSON-Objekt der Form ##{group: :index}## übergeben werden, um die Gruppenzuweisung eines Kurses für einen Teilnehmer zu ändern.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/ea38bb4d09d55b86f740c4152d5b3ac7\">\n    <release version=\"1.0\" studipMinVersion=\"3.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/cbae71d77b83ab7cd64b769c49f63510\"/>\n  </plugin>\n  <plugin displayname=\"CourseHistory\" name=\"CourseHistory\" homepage=\"\" short_description=\"Zeigt den Änderungsverlauf einer Veranstaltung an\" description=\"Bietet Admins die Möglichkeit den Änderungsverlauf einer Veranstaltung zu kontrollieren. Basis sind die Logeinträge\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/54e802257c7e94486adbe4c145799714\" score=\"7.9909929772425\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/102b55c6e7d50a3f1fded960b099cc11\">\n    <release version=\"3.3\" studipMinVersion=\"4.3\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/1a6e4caef5ebeb5397c8de202e1abf8f\"/>\n    <release version=\"3.2\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/1d72b75f0c15cc948a527ba5480c1c14\"/>\n    <release version=\"3.0\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/751d444c0eb64323d4440396a9f35fe7\"/>\n    <release version=\"1.0\" studipMinVersion=\"3.3\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2a99312c8deb2434789a5704fb45a5c6\"/>\n  </plugin>\n  <plugin displayname=\"Courseware\" name=\"Courseware\" homepage=\"https://github.com/virtUOS/courseware\" short_description=\"Interaktive multimediale Lernmodule erstellen und nutzen\" description=\"Mit der Courseware können Sie interaktive multimediale Lernmodule erstellen und nutzen. Die Module sind in Kapitel, Unterkapitel und Abschnitte unterteilt und können aus Textblöcken, Videosequenzen, Aufgaben (benötigt das Vips-Plugin), Kommunkationselementen und einer Vielzahl weiterer Blöcke bestehen. Fertige Module können exportiert und in andere Kurse oder andere Installationen importiert werden.  &#10;  &#10; Zugriff auf alle Releases und Sourcecode:  &#10;https://github.com/virtUOS/courseware/releases: http://github.com/virtUOS/courseware/releases  &#10;  &#10; Hilfe:  &#10;StudIP Hilfe: Courseware: https://hilfe.studip.de/help/4.4/de/MoocIP.Courseware  &#10;GitHub: Courseware Wiki: https://github.com/virtUOS/courseware/wiki/  &#10;  &#10; Dokumentation:  &#10;GitHub: Anleitung für Entwickler: https://github.com/virtUOS/courseware/wiki/Entwicklung  &#10;  &#10;**ab Version 3.1 und 4.1 wird das DatenschutzPlugin unterstützt**  &#10;  &#10;&#10;**Version 5**&#10;-------------&#10;&#10; Diese Version ist nur für die Migration der Courseware-Inhalte in die Kern-Courseware. Administratoren können über ein Komondozeilen-Tool die Migration für alle Veranstaltungen auslösen.  &#10; Optional kann in der Stud.IP Konfiguration auch die manuelle Migration aktiviert werden. Hiermit haben Lehrende die Möglichkeit die Migration zu einem gewünschten Zeitpunkt selber auszulösen.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/60d3b9775caf39acba0baa3649fca5fa\" score=\"8.9351692707129\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/b8dfddd62a7c3e4dbfed74d933676b3a\">\n    <release version=\"5.0.9\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/cf7a1956bc9db8795247b179b4831af7\"/>\n    <release version=\"5.0.8\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/6542acc5434b6a2affe3d71c786433dc\"/>\n    <release version=\"5.0.7\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e50b911badf4983f182109d4868a9356\"/>\n    <release version=\"4.8.8\" studipMinVersion=\"4.6\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4f41c987d0787