et/presenting/download/c0f610ca1650a9eecb6a37ec70b153d6\"/>\n    <release version=\"3.2.0\" studipMinVersion=\"3.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/aee47835271a6356b846a72975120509\"/>\n    <release version=\"3.1.0\" studipMinVersion=\"3.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ededafd1f655167a54745e628d17e5a1\"/>\n    <release version=\"3.0.7\" studipMinVersion=\"3.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/1241487958b3f751fdfb743c80170376\"/>\n    <release version=\"3.0.6\" studipMinVersion=\"3.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/1ff7c214fbaa9e5eb1249ddafc66036c\"/>\n    <release version=\"3.0.5\" studipMinVersion=\"3.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b67a7474534545cd072a9529a25e7a94\"/>\n    <release version=\"3.0.4\" studipMinVersion=\"3.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2455c3544f79f5b3b8b4b09da263f28f\"/>\n    <release version=\"3.0.3\" studipMinVersion=\"3.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4e636a81b9749bac716b01cb75355d06\"/>\n    <release version=\"3.0.2\" studipMinVersion=\"3.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2ea0a0d67607c1d70cbe189bcdd563f3\"/>\n    <release version=\"3.0.1\" studipMinVersion=\"3.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/9ad9213a4d8aa5ec94b6d6cc4b788583\"/>\n    <release version=\"3.0.0\" studipMinVersion=\"3.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fbf244ff1127a2071cc5fdc2d3825b7c\"/>\n    <release version=\"2.0.2\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a5207d405c21d5a6258d361ced484779\"/>\n  </plugin>\n  <plugin displayname=\"CoursewareFlow\" name=\"CoursewareFlow\" homepage=\"https://github.com/elan-ev/studip-courseware-flow\" short_description=\"Mit diesem Plugin können Courseware-Lernmaterialien aus einer Veranstaltung in andere kopiert und dort mit der Quelle synchron gehalten werden. Änderungen an de\" description=\"CoursewareFlow ist ein Stud.IP-Plugin, mit dem sich Courseware-Lernmaterialien aus einer Veranstaltung in eine andere kopieren und dort mit der Quelle synchron halten lassen. Änderungen an den Ursprungsmaterialien werden automatisch in die Zielveranstaltungen übernommen, sodass Inhalte effizient wiederverwendet und konsistent bereitgestellt werden können.&#10;&#10;CoursewareFlow ist lizenziert unter der GNU Affero General Public License v3.0 (AGPL-3.0).\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/8821bd3f908959416f7876cf5e88fdbe\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/c3e7953ed24070f021cc61b2cfad31fd\">\n    <release version=\"1.0.3\" studipMinVersion=\"5.3\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ba54d46679f5eb5d9729b625192758c2\"/>\n    <release version=\"1.0.2\" studipMinVersion=\"5.3\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5784d35a17abc4631e3775aa09bf49f5\"/>\n    <release version=\"1.0.1\" studipMinVersion=\"5.3\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a5f4b40df43863eea46ef6c48726bf42\"/>\n    <release version=\"1.0.0\" studipMinVersion=\"5.3\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5f236aea905209c0f4653c8a9c5af7cd\"/>\n  </plugin>\n  <plugin displayname=\"CoWriter\" name=\"CoWriter\" homepage=\"\" short_description=\"Kollaboratives Arbeiten an LaTeX-Dokumenten in Echtzeit und in Gruppenarbeit.\" description=\"LaTeX ist *der* Standard bei den mathematisch-naturwissenschaftlichen Fächern, um wissenschaftliche Texte, Klausuren, Übungsaufgaben, (Muster-)Lösungen, Abschlussarbeiten und sogar Präsentationen anzufertigen. Mit dem CoWriter gibt es jetzt eine Möglichkeit, diese Arbeiten in Stud.IP bequem durchzuführen und dabei auch mit anderen zusammen zu arbeiten.  &#10;  &#10;&#10;Bedienung&#10;---------&#10;&#10; Innerhalb einer Veranstaltung kann der CoWriter ganz normal über die Mehr Seite aktiviert werden. Sodann taucht in der Veranstaltung ein weiterer Reiter auf. Dort findet sich eine Beispielseite und ein Beispielunterkapitel in einem separaten Dokument. Der Text dieser Dokumente zeigt den Nutzern von Stud.IP in kurzen Worten, wie man mit dem CoWriter arbeitet, wie die Live-Vorschau funktioniert, wie man Bilder hochlädt (am Besten mit Drag &amp;amp; Drop natürlich!) und wie man ein Dokument auf mehrere Seiten aufteilt.  &#10;  &#10; Die Lehrenden können für jede Seite granular einstellen, wer die Seite einsehen und/oder bearbeiten darf. Auch Gruppenarbeit ist so möglich, dass jede Arbeitsgruppe eine eigene Lösung ausarbeitet, aber nicht die Lösungen der anderen Gruppen sehen darf. Erst am Ende kann der Lehrende die Lösungen für alle wieder lesbar machen.  &#10;  &#10; Dabei ist CoWriter das erste Plugin, mit dem echte Live-Zusammenarbeit in Stud.IP möglich ist. Man sieht in der Sidebar links immer, wer noch gerade das Dokument mitbearbeitet. Zudem werden die Änderungen immer live eingespielt und kontinuierlich gespeichert.  &#10;  &#10; Neben dem Rohtext gibt es eine Live-Vorschau des Dokumentes, mit der man genau sehen kann, wie die Lösungen am Ende aussehen werden. Eine Zoom-Funktion hilft einem dabei noch zusätzlich.  &#10;  &#10; Am Ende kann man sich das Dokument einfach als PDF herunterladen. Alternativ kann man über die Übersicht, mehrere Dokumente zusammen als ein einzelnes PDF exportieren.  &#10;  &#10;&#10;Installation&#10;------------&#10;&#10; Das Plugin kann wie jedes andere Plugin in Stud.IP installiert werden (per Drag Drop in der Pluginverwaltung). Zusätzlich muss man allerdings sicherstellen, dass folgende Kommandozeilentools verfügbar sind und auch durch den Webserverprozess (Apache) ausgeführt werden können:  &#10;   - **pdflatex**: Das Plugin benötigt pdflatex, um die TeX-Dokumente in PDFs umzuwandeln. Üblicherweise ist dieses Kommandozeilentool unter /usr/bin/latex zu finden. Falls dem nicht so ist, muss man es gegebenenfalls installieren und den korrekten Pfad in die config/config_local.inc.php eintragen in der Art: $GLOBALS[&amp;#039;LATEX_PATH&amp;#039;] = &amp;quot;/usr/bin/latex&amp;quot;;. Dann sollte es gehen.&#10;- **convert**: Hinter dem Programm convert verbirgt sich imagemagick, das das Plugin braucht, um aus einem PDF eine Rastergrafik (PNG) zu generieren, die dann dem Nutzer angezeigt wird. Falls dieses Programm nicht im Pfad /usr/bin/convert zu finden ist, muss es gegebenenfalls installiert werden und ein abweichender Pfad in die config/config_local.inc.php eingetragen werden in der Form: $GLOBALS[&amp;#039;CONVERT_PATH&amp;#039;] = &amp;quot;/usr/bin/convert&amp;quot;;&#10;- **pdftk**: Dieses Programm mit dem unscheinbaren Namen wird vom Plugin verwendet, um aus einer mehrseitigen PDF-Datei eine einseitige PDF-Datei zu machen (die anschließend von convert in eine PNG-Datei umgewandelt wird), als auch, um mehrere PDF-Dateien zu verketten und um die maximale Seitenzahl einer PDF-Datei zu finden. Falls dieses Programm nicht im Pfad /usr/bin/pdftk zu finden ist, muss es gegebenenfalls installiert werden und ein abweichender Pfad in die config/config_local.inc.php eingetragen werden in der Form: $GLOBALS[&amp;#039;PDFTK_PATH&amp;#039;] = &amp;quot;/usr/bin/pdftk&amp;quot;; &#10;&#10;  &#10;  &#10; Auf manchen Systemen kann es zusätzlich notwendig sein, noch Ghostscript zu installieren (sudo apt-get install ghostscript). Wenn möglich installieren Sie möglichst viele LaTeX-Pakete, denn ihre Nutzer werden versuchen alle früher oder später mal zu benutzen.  &#10;  &#10; Um eine Seite anzuzeigen, werden alle relevanten Dateien für diese Seite in das /tmp-Verzeichnis verschoben. Es sollte dort also ausreichend Platz vorhanden sein.   &#10;  &#10; Falls diese Bedingungen erfüllt sind, sollte das Plugin funktionieren.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/06269098dcff7506d8b9c156dfa3d6f2\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/5cf254e44cf3484ffda4d1afba80d705\">\n    <release version=\"1.5\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/162b048be9f4172faad28daad45cfa2f\"/>\n    <release version=\"1.3.5\" studipMinVersion=\"4.0\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/9ae6d7854c1fb37c4a9cc67e6cd2ed0f\"/>\n    <release version=\"1.3.4\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/3a690c61f840999036cda0075b6c1d50\"/>\n    <release version=\"1.3.2\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/de310791a0aab9588f3e0d073bc34e3d\"/>\n    <release version=\"1.3.2\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/dfe3facbbcd4ef85536076487ce345f3\"/>\n    <release version=\"1.3.1\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2fbb19f703589a44c996e6f6bd221f35\"/>\n    <release version=\"1.3.1\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a96a97f1684e07bbabdc151e1ba43721\"/>\n    <release version=\"1.0.2\" studipMinVersion=\"3.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/7d1d834f3936f02333d44ed60d12e222\"/>\n  </plugin>\n  <plugin displayname=\"Cronjobber\" name=\"Cronjobber\" homepage=\"https://github.com/derfl0/Cronjobber\" short_description=\"Softcronjobs für Entwicklungsumgebungen\" description=\"Manchmal will man Quick and Dirty den Stud.IP Cronjob laufen haben und ihn auch schnell wieder deaktivieren können. Dieses Plugin ermöglicht dies, ohne dafür auf die Konsole zu müssen.  &#10;  &#10; Produktiveinsatz ist nicht zu empfehlen aber möglich.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/fbeaa375fc6ada26baf54d84c8dcd015\" score=\"8\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/efc9cf07880fb799240e6be3b8ad5060\">\n    <release version=\"1.0\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/7d0ee494c15aa39948c5283659fcdbec\"/>\n  </plugin>\n  <plugin displayname=\"Custom Message Boxes\" name=\"Custom Message Boxes\" homepage=\"\" short_description=\"Zeigt individuelle Messageboxen auf definierten Seiten an\" description=\"Dieses Plugin ermöglicht es, spezielle Messageboxen der verschiedenen Typen (Erfolg, Fehler, Warnung etc) auf definierten oder auch allen Seiten anzuzeigen. Dabei ist es sowohl möglich, die Darstellung nur für bestimmte Nutzergruppen oder einem bestimmten Zeitraum (ab / bis) zu ermöglichen.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/e2b7cb82ffb99586fda589c2dbe92262\">\n    <release version=\"1.4\" studipMinVersion=\"5.0\" studipMaxVersion=\"6.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/58f2b66723a3c0222732e2da0fb37f55\"/>\n    <release version=\"1.2\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/bd98b377f4cf878f04edd259f9fbacb0\"/>\n    <release version=\"1.1\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a1d3a04f74e9c556823620fd6427ce3f\"/>\n  </plugin>\n  <plugin displayname=\"CustomMenu\" name=\"CustomMenu\" homepage=\"\" short_description=\"Zur Einführung der 2.0 wurde hier beschlossen, dass einige Menüpunkte umsortiert werden sollten.Beispielsweise sollte sich der Suchbutton in der Nähe von &amp;quot;Veranstaltungen&amp;quot; befinden oder bei Klick auf Planer direkt der Stundenplan anstatt des Terminplans angezeigt werden.Dieses Plugin erledigt dies.\" description=\"****Hinweis für alle meine Plugin: Getestet bis Stud.IP 2.3.1, Support für künftige Versionen ungeklärt****&#10;&#10;  &#10;&#10;**Das Plugin benötigt je nach Standort Anpassungen im Code und sollte nicht unangepasst auf einem Live-System installiert werden.**&#10;&#10;  &#10;&#10; Alle Änderungen müssen in der Funktion __construct() durchgeführt werden.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/743772d10e774af4bf175059ff3f0c75\">\n    <release version=\"0.8.3\" studipMinVersion=\"2.3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e0aa816e5aeedaca68e4330f8586b1ef\"/>\n    <release version=\"0.8.2\" studipMinVersion=\"2.3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e9b1a6cadba076ee7f5fa10b843c2cd4\"/>\n    <release version=\"0.7\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2c4ce89acf8a01f66eeba7b502bfd34c\"/>\n  </plugin>\n  <plugin displayname=\"CustomStart\" name=\"CustomStart\" homepage=\"\" short_description=\"Das Plugin ersetzt die Stud.IP-Startseite durch eine alternative Ansicht. Die Navigation befindet sich darin links in einer Spalte, rechts ist für Inhalte reserviert.Diese basiert auf der originalen Stud.IP-Startseite.Muss standortspezifisch angepasst werden (z.B. Mensaplan)\" description=\"****Hinweis für alle meine Plugin: Getestet bis Stud.IP 2.3.1, Support für künftige Versionen ungeklärt****&#10;&#10;  &#10; Muss standortspezifisch angepasst werden (z.B. Mensaplan)&#10;&#10; Künftige Versionen könnten aber auch bspw. durch Config-Einträge generisch werden.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/b9e8c671180c31e1746de4681a35b962\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/6ef9db78738800fe3e3b778e2b5ab542\">\n    <release version=\"0.9.9\" studipMinVersion=\"2.3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2d3e673c52e5fbfa60a9a8bc93e13f0c\"/>\n    <release version=\"0.9.9\" studipMinVersion=\"2.3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c99dd3f594fd96a698b872554757d4ac\"/>\n    <release version=\"0.9.8\" studipMinVersion=\"2.3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f27d52ec8a5b7b471ae32d58805eca74\"/>\n    <release version=\"0.9\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/825d0fb51b7edea7515fe90a36514f62\"/>\n  </plugin>\n  <plugin displayname=\"CustomTeilnehmerExport\" name=\"CustomTeilnehmerExport\" homepage=\"\" short_description=\"Der Customteilnehmerexport exportiert die Teilnehmerliste einer Veranstaltung in einer anderen Version.In dieser sind mehr Daten enthalten als im Standardexport\" description=\"****Hinweis für alle meine Plugin: Getestet bis Stud.IP 2.3.1, Support für künftige Versionen ungeklärt****&#10;&#10;  &#10;&#10; Das Plugin nutzt das Plugin ExportItem\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/98c7715420d98eea5c6e3a8287c205ac\">\n    <release version=\"0.8.3\" studipMinVersion=\"2.3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/dcc1048be553d642368ce1d74f2e658e\"/>\n    <release version=\"0.8.1\" studipMinVersion=\"2.3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/471934aef45d3eb143f561a12d9d4da5\"/>\n  </plugin>\n  <plugin displayname=\"DAADSprachnachweisPlugin\" name=\"DAADSprachnachweisPlugin\" homepage=\"https://gitlab.data-quest.de/studip-plugins/DAADSprachnachweisPlugin\" short_description=\"Dieses Plugin hilft bei der Verwaltung von DAAD Sprachnachweisen im Stud.IP System.\" description=\"\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/1f054943ce8b316fc61c05b7bb861d50\">\n    <release version=\"1.0\" studipMinVersion=\"6.0\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/37f106d3156a6973e238d56c21defe57\"/>\n  </plugin>\n  <plugin displayname=\"DatabaseAdminer\" name=\"DatabaseAdminer\" homepage=\"https://github.com/Krassmus/DatabaseAdminer\" short_description=\"Datenbank von Stud.IP aus einsehen und bearbeiten.\" description=\"Dieses Plugin fügt für einen Root-User einen fertig vorkonfigurierten Adminer in den Adminbereich ein. Das bedeutet, man kann über die Stud.IP-Oberfläche die Stud.IP-Datenbank einsehen und bearbeiten, sogar einen Dump ziehen.  &#10;  &#10; Dabei ist ganz wichtig, dass der Adminer, der ja ein komplettes PHP-Skript ist, nicht für Fremde Menschen aufrufbar ist. Ein spezielles Adminer-Plugin gewährleistet die SSO-Anmeldung für alle Root-User und verhindert jeglichen anderen Zugang.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/62542c44c52ee8d194c86035416d168d\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/bbdd4103ccdc950807952af962eeb7ed\">\n    <release version=\"1.5\" studipMinVersion=\"4.0\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2427932921501377819c39428c3a8e2a\"/>\n    <release version=\"1.4.1\" studipMinVersion=\"4.0\" studipMaxVersion=\"5.2\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2cc630e82e3e778c34228c01aa7d8390\"/>\n    <release version=\"1.4\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.7\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/7975923b3204bd6298d7de04828c5122\"/>\n    <release version=\"1.3\" studipMinVersion=\"3.1\" studipMaxVersion=\"4.3\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fff89f2e39b72774cfea14b7adbd9d77\"/>\n    <release version=\"1.2\" studipMinVersion=\"3.1\" studipMaxVersion=\"4.3\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4298d9549ffb737fc13a176463f46be2\"/>\n    <release version=\"1.1\" studipMinVersion=\"3.1\" studipMaxVersion=\"4.2\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4aaaa37de35bc01f32c22594cb755353\"/>\n    <release version=\"1.0\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/3622d2a1cb30f4b710f1b843d1d61c80\"/>\n  </plugin>\n  <plugin displayname=\"Datefinder\" name=\"DatefinderPlugin\" homepage=\"https://github.com/Krassmus/DatefinderPlugin\" short_description=\"Erweitert die Fragebögen um den Termintypen &amp;quot;Terminfindung&amp;quot;, der wie ein Doodle ist.\" description=\"Manchmal wünscht man sich ein Tool wie Doodle in Stud.IP. Es gibt schon das Stoodle-Plugin aus Oldenburg bzw. eCULT. Aber ab der 3.4 gibt es in Stud.IP die noch flexibleren Fragebögen. Die Idee liegt nahe, in einem Fragebogen auch die Frage stellen zu können, wann man denn Zeit hätte. Stud.IP hat gegenüber einem Doodle drei sehr große Vorteile: 1.) Es kennt schon einige meiner Termine (Veranstaltungstermine oder private) 2.) Es wird wissen, wenn sich neue Termine für mich ergeben, die ich bei Beantwortung der Frage vielleicht noch nicht kannte (durch das Sprechstunden-Plugin zum Beispiel). 3.) Es kann einen bei dem Doodle ermittelten Termin direkt in meinen Terminkalender eintragen. Diese drei Vorteile werden von dem Datefinder-Plugin bzw. dem Terminfindungsfragetypen geschickt ausgenutzt, um Missverständnisse gleich auszuräumen. Ich habe bei der Beantwortung der Frage (siehe Screenshots) gleich die Möglichkeit zu sehen, welche Termine habe ich schon in den fraglichen Zeiträumen. Zudem habe ich die Möglichkeit zu sagen: wenn sich demnächst neue Termine für mich ergeben, soll in diesem Fragebogen meine Antwort automatisch dahingehend aktualisiert werden, dass ich da keine Zeit habe. Stud.IP aktualisiert also meine Antwort und ich muss mich um nichts kümmern. Der Vorteil ergibt sich schon bei zwei oder mehreren gleichzeitig laufenden Terminfindungen. Wenn die erste Terminfindung abgelaufen ist, wird der Termin automatisch (wenn ich das denn möchte) in meinen Terminkalender eingetragen und steht in der zweiten Terminfindung nicht mehr zur Verfügung. Und wenn ich die ganze Zeit nicht ins Stud.IP geschaut habe und mich nach dem ganzen Prozedere das erste Mal in Stud.IP wieder anmelde, habe ich zwei Termine im Terminkalender, die sich nicht überschneiden. Cool, oder? Dadurch dass dieses Plugin nur die Fragebögen erweitert, ist es auch genauso flexibel wie die neuen Fragebögen. Es kann also in Veranstaltungen, in Einrichtungen, der Startseite von Stud.IP oder meiner Profilseite eingehangen werden oder sogar in allem gleichzeitig.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/8c213b5a3f16c4108dc2cb0f480cacb5\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/f590e9ca27f2e47395654fd5d51b77a3\">\n    <release version=\"1.1\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/6fe529bdb716771df0d07fd80e440fe6\"/>\n    <release version=\"1.0\" studipMinVersion=\"3.4\" studipMaxVersion=\"3.6\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/56d5c7eff06f783ff6e9a157b8923b35\"/>\n  </plugin>\n  <plugin displayname=\"Datei Timer\" name=\"Datei-Timer\" homepage=\"\" short_description=\"Zeitgesteuertes Hochladen von Dateien\" description=\"Mit dem Datei Timer ist es möglich, Dateien im eigenen Profil hochzuladen und zu einer bestimmten Zeit in einer Veranstaltung in den Dateibereicht zu verschieben\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/578788e849f4c79808cfae1190d1dca9\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/e35cb1f8043964b8ba32a7405b0f85e9\">\n    <release version=\"1.0\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/afb765da6946ce21f253690883b10ef0\"/>\n  </plugin>\n  <plugin displayname=\"Dateisuche\" name=\"StudipContentSearch\" homepage=\"https://github.com/noackorama/StudipContentSearch\" short_description=\"Plugin für die Suche nach Dateien und Dateiinhalten (experimentell)\" description=\"Das Plugin ermöglicht eine Stud.IP weite Suche nach Dateien. Es wird in Name, Autor, Dateityp und optional im Inhalt der Datei gesucht. Die Inhalte werden in Textform aus den Originaldateien extrahiert und in einer separaten Index Tabelle vorgehalten. Für gefundene Dateien gibt es eine Vorschau und Downloadmöglichkeit, wenn man Zugriff auf die Datei hat. Wenn die gefundene Datei in einer frei zugänglichen Veranstaltung gefunden wurde, wird nur ein Link zu dieser Veranstaltung angeboten.  &#10;  &#10; Damit die Dateiinhalte extrahiert werden können, müssen auf dem Server entsprechende Kommandozeilentools installiert sein:&#10;&#10;&#10;    pdf: pdfinfo,pdftotext (Paket poppler-utils)&#10;    doc,rtf,xls,ppt: catdoc&#10;    odt: odt2txt&#10;    txt,docx,xlsx,pptx: im Plugin integriert&#10;&#10;&#10;### ACHTUNG:&#10;&#10; In der Indextabelle werden alle Inhalte von Veranstaltungsdateien gespeichert. Dies wird nur bis zu einer gewissen Anzahl/Größe an Dateien funktionieren. Wer versucht das Plugin auf einer großen Stud.IP Installation zu betreiben sei gewarnt. Bei den üblichen 100en von Gigabytes an Dateien die dort vorhanden sind, wird schon das initiale Erstellen des Index viele Stunden dauern. Die enstehende Indextabelle könnte schlicht zu groß werden, um eine halbwegs performante Abfrage über die Mysql Volltextsuche zu ermöglichen.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/e0b624d07891bb32e35a310afca75094\" score=\"8.9755400895366\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/fd3e2bf6196731d9bf66953ffebcdcec\">\n    <release version=\"0.8\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/06533a8d844a2b0c20a785b9cd469c18\"/>\n  </plugin>\n  <plugin displayname=\"DatenfeldSuche\" name=\"DatenfeldSuche\" homepage=\"\" short_description=\"Mit der Datenfeldsuche lassen sich Veranstaltungen aufgrund ihres freien Datenfelds finden. Beispiele: Datenfelder Sprache oder Modul.\" description=\"****Hinweis für alle meine Plugin: Getestet bis Stud.IP 2.3.1, Support für künftige Versionen ungeklärt****&#10;&#10; &#10;&#10;Version 1.0 für Stud.IP 2.3+&#10;&#10;kleinere Versionen: benötigt zwingend die angepasste Button-API in der 2.2. siehe hierfür das Plugin markItUp&#10;&#10; &#10;&#10;Die Suche geht dabei nicht trennscharf vor sondern nutzt reguläre Ausdrücke, um auch ähnliche Treffer zu finden.&#10;&#10;Die Suche nach dem Modul **MT1 **ist gleichwertig zur Suche nach **MT 1**. Damit sollen Flüchtigkeitsfehler Seitens der Dozenten oder Admins berücksichtigt werden. **  &#10;**\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/cc4709240d216c09f04917b62c452fe6\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/7e501fdc4d34bcfb9b53ab118d70a58b\">\n    <release version=\"1.0.2\" studipMinVersion=\"2.3\" studipMaxVersion=\"2.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/58ec266516340b76d8d6fc79b0e3bf69\"/>\n    <release version=\"1.0.1\" studipMinVersion=\"2.3\" studipMaxVersion=\"2.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f0405103c00525a466cbae7b21d2af8e\"/>\n    <release version=\"1.0\" studipMinVersion=\"2.3\" studipMaxVersion=\"2.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c6900a69c62931eb77d8810748e60872\"/>\n    <release version=\"0.9\" studipMinVersion=\"2.0\" studipMaxVersion=\"2.2.2\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/d34d931cf7f3f4e3505f19c9a9abd8a2\"/>\n  </plugin>\n  <plugin displayname=\"Datenschutz\" name=\"Datenschutz\" homepage=\"\" short_description=\"Plugin zur Unterstützung beim Export von personenbezogenen Daten.\" description=\"Datenschutz-PlugIn zur EU DSGVO&#10;===============================&#10;&#10;Stud.IP ist nach dem Grundsatz der Datensparsamkeit und in Einklang mit den Datenschutzgesetzen der Bundesländer entwickelt worden: Daten werden immer nur dort erhoben, wo es unumgänglich und notwendig ist, Anwenderinnen und Anwender können selbst entscheiden, wo welche Informationen von Ihnen sichtbar sind.Schon immer konnten Systemadministratoren Auskunft über die erhobenen und verarbeiteten Daten geben.  &#10;  &#10;&#10;Das von data-quest entwickelte und kostenlos zur Verfügung gestellte Plugin ist für Stud.IP 4.x und Stud.IP 3.5 verfügbar. Es setzt  folgende Anforderungen um:&#10;&#10;- Informationsmöglichkeiten: Das PlugIn baut in den Footer des Systems einen Link auf die Datenschutzerklärung ein. Es ist eine Musterdatenschutzerklärung hinterlegt, die aber ZWINGEND von Betreibern angepasst werden muss!&#10;- Auskunftsrecht: Anwenderinnen und Anwender können an eine hinterlegte Mailadresse aus der Datenschutzerklärungsseite heraus oder von ihrer persönlichen Profilseite aus eine Auskunftsanfrage stellen. Betreibereinrichtungen müssen dann Auskunft darüber geben, welche Daten von der anfragenden Person gespeichert sind.  Hierzu bietet das Plugin für Root die Möglichkeit, alle im Kernsystem gespeicherten Daten der Person aufzurufen. Dazu gehören personenbezogene Daten wie Name, Mailadresse, persönliche Angaben, aber auch belegte Kurse, hochgeladenes Profilbild, Forenbeiträge, eigene Dateien, etc. Die Daten werden in einer Übersicht dargestellt. Die Übersicht lässt sich als PDF- oder CSV-Datei exportieren. Alternativ lässt sich das PlugIn so konfigurieren, das auch Admins oder Nutzerinnen und Nutzer für sich selbst ihre Daten einsehen und herunterladen können.&#10;- Recht auf Datenübertragbarkeit: Alle Daten einer Person lassen sich von Root (konfigurierbar auch von der Person selbst) als ZIP-Files herunterladen. Darin enthalten sind alle eigenen Dateien sowie Datenbankeinträge in CSV-Dateien. Diese lassen sich in eine andere Stud.IP-Datenbank manuell übertragen. Da es keinen Standard für Datenaustausch zwischen LMS/CMS gibt, muss für die Übertragung in andere Systeme die CSV ggf. transformiert werden.&#10;- Recht auf Löschung: Hier gibt es keine Änderungen durch das PlugIn. Das Löschen einer Person im Stud.IP-System löscht schon immer alle personenbezogenen Daten und, falls gewünscht, auch der hochgeladenen Dateien. Forenbeiträge und Wikieinträge werden anonymisiert.&#10;&#10;   - - - - - -&#10;&#10;  &#10; Achtung!&#10;============&#10;&#10;Die folgenden Hinweise sind sehr wichtig und müssen unbedingt beachtet werden:&#10;&#10;- Das DatenschutzplugIn stellt in der vorliegenden Version nur Funktionen und Informationen betreffend des Kernsystems zur Verfügung, NICHT aus evtl. im Einsatz befindlichen PlugIns.&#10;- Für die wenigen PlugIns, die personenbezogene Daten speichern, bringt das Datenschutzplugin eine Mini-API zur Abfrage und Löschung der Daten mit. Diese Funktionen müssen aber in alle weiteren PlugIns integriert werden ODER die in Plugins gespeicherten Infos müssen händisch zum Datenpaket der Person hinzugefügt werden.&#10;- Im Datenschutzplugin ist eine Musterdatenschutzerklärung enthalten. Diese muss UNBEDINGT durch die eigene Datenschutzerklärung ersetzt oder zumindest angepasst werden.&#10;- Das DatenschutzplugIn ist verfügbar für Stud.IP 3.5 und 4.x. Für ältere Versionen wird das Plugin nur im Auftrag rückportiert.&#10;- Ab Stud.IP 4.2 (Herbst 2018) ist das Datenschutzplugin fester Bestandteil von Stud.IP und bietet dann eine breit ausgebaute Datenschutz- und Archivierungs-API.&#10;- Das Datenschutzplugin wird von der data-quest GmbH zur Verfügung gestellt. Es wurde in Zusammenarbeit mit dem unternehmensinternen Datenschutzverantwortlichen entwickelt und ist für Betreiber die Grundlage um ihr Stud.IP rechtssicher zu gestalten. Die data-quest GmbH weist aber ausdrücklich darauf hin, dass die Installation des PlugIns alleine NICHT ausreicht. Die enthaltenen Mustertexte müssen von der jeweiligen Betreibereinrichtung mit ihren eigenen Datenschutzexperten besprochen und an die eigenen Hausregeln angepasst werden.&#10;- Data-quest übernimmt KEINE Haftung.&#10;- Diese Seite stellt KEINE Rechtsberatung dar.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/c68c7693193bda53859b5148bb8b0d75\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/c19d6eaa40a4154337a302050ecc5ece\">\n    <release version=\"1.41.6\" studipMinVersion=\"4.1\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/24b9cf211041db6677937bd346497236\"/>\n    <release version=\"1.41.5\" studipMinVersion=\"4.1\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e5cf1e2c518c40994464fda4386c3a0b\"/>\n    <release version=\"1.41.4\" studipMinVersion=\"4.1\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8e24a96ce9e376a41d498c652ac17706\"/>\n    <release version=\"1.41.3\" studipMinVersion=\"4.1\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f831314fceceaa9e34a4b3757ff9ce11\"/>\n    <release version=\"1.41.2\" studipMinVersion=\"4.1\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/df56868e111156af72758f00c0a82f0b\"/>\n    <release version=\"1.41.1\" studipMinVersion=\"4.1\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a8092b9f7ee6aa3aae9b2fab2ba60b44\"/>\n    <release version=\"1.41.0\" studipMinVersion=\"4.1\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f1118db67de77d0e4b0d27585d0c3fac\"/>\n    <release version=\"1.40.6\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2fe1d7f4c38f508219c2c3e201d0c014\"/>\n    <release version=\"1.40.5\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/07d44ea7e4a896a733583f73789ede97\"/>\n    <release version=\"1.40.4\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b37060336546d62ce24e31660ff70219\"/>\n    <release version=\"1.40.3\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fc8d72c956c5b8d8e6e7be47cdc7fec9\"/>\n    <release version=\"1.40.2\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/0ac7e01a4d264ae3af72a952a715164d\"/>\n    <release version=\"1.40.1\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/660baf1abd2989931a001264faf0becf\"/>\n    <release version=\"1.40.0\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a7e040ed021ba7356ffb476565571d32\"/>\n    <release version=\"1.35.5\" studipMinVersion=\"3.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a898dbf4132bd797cbf4f39ccb72dd64\"/>\n    <release version=\"1.35.4\" studipMinVersion=\"3.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/d589049c44293208c4c3cf5b62c91df4\"/>\n    <release version=\"1.35.3\" studipMinVersion=\"3.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/7ee47d38e4c74d3bcd84d63658ed11d1\"/>\n    <release version=\"1.35.2\" studipMinVersion=\"3.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/46a239b8e5964d879d575f7f97581ca3\"/>\n    <release version=\"1.35.1\" studipMinVersion=\"3.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ccfc34d1e4942f6311d77f11a1dc5e81\"/>\n    <release version=\"1.35.0\" studipMinVersion=\"3.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/26f80a3a2b97458b50224a09e7193f5b\"/>\n  </plugin>\n  <plugin displayname=\"DeleteMessages\" name=\"DeleteMessages\" homepage=\"\" short_description=\"Auswahl und Löschung von mehreren Nachrichten\" description=\"**Ermöglicht das Auswählen und Löschen von mehreren Nachrichten im Posteingang und -ausgang.**\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/679d4f18a74f4b2047e924e4dd59e09f\" score=\"7.0096256295213\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/4200c03cb493ba531c722fdc18c958b0\">\n    <release version=\"0.1.3\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/47dcbfcc9b7cda3a30df2fa67d2a929f\"/>\n    <release version=\"0.1.1\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/459a696293bc87507f19b72e631d5a25\"/>\n  </plugin>\n  <plugin displayname=\"DeLorean\" name=\"DeLorean-Wiederherstellungsmaschine\" homepage=\"https://gitlab.data-quest.de/studip-plugins-oeffentlich/DeLorean\" short_description=\"Timemachine für Stud.IP.\" description=\"Wenn man schon durch die Zeit reisen will, dann doch bitte mit Stil!&#10;&#10;Die DeLorean-Wiederherstellungsmaschine gibt Root in Stud.IP die Möglichkeit, alle Änderungen (oder sagen wir mal die meisten) einzusehen und wieder rückgängig zu machen.  &#10;  &#10;Beispiel: Ein Dozent beschwert sich bei den Admins, dass sein Dateibereich keine Dateien mehr hat, behauptet aber, er habe ganz sicher nichts verändert. Der Admin kann dann als Root in den DeLorean steigen und sieht ganz genau, wer die Dateien gelöscht hat. Er sieht auch den Zeitpunkt, an dem sie geändert worden sind und was genau (zum Beispiel dass sie gelöscht worden sind). Zudem kann er die jeweiligen Änderungen mit Checkboxen anklicken und alle Änderungen wieder rückgängig machen. Das bedeutet, er kann die Dateien alle wiederherstellen.  &#10;  &#10;Unter Admin -&amp;gt; System taucht ein Navigationspunkt auf, der &amp;quot;Delorean Wiederherstellungsmaschine&amp;quot; heißt. Dort sieht man eine Übersicht (siehe Screenshot) aller protokollierten Änderungen. Man kann sich die Details einer Änderung ansehen. Aber man kann auch nach Typen filtern oder nach einem bestimmten Zeitpunkt, um alle Änderungen anzusehen, die gleichzeitig passiert sind (wie beim Massenlöschen). Oder man benutzt die Suchfunktion, um beispielsweise eine user_id oder eine seminar_id einzugeben, und sieht dann alle Änderungen, die in irgendeiner Form direkt mit dem Nutzer oder der Veranstaltung zu tun haben.  &#10;  &#10;Weitere Features:&#10;&#10;- Maximaler Speicherplatzverbrauch: Wie jedes Backup braucht auch der DeLorean zusätzlichen Speicherplatz. Man kann einstellen, dass aber nicht mehr als x GB verwendet werden sollen.&#10;- Anonymisierung: Man kann die Daten, die der DeLorean erfasst anonymisieren - entweder sofort oder nach einer bestimmten Zeit wie einer Woche.&#10;- Lehrende und Tutor*innen können optional innerhalb einer Veranstaltung selbst die gelöschten Dateien wiederherstellen. Für sie taucht im Dateibereich eine Aktion auf &amp;quot;Gelöschte Objekte wiederherstellen&amp;quot;, wenn es denn gelöschte Objekte gibt. Hier kann man die Ordner und Dateien einfach per Klick wiederherstellen, ohne Admins anschreiben zu müssen.&#10;&#10;  &#10; \" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/2f0a77747b01583388a5eee517d1c70e\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/d8a5a8a9365deb0b23f85f46f1bb5ab3\">\n    <release version=\"3.1.2\" studipMinVersion=\"5.0\" studipMaxVersion=\"6.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/10c25151ecea092fdfd73e890bbe690c\"/>\n    <release version=\"2.9\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/17f2d6eaf25b6ac99d8bf14ca2ec482c\"/>\n    <release version=\"2.7\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ec40691a2411fe645d3cba0deacff375\"/>\n    <release version=\"2.20\" studipMinVersion=\"4.0\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e0222d9bbe84975c903168fc8d230362\"/>\n    <release version=\"2.17\" studipMinVersion=\"4.0\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/69184c5ed7a40452178da23899916f4c\"/>\n    <release version=\"2.13\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4d75d1249706d9b91d6ed45516135e26\"/>\n    <release version=\"2.12\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f12767eb3aaf32865c7151f4b535a1f8\"/>\n    <release version=\"2.11\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e4d82d0bad98c9fe239ba41345e25fe3\"/>\n  </plugin>\n  <plugin displayname=\"DetailsAblaufplanPlugin\" name=\"DetailsAblaufplanPlugin\" homepage=\"\" short_description=\"Zeigt den Ablaufplan auch auf der Detail-Seite der Veranstaltung - auch für Personen, die noch nicht Teilnehmende sind.\" description=\"Manchmal möchte man, wenn man sich für eine Veranstaltung interessiert, sehen, wie der genaue Ablauf der Veranstaltung aussieht. Warum nicht? Dieses Plugin zeigt unter der Detailseite einfach den Ablaufplan an, sodass man genau sehen kann, welche Themen zu welchem Termin bei welchem Lehrenden stattfindet.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/83c13357df875face4870ec77ea88dc4\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/dcf2d4f11e63fddfc33c0bf545f6feae\">\n    <release version=\"1.1\" studipMinVersion=\"4.5\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/beefe1e5c5210331b6fdbc24c9826c40\"/>\n  </plugin>\n  <plugin displayname=\"DigicampusHeader\" name=\"DigicampusHeader\" homepage=\"\" short_description=\"Digicampusheader passt das Design von Stud.IP an das lokale Corporate Design an.\" description=\"Ein Plugin, wie es sicherlich viele Institutionen erstellt haben: Per CSS wird die Kopfzeile von Stud.IP an das lokale Corporate Design angepasst. Weiterhin wird das favicon ausgetauscht und die Druckansicht angepasst.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/95f1eb4b5988159a06649ee01f29ba71\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/16eb8554b325c73b8f3cd329d373a4f1\">\n    <release version=\"0.8\" studipMinVersion=\"2.3\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/73dfb181c80693c156f0dc90c46d52f8\"/>\n  </plugin>\n  <plugin displayname=\"Diplomacy\" name=\"Diplomacy\" homepage=\"https://github.com/Krassmus/Diplomacy\" short_description=\"Spiel den Strategieklassiker in einer Veranstaltung mit Freunden.\" description=\"Spiel Diplomacy, den Strategieklassiker online mit Freunden innerhalb einer Veranstaltung oder Studiengruppe! Diplomacy ist eigentlich ein strategisches Brettspiel, das den ersten Weltkrieg in Europa nachspielt. Es gibt Armeen und Flotten. Wichtig ist allerdings, dass Diplomacy komplett ohne Zufall auskommt. Dadurch ist es besonders wichtig, dass man sich mit den anderen Spielern abspricht, dass man Bündnisse schmiedet und sie natürlich hin und wieder auch bricht. Die Kommunikation zwischen den Spielern ist ein zentrales, ganz wichtiges Element in dem Spiel. Nur wer gut verhandeln kann, kann das Spiel gewinnen. Der Ablauf von Diplomacy ist so, dass alle Spieler gleichzeitig verhandeln, zeitgleich einfache Befehle für ihre Einheiten aufschreiben und alle gemeinsam zeitgleich diese Befehle aufdecken. Erst durch die Kombination der Befehle ergibt sich, welche Befehle erfolgreich sind und welche geblockt werden. Ich habe dieses Plugin gebaut, weil meine eigenen Freunde, mit denen ich gerne Diplomacy gespielt habe, jetzt über die ganze Republik verteilt sind. Ich suchte nach einer guten Möglichkeit, dass wir die Befehle, die wir aufschreiben, irgendwo speichern können, ohne dass die Mitspieler sie lesen können. Das Plugin macht genau das: In einer Veranstaltung von Stud.IP macht man eine neue Runde Diplomacy, weist die Spieler den Ländern zu und startet den ersten Zug. Dann kann jeder Spieler für sein Land Befehle aufschreiben. Und erst wenn der Spielleiter, der selbst mitspielen kann, den neuen Zug zu einem verabredeten Zeitpunkt beginnt, können alle Spieler die Befehle der anderen Spieler aus der letzten Runde einsehen. Mit diesen Informationen weiß man, wo die eigenen Einheiten in der neuen Runde stehen, kann neu verhandeln und neue Befehle aufschreiben. Verhandeln kann man in Stud.IP über Blubber (hat sich gut bewährt) oder über Direktnachrichten. !! Features - Länder des Spiels sind Gruppen der Veranstaltung. Dadurch können sogar mehrere Personen ein Land gemeinsam spielen. Oder ein Spieler kann mehrere Länder spielen, wenn nicht genug Spieler da sein sollten. - Alle Diplomacy-Karten sind spielbar, nicht nur die Classic-Karte. Im Internet findet man viele Kartenvarianten wie Colonial Diplomacy, Zweiter Weltkrieg oder Mittelerde-Diplomacy. - Spielregeln sind im Plugin verlinkt, erprobte Regelvarianten sind ebenfalls möglich und werden erläutert. - Man braucht einen Spielleiter, der kann aber selbst mitspielen, da nicht einmal er die Befehle der anderen Spieler einsehen kann. - Spielzüge können vom Spielleiter eine besondere Beschreibung bekommen und man kann eine Karte zu dem Zug hochladen, auf der die Spieler den aktuellen Stand sehen. So eine Karte müsste natürlich vom Spielleiter gemalt werden, ist aber nicht zwingend zum Spielen nötig. - Es gibt eine Historie, in der man alle Karten aller Züge des Spiels durchsliden kann. Das sieht sehr cool aus und man kann im Nachhinein sehr schön sehen, wie ein Spieler sein Reich vergrößert. - Rundenwechsel können automatisch (also auch in Abwesenheit des Spielleiters) zu einem bestimmten Zeitpunkt geschehen oder wenn alle Spieler anklicken, dass sie fertig sind, auch vorher schon.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/284c53d45342c0662206a84fca6cc97f\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/0057201fef7b646faf216c0138f5796c\">\n    <release version=\"1.1.2\" studipMinVersion=\"4.4\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/71d4415597f689c0a7c85f759b793f0f\"/>\n    <release version=\"1.1.1\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f85bd10160ca6bec4a93ae6943ae7c04\"/>\n    <release version=\"1.0.7\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c0308bdcaa8d39a5212f45f30c80efd5\"/>\n  </plugin>\n  <plugin displayname=\"Dokumentation von Online-Prüfungen in Stud.IP und Präsenzterminen\" name=\"Klausurplaner\" homepage=\"\" short_description=\"Klausurplaner für die Dokumentation der Verwendung von Prüfungstools und Präsenzterminen\" description=\"Dokumentation von Online-Prüfungen in Stud.IP und Präsenzterminen  &#10; Mit diesem Plugin kann die Nutzung von definierbaren Tools (in Stud.IP oder extern) sowie die Wahrnehmung von Präsenzterminen dokumentiert werden. Ursprünglich wurde es dafür konzipiert, bestimmte Last-Konstellationen zu erkennen (Überlast für bestimmte Systembereiche bei zeitgleicher Nutzung vieler Personen) und im weiteren Verlauf dahin erweitert, während der Pandemie-Zeit eine Abschätzung der notwendigen Test-Kapazitäten (Covid19-Schnelltests) zu ermöglichen. Dozenten und Tutoren einer Veranstaltung im aktuellen oder nachfolgenden Semester sind berechtigt, hier ihre Prüfungs- und/oder Anwesenheitstermine mit entsprechender Personenstärke einzutragen.  &#10;  &#10; Die Bezeichnung und Anzahl von &amp;quot;Fachbereichen&amp;quot;, &amp;quot;Tools&amp;quot; und den verwendeten Farben bzw. Wertegrenzen kann über die Konfiguration im Root-Bereich vorgenommen werden.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/8feedbfb3ab78f31e5cabc8e95ede8d8\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/7b4b66220e9de585b7bd535d34aadde7\">\n    <release version=\"1.0\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.5\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f5b4f25666bb1642022ca051f8c6e6a2\"/>\n  </plugin>\n  <plugin displayname=\"Doorman - Automatisches Setzen von Anmeldeeinstellungen\" name=\"Doorman\" homepage=\"https://gitlab.data-quest.de/studip-plugins-oeffentlich/doorman\" short_description=\"Stellt X Tage vor Veranstaltungsbeginn automatisch Einstellungen wie verbindliche Anmeldung, Wartelisten usw.\" description=\"Pro Einrichtung kann man Cronjob-Tasks anlegen, die X Tage vor Beginn einer Veranstaltung die Anmeldung auf &amp;quot;verbindlich&amp;quot; setzen, die Warteliste oder das automatische Nachrücken deaktivieren.&#10;&#10;Bitte beachten:&#10;===============&#10;&#10;Beim Update auf 2.0 am besten die alte Version löschen und dann die neue Version installieren.&#10;&#10;Was ist neu?&#10;============&#10;&#10;Doorman kann nun auch Erinnerungsnachrichten X Tage vor Beginn verschicken und ist mit Stud.IP 5.x und PHP 8.x kompatibel.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/8a4e6929b18c9c7509b87f3f04703837\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/cbed3c9ad5bc011f91c1293fede587b6\">\n    <release version=\"2.0\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/914b781ceb12c8edb76a061d875f65c1\"/>\n    <release version=\"1.2\" studipMinVersion=\"4.0\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/0e86e0e65921fbe43ac7af41c9c512d6\"/>\n    <release version=\"1.0\" studipMinVersion=\"2.4\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/22157bcad69e95ed359c46db39ff8a4b\"/>\n    <release version=\"1.0\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/82825a3b915eddd2971ca7e69a7fc2b2\"/>\n  </plugin>\n  <plugin displayname=\"eAufgaben-Models\" name=\"eTaskModels\" homepage=\"https://gitlab.elan-ev.de/studip/studip-plugin-eaufgaben-models\" short_description=\"Macht ihr Stud.IP v3.x kompatibel für eAufgaben-Tools\" description=\"eAufgaben-Tools wie zum Beispiel Cliqr können mit diesem Plugin auch in Stud.IP-Versionen v3.x betrieben werden. Normalerweise sind die eAufgaben-Basisdateien nur in Stud.IP Versionen ab v4.0 vorhanden.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/4bddd4d1a24354316d3cb1eeb64b443d\">\n    <release version=\"1.0.0-beta.3\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/0e1fd063b2c85faf150a3e9379dac771\"/>\n  </plugin>\n  <plugin displayname=\"EctsOverview\" name=\"EctsOverview\" homepage=\"\" short_description=\"ECTS Übersicht für Studierende\" description=\"Mit dem EctsOverview Plugin ist es möglich, dass Studierende einen Überblick über die bisher erreichten ECTS erhalten. Ein manuelles bearbeiten der ECTS für die Statistik ist ebenfalls möglich. So können auch Veranstaltungen, deren ECTS Punkte nicht geflegt werden trotzdem in der Statistik auftauchen\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/89139856cf690c3aacc2c1ddc6b04d2f\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/8d45d6881eefe14cb7bed02812d3d4ca\">\n    <release version=\"1.0\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/9944ecdb92d40034fa8118866709b5d7\"/>\n  </plugin>\n  <plugin displayname=\"EditSemesterPlugin\" name=\"EditSemesterPlugin\" homepage=\"https://github.com/Krassmus/EditSemesterPlugin\" short_description=\"Mit diesem Plugin kann man Zeiten von Semestern ändern, die schon Veranstaltungen haben.\" description=\"Normalerweise kann man in Stud.IP die Zeiten von Semestern nicht mehr ändern, sobald ein Semester mindestens eine Veranstaltung hat. Mit diesem Plugin ist das dennoch möglich.  &#10;  &#10; Man kann unter Admin -&amp;gt; Standort -&amp;gt; Semester in der Sidebar unter Aktionen den Punkt &amp;quot;Semesterzeiten ändern&amp;quot; auswählen. Das ist etwas gedoppelt in der Oberfläche, ließ sich aber anders als Plugin nicht einbauen. Dort wählt man das betreffende Semester aus und verändert dann ausschließlich das Ende dieses Semesters. Der Beginn des Nachfolgenden Semesters wird automatisch mit geändert. Und natürlich bleiben alle Veranstaltungen dem richtigen Semester zugeordnet. Funktioniert auch für Mehrsemestrige Veranstaltungen.  &#10;  &#10; Dieses Plugin verändert wirklich nur die Semesterzeiten, nicht aber die Vorlesungszeiten und auch nicht die Zeiten regelmäßiger Termine! Das muss man dann noch danach händisch verändern, was aber auch über Kernfunktionalitäten von Stud.IP kein Problem ist.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/c832f125ed0e4005219a39cfd85b7b67\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/357b06be0c5a9cb1f0238fed37dd61df\">\n    <release version=\"1.0\" studipMinVersion=\"\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4695293adf60b5e9a51150060246df23\"/>\n  </plugin>\n  <plugin displayname=\"ELMO (&amp;quot;E-Learning-Modul&amp;quot;)\" name=\"Elearning-Modul\" homepage=\"\" short_description=\"Ermöglicht eine thematische Strukturierung von Aufgabenstellungungen für e-learning Szenarien.\" description=\"\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/73b05a113a23ce983af5cad3a99c2bbd\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/dc3f7b679263700e54109cb43b49c62f\">\n    <release version=\"0.70\" studipMinVersion=\"3.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/506deddf452af36c279cc8b0fe5442a3\"/>\n    <release version=\"0.65\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5934567c0dccc8f93a7b3d24bf4fc72a\"/>\n    <release version=\"0.58\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/1ef249c1b18330d9cf5bd2394464334d\"/>\n  </plugin>\n  <plugin displayname=\"ErgebnisPinPlugin\" name=\"ErgebnisPinPlugin\" homepage=\"https://gitlab.studip.de/luh/plugins/ErgebnisPinPlugin\" short_description=\"Stellt Ergebnis-PINs zur anonymen Bekanntgabe von Klausurnoten bereit\" description=\"ErgebnisPinPlugin&#10;=================&#10;&#10;Stellt Ergebnis-PINs zur anonymen Bekanntgabe von Klausurnoten bereit. PINs werden im Veranstaltungskontext angezeigt. Studierende sehen dort nur ihre eigene PIN, Lehrende und Tutor/innen sehen dort die gesamte Liste und können diese als CSV herunterladen. Die Matrikelnummern (die entsprechende Datenfeld-ID kann in der Admin Konfiguration angepasst werden) können bei Bedarf auch für Tutor/innen angezeigt werden.&#10;&#10;Changelog&#10;=========&#10;&#10;**2024-02-07 v1.5**&#10;&#10;- Das Auge beim &amp;quot;Matrikelnummer für TutorInnen unsichtbar schalten&amp;quot; wechselt nun zwischen offen und geschlossen&#10;&#10;**2024-01-23 v1.4**&#10;&#10;- Sortierung der Liste erfolgt nun neben dem Nachnamen auch mit dem Vornamen; so ist die Liste einheitlich zur Teilnehmenden-Liste der Veranstaltung sortiert.&#10;&#10;**2023-09-04 v1.3**&#10;&#10;- Alle Meldungen ins Englische übersetzt&#10;- Begriffe vereinheitlicht&#10;&#10;**2023-06-12 v1.2**&#10;&#10;- Callback für *CourseDidDelete* hinzugefügt&#10;&#10;**2023-05-03 v1.1**&#10;&#10;- Datenfeld-ID der Matrikelnummer konfigurierbar gemacht&#10;&#10;**2023-01-30 v1.0**&#10;&#10;- Stud.IP 5.3-ready\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/2c996c6b5da64826582bb0d72231f03d\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/b239918e3a3d640ea8c75549a4f78692\">\n    <release version=\"1.5\" studipMinVersion=\"4.3\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/1d3e044d7294496b289834f3ffe6ef82\"/>\n    <release version=\"1.4\" studipMinVersion=\"4.3\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b49112b313029324de830ba5ee11d249\"/>\n    <release version=\"1.3\" studipMinVersion=\"4.3\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a49bde0d4bedeca6bdaea809262cffe4\"/>\n    <release version=\"1.2\" studipMinVersion=\"4.3\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5a9177937e25d5d386f08b27f02aeecd\"/>\n    <release version=\"1.1\" studipMinVersion=\"4.3\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/24d2551d520bde7e10655ea3aae013fb\"/>\n    <release version=\"1.0\" studipMinVersion=\"4.3\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c907cca20c0861b241ee9c4ea642627e\"/>\n  </plugin>\n  <plugin displayname=\"ESA (Elektronischer Semester Apparat)\" name=\"Elektronischer Semester Apparat\" homepage=\"https://develop.studip.de\" short_description=\"Ermöglicht es zentral Semesterapparate für Veranstaltungen zu administrieren\" description=\"Elektronischer Semester Apparat (ESA)&#10;=====================================&#10;&#10;Aufgabe des Plugins ist es, parallel zu den klassischen Semesterapparaten auch elektronische Semesterapparate anzubieten, die in Stud.IP integriert werden und nur für die Teilnehmer/-innen einer Lehrveranstaltung verfügbar sind. In den elektronischen Semesterapparaten sollen neben den Katalognachweisen auch digitale Ressourcen wie eBooks, gescannte Kopien oder Internetquellen zugreifbar sein.&#10;&#10;Die Anzeige des elektronischen Semesterapparates erfolgt über ein eine erweiterte Literaturliste. Dateien werden in einer versteckte Dateiablage abgelegt und von der Literaturliste aus verlinkt. Der Zugang zu den Dateien erfolgt für normale Nutzer/-innen (Studenten, Dozenten) nur über die Literaturliste, zusätzlich kann der Zeitraum in dem der Zugriff erlaubt ist beschränkt werden.&#10;&#10;Alle Arbeiten, die zur Erstellung und Bearbeitung der elektronischen Semesterapparate in Stud.IP erforderlich sind, werden ausschließlich durch Nutzer denen die spezielle Rolle “Literaturadministrator“ zugewiesen wurde durchgeführt (z.B. eine Mitarbeiterin bzw. einen Mitarbeiter der Bibliothek). Dazu ist es nicht erforderlich diesem Nutzer administrative Rechte für die Veranstaltungen einzuräumen, alle notwendigen Einstellungen werden über das Systemplugin vorgenommen.&#10;&#10;Dozentinnen und Dozenten einer Veranstaltung dürfen selbst keine Änderungen an dem Semesterapparat durchführen. Diese Restriktionen sind notwendig, da das Urheberrecht beachtet und die Lizenzverträge mit den Verlagen eingehalten werden müssen. Deshalb prüfen Mitarbeiter/-innen der Bibliothek im Vorfeld von Fall zu Fall, ob die angeforderten Dokumente in einer Veranstaltung zur Verfügung gestellt werden dürfen. Im Falle von gescannten Kopien muss zusätzlich die Zugangsbeschränkung auf einen bestimmten Teilnehmerkreis sichergestellt werden (s. § 52a UrhG). Daher ist der Zugriff auf die Dokumente ausschließlich über das Plugin möglich. Beim Zugriff wird zusätzlich überprüft, ob es sich um eine geschlossene Veranstaltung (mit Passwort gesichert) handelt.&#10;&#10;- Installation und Konfiguration: http://plugin-dev.studip.de/index.php/Plugins/EsaPluginInstallation&#10;- Erstellung und Pflege von Semesterapparaten: http://plugin-dev.studip.de/index.php/Plugins/EsaPluginListen&#10;- Dokumente zu Semesterapparaten: http://plugin-dev.studip.de/index.php/Plugins/EsaPluginDokumente&#10;- Semesterapparat in der Veranstaltung: http://plugin-dev.studip.de/index.php/Plugins/EsaPluginVeranstaltung\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/9667533d76eef28ca3c51e11763c114c\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/cb8178c22e70c87c3eaaa494e3582e4c\">\n    <release version=\"0.73\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/74296d373c223ea1c71f31308ccfdc71\"/>\n    <release version=\"0.7\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b171c2e2cbe575f7e67ae7e939c7cc0c\"/>\n    <release version=\"0.62\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/422a432d28189f410e7271ea1df99d8b\"/>\n    <release version=\"0.6\" studipMinVersion=\"2.3\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/65c16ae065ad0fac51032d0b8dcbd154\"/>\n    <release version=\"0.44\" studipMinVersion=\"2.0\" studipMaxVersion=\"2.2\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/296645ce758ed90962340d17cf751ccf\"/>\n  </plugin>\n  <plugin displayname=\"Etherpad-Plugin\" name=\"EtherpadPlugin\" homepage=\"https://develop.studip.de/studip/dispatch.php/course/scm?cid=c40fcd60f27af624ecbb3311a5958be4\" short_description=\"Gemeinsam Texte erstellen und die Texterstellung koordinieren\" description=\"Mit diesem Plugin können Sie allein oder mit vielen Menschen gleichzeitig Texte bearbeiten. Alle Teilnehmende der Veranstaltung können lesen und schreiben.&#10;&#10;- Echt gleichzeitiges Arbeiten: Mehrere Personen können zur gleichen Zeit bearbeiten, alle sehen die Änderungen sofort.&#10;- Versionshistorie: Keine Änderung geht verloren, benutzen Sie das Uhr-Symbol oben.&#10;- Zwischenstände speichern: Im Menu links können sie den &amp;quot;aktuellen Inhalt sichern&amp;quot;, der dann als PDF-Datei im Dateibereich landet.&#10;- Beliebig viele Pads pro Veranstaltung&#10;- Weltweiter Zugriff möglich: Im Menü links können Sie das Pad veröffentlichen und die dann angezeigte URL weitergeben.&#10;&#10;  &#10; Bei diesem Plugin handelt es sich um eine Weiterentwicklung des StudIPad-Plugins des ZMML mit erweitertem Funktionsumfang und Installationsanweisung für das Etherpad.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/09014b60b564afc9061cf18751c8ab95\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/b981b9863285bb657537f9adda1570a3\">\n    <release version=\"4.1\" studipMinVersion=\"4.6\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/3734089028a25bd01ed56270ac972627\"/>\n    <release version=\"4.0\" studipMinVersion=\"4.6\" studipMaxVersion=\"5.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5a1db74dc2399ee12cdcbd088199b4e1\"/>\n    <release version=\"3.1\" studipMinVersion=\"4.6\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f718bb3f5778bbdc7fb02e0b75800280\"/>\n    <release version=\"3.0\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e2e1fcbc6bde6b2fa15a76ff1f0c4fde\"/>\n  </plugin>\n  <plugin displayname=\"EvasysPlugin\" name=\"EvasysPlugin\" homepage=\"https://gitlab.studip.de/studip/plugins/EvasysPlugin\" short_description=\"Binden Sie die Evaluationssoftware evasys der Firma evasys GmbH in Stud.IP ein mit umfangreichen Administrationstools.\" description=\"### Stud.IP-evasys-Schnittstelle&#10;&#10;Mit diesem Plugin kann man das eigene Stud.IP mit der professionellen Evaluationssoftware evasys verknüpfen. Man braucht dazu natürlich ein existierendes evasys und einen angelegten Nutzer der dortigen SOAP-Schnittstelle.  &#10;  &#10;Funktionsumfang&#10;&#10;- Import der Fragebögen aus evasys in Stud.IP&#10;- Zuweisen von Evaluationsprofilen zu Veranstaltungen in Stud.IP&#10;- Eine Dabei werden Standardfragebögen und Standardbefragungszeiträume gesetzt: Global, pro Fakultät und pro Institut in Stud.IP. Mit diesen Standardwerten reicht es meist, bei der Veranstaltung zu definieren, dass sie evaluiert werden soll, und alle Werte sind schon vorab korrekt gesetzt.&#10;- Feingranulare Einstellungen pro Veranstaltung möglich.&#10;- Massenbearbeitungsfunktionen mehrerer Veranstaltungen.&#10;- Optional können Lehrende sich auch freiwillig evaluieren lassen.&#10;- Transfer der Veranstaltungen nach evasys.&#10;- Die Befragung selbst wird in der Veranstaltung von Stud.IP angezeigt. Die Befragung ist ein anonymes TAN-Verfahren.&#10;- Anzeige von QR-Codes zu den Befragungen&#10;- Benachrichtigung an die Studierenden über neue Befragungen&#10;- Reports an die Lehrenden und optional Freigabe der Reports auch an die Studierenden&#10;- Feedback-Widget für die Startseite der Lehrenden über die Rückläufer&#10;&#10;  &#10;Und noch weitere Features. Die Schnittstelle ist so ausgelegt, dass man sehr viel einstellen kann. Das Plugin ist kostenlos und wird von der Community weiterentwickelt. Um das Plugin einzusetzen und zu verstehen, raten wir wegen den vielfachen Einstellmöglichkeiten zu einer Schulung bei der Firma data-quest GmbH.&#10;&#10; &#10;&#10;Changelog der letzten Versionen&#10;===============================&#10;&#10;Version 4.12.7:  &#10;- Automatischer Teilnehmersync soll keine Papierbefragungen behandeln: https://github.com/data-quest/EvasysPlugin/issues/21  &#10;- Befragungsart in CSV-Export bei freiwilliger/individueller Evaluation hinzufügen: https://github.com/data-quest/EvasysPlugin/issues/20  &#10;- Der abendlich Sync soll auch Veranstaltungen löschen: https://github.com/data-quest/EvasysPlugin/issues/19  &#10;- Info an Lehrende soll auch Admins in der Veranstaltung angezeigt werden: https://github.com/data-quest/EvasysPlugin/issues/17  &#10;- Nachricht über neue Evaluationen an Studierende: https://github.com/data-quest/EvasysPlugin/issues/15  &#10;- Datepicker absichern: https://github.com/data-quest/EvasysPlugin/issues/14  &#10;- Neue Filter &amp;quot;Fragebogenkurzname&amp;quot;, &amp;quot;Evaluationsart (online, Papier&amp;quot; und &amp;quot;Evaluationszeitraum (Hauptphase ja/nein)&amp;quot;: https://github.com/data-quest/EvasysPlugin/issues/13  &#10;- Evaluationsergebnisse erst x Tage nach Evaluationsende anzeigen: https://github.com/data-quest/EvasysPlugin/issues/12  &#10;- Bei Papierevaluationen soll eingestellt werden, ob Deckblatt oder Selbstdruckverfahren genutzt wird: https://github.com/data-quest/EvasysPlugin/issues/11  &#10;- messagebox_warning statt error: https://github.com/data-quest/EvasysPlugin/issues/10  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/10 Übersetzung des Plugins: https://github.com/data-quest/EvasysPlugin/pull/9  &#10;  &#10;Version 4.16.1:  &#10;- Massenbearbeiten: Beginn wird mit bearbeitet, wenn man das Ende bearbeiten will: https://github.com/data-quest/EvasysPlugin/issues/37  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/37 &amp;quot;Wird auf dem Fregebogen genannt&amp;quot; optional nicht anzeigen: https://github.com/data-quest/EvasysPlugin/issues/36  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/36 Evasys-Plugin in Einrichtungen unterbinden: https://github.com/data-quest/EvasysPlugin/issues/35  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/35 Cannot pass parameter 5 by reference: https://github.com/data-quest/EvasysPlugin/issues/34  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/34 Nutzlosen Text entfernen: https://github.com/data-quest/EvasysPlugin/issues/33  &#10;- Berichte per EvaSys versenden: https://github.com/data-quest/EvasysPlugin/issues/31  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/31 Benachrichtigung an Studierende informiert auch über Papierevaluationen: https://github.com/data-quest/EvasysPlugin/issues/30  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/30 [feat] own socket-timeout for EvaSys Soap-Calls: https://github.com/data-quest/EvasysPlugin/issues/28  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/28 Meldung freiwilliger Evaluationen gibt den falschen Nutzer an: https://github.com/data-quest/EvasysPlugin/issues/26  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/26 Nachricht über neue Evaluation übersetzbar und anpassbar machen: https://github.com/data-quest/EvasysPlugin/issues/25  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/25 Veranstaltungstyp auf 50 Zeichen begrenzen: https://github.com/data-quest/EvasysPlugin/issues/23  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/23 Folgen des Links per Mail führt dazu, dass Evaluationsdaten verändert werden: https://github.com/data-quest/EvasysPlugin/issues/22  &#10;  &#10;Version 5.0:  &#10;  &#10;- Reports in verschiedenen Sprachen anbieten: https://github.com/data-quest/EvasysPlugin/issues/16  &#10;- Bugfix: Evasys-Reiter taucht auf, obwohl er nicht da sein sollte: https://github.com/data-quest/EvasysPlugin/issues/38  &#10;- Sperren von Veranstaltungen nach Transfer: https://github.com/data-quest/EvasysPlugin/issues/39  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/39 Filtern auf Veränderungen nach dem Transfer: https://github.com/data-quest/EvasysPlugin/issues/40  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/40 Evaluationsende und Beginn in Nachrichten an Studierende: https://github.com/data-quest/EvasysPlugin/issues/41  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/41 Ergebnisse am Ende des Semesters löschen: https://github.com/data-quest/EvasysPlugin/issues/42  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/42 Art der Evaluation in Modus umbenennen und höher platzieren: https://github.com/data-quest/EvasysPlugin/issues/43  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/43Bugfix: Bei mehrsemestrigen Veranstaltungen landen die Befragungen im falschen Semester: https://github.com/data-quest/EvasysPlugin/issues/44  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/44 Hinzufügen von Mails zu mehreren Eval-Profilen: https://github.com/data-quest/EvasysPlugin/issues/45  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/45 Suche in den Soap-Logs: https://github.com/data-quest/EvasysPlugin/issues/46  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/46 Logs im Evaluationsprofil soll erweitert werden: https://github.com/data-quest/EvasysPlugin/issues/47  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/47 Trace aussschalten bei SOAP-Aufrufen: https://github.com/data-quest/EvasysPlugin/issues/48  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/48Bugfix: Größe der Logeinträge begrenzen: https://github.com/data-quest/EvasysPlugin/issues/49  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/49Bugfix: Abfragen der Fragebögen geht nicht mehr: https://github.com/data-quest/EvasysPlugin/issues/50  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/50Bugfix: Weitere Datenfelder / CustomFields enthalten nur Array: https://github.com/data-quest/EvasysPlugin/issues/51  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/51 Übersicht individueller Evaluationen verschieben: https://github.com/data-quest/EvasysPlugin/issues/52  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/52 Eingabe individueller Evaluationen erleichtern: https://github.com/data-quest/EvasysPlugin/issues/53  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/53Bugfix: Nach dem Übertragen werden Reports versendet: https://github.com/data-quest/EvasysPlugin/issues/54  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/54 Evaluationsreiter optimieren: https://github.com/data-quest/EvasysPlugin/issues/55  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/55 Studienbereiche per Beschreibungstext übertragen: https://github.com/data-quest/EvasysPlugin/issues/57  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/57 Editor für Texte der Systemmails: https://github.com/data-quest/EvasysPlugin/issues/58  &#10;- : https://github.com/data-quest/EvasysPlugin/issues/58 Rebranding evasys: https://github.com/data-quest/EvasysPlugin/issues/59  &#10;- Bugfix: Angaben bei CustomFields eventuell in der falschen Reihenfolge: https://github.com/data-quest/EvasysPlugin/issues/61  &#10; &#10;&#10;Version 5.1.6&#10;&#10;- Reports in verschiedenen Sprachen: https://github.com/data-quest/EvasysPlugin/issues/16&#10;- Bugfix: Daten der Evaluation haben falschen Hinweistext: https://github.com/data-quest/EvasysPlugin/issues/63&#10;- Bei den Standardwerten sollen im Maileditor zwei weitere Mails bearbeitet werden: https://github.com/data-quest/EvasysPlugin/issues/64&#10;- Bugfix: Fehlender Einsatz der Begrifflichkeiten: https://github.com/data-quest/EvasysPlugin/issues/65&#10;- Bugfix: Class &amp;#039;Modules&amp;#039; not found: https://github.com/data-quest/EvasysPlugin/issues/66&#10;- Bugfix: Reihenfolge der Nachrichteneinstellungen ändern: https://github.com/data-quest/EvasysPlugin/issues/67&#10;- Bugfix: Massenbearbeitung des Befragungsendes funktioniert nicht: https://github.com/data-quest/EvasysPlugin/issues/68&#10;- Bugfix: Platzhalter {{course}} fehlt in Nachricht an Studierende: https://github.com/data-quest/EvasysPlugin/issues/69&#10;- Infotext für Studierende soll für Lehrende und Admins besonders gekennzeichnet sein: https://github.com/data-quest/EvasysPlugin/issues/70&#10;- Pflichtevaluation kann in individuelle Evaluation umgewandelt werden: https://github.com/data-quest/EvasysPlugin/issues/71&#10;- Tutor:innen sollen auch nicht an Befragungen teilnehmen können (konfiguriert über EVASYS_PLUGIN_PARTICIPANT_ROLES): https://github.com/data-quest/EvasysPlugin/issues/72&#10;- Bugfix: Irreführenden Text anpassen: https://github.com/data-quest/EvasysPlugin/issues/73&#10;- Massenbearbeiten: Beim Ent-Beantragen sollen die durchführenden Lehrenden wieder gelöscht werden. (Vielleicht auch eher ein Bugfix): https://github.com/data-quest/EvasysPlugin/issues/74&#10;- Warnen, wenn vorgesehene Lehrende nicht mehr in Veranstaltung sind über ein weiteres Icon: https://github.com/data-quest/EvasysPlugin/issues/75&#10;- Bugfix: Icon auf der Seite zum Einstellen der Emailbenachrichtigungen ist falsch: https://github.com/data-quest/EvasysPlugin/issues/76&#10;&#10; &#10;&#10;Version 5.5.13:&#10;&#10;- Anzeigen wenn nach Transfer eine Veranstaltung ent-beantragt wurde: https://github.com/data-quest/EvasysPlugin/issues/98.&#10;- Lehrende sollen immer aktuelle Rückläufer der Befragung sehen: https://github.com/data-quest/EvasysPlugin/issues/97.&#10;- Upgrade zu Stud.IP 5.4: https://github.com/data-quest/EvasysPlugin/issues/85.&#10;- Bugfix: Admins können Veranstaltungen nicht administrieren: https://github.com/data-quest/EvasysPlugin/issues/102.&#10;- Bugfix: Missing Template: https://github.com/data-quest/EvasysPlugin/issues/101.&#10;- Bugfix: Kleinere Probleme im Adminbereich: https://github.com/data-quest/EvasysPlugin/issues/100.&#10;- Bugfix: Dozenten können eventuell nicht beantragen: https://github.com/data-quest/EvasysPlugin/issues/96.&#10;- Bugfix: Bei unbegrenzten Veranstaltungen fehlt für Admins die Checkbox: https://github.com/data-quest/EvasysPlugin/issues/95.&#10;- Bugfix: Bei EVASYS_FORCE_ONLINE nur zusätzliche Felder ohne Papierbefragungen zeigen: https://github.com/data-quest/EvasysPlugin/issues/94.&#10;- Bugfix: Lehrende bekommen Fehler beim Beantragen: https://github.com/data-quest/EvasysPlugin/issues/93.&#10;- Bugfix: Filter auf beantragt und noch nicht übertragen wirft Fehler: https://github.com/data-quest/EvasysPlugin/issues/92.&#10;- Bugfix: Umstellen auf neue Semesterstruktur: https://github.com/data-quest/EvasysPlugin/issues/91.&#10;- Bugfix: Mehrere VA beantragen ignoriert EVASYS_FORCE_ONLINE: https://github.com/data-quest/EvasysPlugin/issues/90.&#10;- Bugfix: &amp;quot;Daten wurden gespeichert&amp;quot; taucht zu oft auf ab 5.4: https://github.com/data-quest/EvasysPlugin/issues/89.&#10;- Bugfix: Veranstaltung erscheint versteckt, obwohl sie das nicht ist: https://github.com/data-quest/EvasysPlugin/issues/88.&#10;- Bugfix: Für Lehrende den EVASYS_INDIVIDUAL_TIME_OFFSETS verbindlich (serverseitig) machen: https://github.com/data-quest/EvasysPlugin/issues/87.&#10;- Bugfix: Veranstaltungsreiter taucht für Studierende bei Papierbefragung auf: https://github.com/data-quest/EvasysPlugin/issues/86.&#10;- Bugfix: Diverse kleine Fehler: https://github.com/data-quest/EvasysPlugin/issues/84.&#10;- Bugfix: Versenden von Nachrichten läuft nicht durch: https://github.com/data-quest/EvasysPlugin/issues/83.&#10;- Bugfix: Standardfragebogen nicht ausgewählt: https://github.com/data-quest/EvasysPlugin/issues/82.&#10;- Bugfix: Verknüpfen eines Fragebogens mit Veranstaltung erzeugt Fehler: https://github.com/data-quest/EvasysPlugin/issues/81.&#10;- Bugfix: Beginn des Bearbeitungszeitraumes für Admins hat keinen Datepicker: https://github.com/data-quest/EvasysPlugin/issues/80.&#10;- Bugfix: Dozierende sehen Fehlermeldung statt Evaluationsdaten: https://github.com/data-quest/EvasysPlugin/issues/79.&#10;- Bugfix: Bearbeiten des neuen Semesters geht erst ab Semesteranfang: https://github.com/data-quest/EvasysPlugin/issues/78.&#10;- Bugfix: Reports in verschiedenen Sprachen verwendet falsche ID: https://github.com/data-quest/EvasysPlugin/issues/77.&#10;- Bugfix: Zurückgezogene Beantragungen werden für Lehrende falsch dargestellt: https://github.com/data-quest/EvasysPlugin/issues/99.&#10;&#10;  &#10;Vielen Dank an alle, die mitgearbeitet haben!\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/23d935ae6ff4c8b1e0ef984aadd8f657\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/85cee75aa3ebff643d37e0be06cde6bf\">\n    <release version=\"5.5.13\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/50f37c8cf9b24b4fb98baa3bddf4f1aa\"/>\n    <release version=\"5.1.6\" studipMinVersion=\"4.2\" studipMaxVersion=\"5.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b070ed3aa5e2b195480fc056ff32053f\"/>\n    <release version=\"5.0\" studipMinVersion=\"4.2\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b4f0d3b9993e2483842466037de0910c\"/>\n    <release version=\"4.16.1\" studipMinVersion=\"4.0\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/054ea240e1cef845e5883a02d1462194\"/>\n    <release version=\"4.12.7\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/d314e75a0d1228f7a