\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/de241ad39e3c5892fe3ac637f65e5d11\"/>\n    <release version=\"2.4\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2f5bc45e9583a3459ee3ff83f5ebf202\"/>\n    <release version=\"2.20\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/14fc31f7555fb79cff7565d9c22315f9\"/>\n    <release version=\"2.17\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8060ad323028203908796b3a833b5c8f\"/>\n    <release version=\"2.16\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/492ee5bb3601f77385bf806bfe1a95fe\"/>\n    <release version=\"2.10\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/af90beac7450054f7b71d96ecbeedae0\"/>\n    <release version=\"2.1\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/7cf3123f2d362a7aaab640ff8c415994\"/>\n    <release version=\"1.5.5\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.3\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/1d39779646fe5ec499e1b95448cd64f3\"/>\n    <release version=\"1.5.2\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.2\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b149c5f7c7897fff6704c618909bfc01\"/>\n    <release version=\"1.2.2\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fa12d9ab14f324d0eaa316c9a87ddb57\"/>\n    <release version=\"1.1.6_v23\" studipMinVersion=\"2.3\" studipMaxVersion=\"2.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/73c71cbbaca26dd4e2f1bd73e0bb4b5c\"/>\n  </plugin>\n  <plugin displayname=\"MeinCSS\" name=\"CustomCSS\" homepage=\"https://github.com/Krassmus/CustomCSS\" short_description=\"Mit dem Plugin können Nutzer das CSS für Stud.IP anpassen und sich gegenseitig ihre Verbesserungen schicken.\" description=\"Über Einstellungen können die Nutzer eigenes CSS definieren, mit dem Stud.IP etwas anders aussieht. So können Sie sich Stud.IP selbst modden, wenn sie möchten. Zudem besteht eine einfache Möglichkeit, das verändernde CSS zu blubbern und andere Nutzer können so auch davon profitieren.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/21837dc39c7fd5a2c79b866b730c1aca\">\n    <release version=\"0.6\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/d9178400417663954667f1eee97bbf54\"/>\n    <release version=\"0.4\" studipMinVersion=\"3.0.99\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c04a1b58c66f6d71908a4718b14af78b\"/>\n  </plugin>\n  <plugin displayname=\"Meldung einer Barriere innerhalb Stud.IP\" name=\"Barrierefreies Formular\" homepage=\"\" short_description=\"Meldung einer Barriere innerhalb Stud.IP\" description=\"**Hinweis: Ab Stud.IP 5.3 ist diese Funktion Bestandteil des Kernsystems, dieses Plugin ist dann obsolet!**&#10;&#10;Dieses Plugin erzeugt eine Seite &amp;quot;Barriere melden&amp;quot; mit einem Formular, über das sich eine Barriere für Nutzende melden lässt, die auf Hilfsmittel wie Screenreader oder Ähnliches angewiesen sind. Die Seite ist im Footer verlinkt, damit von überall im System darauf zugegriffen werden kann.  &#10;  &#10;Barrieren sind beispielsweise nicht lesbare PDFs oder Probleme mit der Navigation. Die Empfänger-E-Mailadressen können im Adminbereich konfiguriert werden.  &#10;  &#10;Zusätzlich wird eine vorgefertigte Seite &amp;quot;Erklärung zur Barrierefreiheit&amp;quot; mit Platzhaltern angelegt. Alternativ kann eine bereits bestehende Seite zur Barrierefreiheitserklärung verlinkt werden.  &#10;  &#10;Im Adminbereich wird unter &amp;quot;Standort&amp;quot; der Menüpunkt &amp;quot;Barrierefreiheit&amp;quot; hinzugefügt. Als Empfänger der über das Formular gemeldeten Barriere wird zunächst die Kontaktadresse **[UNI_CONTACT]** eingetragen, es lassen sich aber mehrere Empfänger-E-Mailadressen hinzufügen und wieder entfernen. **Es ist allerdings darauf zu achten, dass mindestens eine gültige E-Mailadresse hinterlegt wird, da die Zustellung der gemeldeten Barriere sonst nicht gewährleistet werden kann!**  &#10;  &#10;**Update v1.2:**  &#10;**Die Barrierefreiheitserklärung wurde aktualisiert.**  &#10;  &#10;**Update v1.3:**  &#10;**Im Formular sind die Überschriften nun korrekt ausgezeichnet.**  &#10;  &#10;**Update v1.5:**  &#10;**Englische Übersetzung implementiert**  &#10;  &#10;**Update v1.6:**  &#10;**Anpassungen an der HTML-Struktur; Autocomplete eingebaut**\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/70cde5cb54813916516e6a78956481f7\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/f102d160e0fd55b5658d207851cbc6e2\">\n    <release version=\"1.6\" studipMinVersion=\"4.4\" studipMaxVersion=\"5.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e53b49f66d7f3204d489799dea6b2024\"/>\n    <release version=\"1.5\" studipMinVersion=\"4.4\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/02e9fae56b7e39b51a77b48c1319c355\"/>\n    <release version=\"1.3\" studipMinVersion=\"4.4\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/63230771638d3c0730597d2bf129845f\"/>\n    <release version=\"1.2\" studipMinVersion=\"4.4\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/50a6efb8859a7c4a3d5e131ac52c83e6\"/>\n    <release version=\"1.1\" studipMinVersion=\"4.4\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/432a67bb3c07d9d029e0f7527bb5d1f6\"/>\n    <release version=\"1.0\" studipMinVersion=\"4.5\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a9ccfd84a1b958d02f990765a16198f5\"/>\n  </plugin>\n  <plugin displayname=\"Memcache-Plugin\" name=\"MemcachePlugin\" homepage=\"\" short_description=\"Cache-Erweiterung, um memcached nutzen zu können\" description=\"Cache-Erweiterung, um memcached nutzen zu können\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/5c3b6e43090d96816ed6bb69864cf9f3\">\n    <release version=\"2.0\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/07e750834c87271d59d213e2fd3e5c8b\"/>\n  </plugin>\n  <plugin displayname=\"MemcachedPlugin\" name=\"MemcachedPlugin\" homepage=\"\" short_description=\"Cache-Plugin für das memcached PHP-Modul\" description=\"Dieses Cache-Plugin verwendet das memcached-PHP-Modul zur Speicherung: http://pecl.php.net/package/memcached.  &#10;  &#10; Achtung: Es verwendet ausschließlich das memcache**d**-Modul und nicht das memcache-Modul.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/c511a822c4ab899e2a6d0b0ec3c05c67\">\n    <release version=\"1.4.2\" studipMinVersion=\"2.4\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ce0a6e8fa996905e7c77604620725ddb\"/>\n    <release version=\"1.4.1\" studipMinVersion=\"2.4\" studipMaxVersion=\"4.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4a2b92ce7755ba3361f56772716d169e\"/>\n    <release version=\"1.4\" studipMinVersion=\"2.4\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/cd6b811405fba75bbd317d741324f77b\"/>\n    <release version=\"1.2\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fee6055e419363f50f8cd0577870643a\"/>\n  </plugin>\n  <plugin displayname=\"MergeStudyCourses\" name=\"MergeStudycourses\" homepage=\"\" short_description=\"Dieses Plugin ermöglicht es, verschiedene Studiengänge zusammenzuführen. Macht Sinn, wenn aus Versehen ein Studiengang doppelt angelegt wurde, oder aber beim Umstieg von 1.x auf 2.0 wenn man die verschiedenen Studiengänge X (Bachelor), X (Master) etc. zusammenführen möchte.\" description=\"Hierzu müssen lediglich zwei Studiengänge ausgewählt werden.&#10;&#10; Man muss festlegen, welcher beibehalten werden soll, der andere wird gelöscht und alle DB-Einträge auf eben diesen Studiengang umgetragen.&#10;&#10; Zugleich kann dem Studiengang ein Abschluss zugewiesen werden und er auch gleich umbenannt werden. &#10;&#10; Aus den Studiengängen Musik (BA) und Musik (MA) wird dann das Studienfach Musik. Auf Wunsch können alle Studierende dieser beiden Studiengänge dann bspw. auf Bachelor gebucht werden (man muss dann natürlich noch eine Nachricht schalten, dass die Studierenden die Studiengänge prüfen müssen)&#10;&#10;  &#10;&#10;**Das Plugin wurde für die 2.0 entwickelt. Es wurde nicht eingesetzt, da aufgrund der fehlenden Zulassungsbeschränkungen nach wie vor BA- und MA-Studiengänge doppelt gehalten werden. Für Fragen stehe ich gerne zur Verfügung, vor einem Einsatz muss dieses Plugin aber auf jeden Fall getestet werden.**\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/443921dad38d26e1bbab949606c007ba\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/0e3a65dc149da4a2df38be945f26d65f\">\n    <release version=\"0.5\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/97ac66406c6fb3091f220e451fa33f61\"/>\n  </plugin>\n  <plugin displayname=\"MessagesWidget\" name=\"MessagesWidget\" homepage=\"\" short_description=\"Mit diesem Widget werden Ihnen Ihre drei neusten Nachrichten auf der Startseite angezeigt.\" description=\"\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/f8ff1b4fdcd62620109f2a524086da1a\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/0d184ab6e9f69a81108ed673d4e46b3d\">\n    <release version=\"1.0.1\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fe0b63630e26d4c5d50bdbd53886759f\"/>\n    <release version=\"1.0\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/15325f24f3cefd40838ffcdb062853eb\"/>\n  </plugin>\n  <plugin displayname=\"Mitarbeiter Import Tool\" name=\"InstitutesMemberTool\" homepage=\"\" short_description=\"Mit dem Mitarbeiter Tool können gesammelt Berechtigungen an Einrichtungen vergeben werden. Man importiert eine Liste von Nutzern anhand von user_id,username oder TEILNEHMER_IMPORT_DATAFIELDS und gibt für jeden Nutzer zusätzlich an welche Rolle er an welcher Einrichtung bekommen soll. Die Einrichtung kann als Name oder institut_id angegeben werden. Beim Import wird der Nutzer bei Bedarf auch global in eine passende Rolle befördert (globale Degradierungen sind nicht möglich).\" description=\"\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/f62e4790bb3bb63b0327c1792ae0a204\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/31c36e0f2377b7a52e15c3b4ab56c110\">\n    <release version=\"1\" studipMinVersion=\"2.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/08732c1548a9a382651b3ba2eb23fcf5\"/>\n  </plugin>\n  <plugin displayname=\"Mitfahrzentrale\" name=\"Mitfahrzentrale\" homepage=\"https://www.bessermitfahren.de\" short_description=\"Einfache und schnelle Suche nach Mitfahrgelegenheiten.\" description=\"Nachdem mitfahrgelegenheit.de und mitfahrzentrale.de nicht mehr existieren und Blablacar kostenpflichtig geworden ist, gibt es nun hier die Lösung:  &#10;  &#10; Mit diesem Plugin wollen wir ein deutschlandweites Netzwerk für Mitfahrgelegenheiten aufbauen.  &#10; Ohne Anmeldung &amp;amp; Buchungssystem direkt Kontakt zu den FahrerInnen aufnehmen.  &#10;  &#10; Es werden keine Daten gesammelt!  &#10;  &#10; Neue Fahrten können schnell und einfach ohne Registrierung erstellt und über das Plugin gesucht werden.  &#10;  &#10; Changelog  &#10;  &#10; 1.3 (4. November 2018)&#10;&#10;- an Stud.IP v4 angepasst&#10;&#10; 1.2 (26. Oktober 2016) - externe JS Datei durch direkte API-Anbindung ersetzt&#10;&#10; 1.1 (19. Oktober 2016) - aktive Navigation hervorheben&#10;- Quellcode optimiert&#10;&#10; 1.0 (18. Oktober 2016) - 1. Version mit Suchformular und Schnellnavigation\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/81e66d8f60fc30dd22ac2fc99ddf8db3\" score=\"8.9999997078951\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/0e04f1c4672c684fed8a6d3e77fc54b5\">\n    <release version=\"1.3\" studipMinVersion=\"\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/15ff29e915a19bb86689f21709c010ad\"/>\n    <release version=\"1.2\" studipMinVersion=\"\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/d06686125fd0f48e13257635e821824d\"/>\n    <release version=\"1.1\" studipMinVersion=\"\" studipMaxVersion=\"3.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2d69f92e13cb7f8cb4b0bada0afaef76\"/>\n  </plugin>\n  <plugin displayname=\"Mooc.IP - OpenCourses\" name=\"Mooc.IP\" homepage=\"http://moocip.de/\" short_description=\"OpenCourses-Teil von Mooc.IP\" description=\"Mooc.IP OpenCourses erweitert Stud.IP um den externen Zugriff von Nutzern auf MOOC-artige Veranstaltungen. Diese können sich über eine spezifische Portalseite einen Überblick über die angebotenen Kurse verschaffen und sich dann direkt für einen solchen Kurs registrieren. Außerdem wird eine angepasste Überssichtsseite für Veranstaltungen mitgeliefert, die es unter anderem erlaubt, bequem ein Vorschauvideo einzubinden. Unterstüzt werden dabei MP4-Videos, YouTube- und Opencast-Links. Die Autorenumgebung zur Gestaltung und Präsentation von Mooc-artigen Inhalten ist ab dieser Version ausgelagert in ein separates Plugin: Mooc.IP Courseware Massive Open Online Courses sind nun schon lange in aller Munde. Neben den großen Plattformen stehen viele weitere Intiativen bereit, MOOCs, SPOCs, DOCCs, MOF2FOCs usw. unters Volk zu bringen. Gemeinsam ist vielen dieser Bemühungen eine Darstellungsweise, die Inhalte a) einfach zugänglich macht und b) den Content auf eine bestimmte Art und Weise in den Vordergrund stellt. Diese Darstellungsweise nenne ich “MOOC-Anmutung”. Mit Stud.IP sind offene Kurse in MOOC-Anmutung bislang nicht zu realisieren. Natürlich ist – wie immer bei Stud.IP – alles schon lange irgendwie vorhanden, aber eben nicht in der Weise miteinander verknüpft, wie die Nutzer das in diesem Fall erwarten. Aus verschiedenen Anlässen heraus sind wir der Auffassung, dass Stud.IP die Möglichkeit brauchen kann, offene, MOOC-artige Kurse anzubieten. Wir sind der Auffassung, dass es für Hochschulen und andere Stud.IP-Betreiber ein wichtiger Mehrwert sein kann, MOOC-artige Angebote und reguläre Angebote in einer Plattform miteinander zu verknüpfen. Der Einsatz von spezifischer MOOC-Software wie der Open-Source-edX-Plattform bietet diese Möglichkeiten nicht. Mooc.IP OpenCourses bietet: - eine frei gestaltbare Portalseite sowie eine spezifische Portalseite für Kurse - die Möglichkeit, sich direkt für einen solchen Kurs anzumelden und zu registrieren - angepasste Übersichtsseite in Veranstaltungen mit Vorschauvideo oder -bild, Angabe von Startdatum, Dauer und weiteren Hinweisen - MOOC-artige Kurse mit regulären Veranstaltungen in einem Stud.IP zusammen sicher und übersichtlich handhaben können Mooc.IP OpenCourses kann nicht: - Szenarien mit sehr vielen Nutzer (“Massive”) unterstützen\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/6b54539039323b8ca76ede83002cf684\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/0d6f6890e362733811914923e212d9ca\">\n    <release version=\"2.0.1\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/d6a181f357f6f9b1ffb1d6b1f7a63e8e\"/>\n  </plugin>\n  <plugin displayname=\"Moodle-Connect\" name=\"MoodleConnect\" homepage=\"https://github.com/elan-ev/studip-moodle-connect\" short_description=\"Stud.IP Kurs mit Moodle Kurs verknüpfen\" description=\"Um den Konnektor zu verwenden, müssen einige Einstellungen in Moodle vorgenommen und der Konnektor in Stud.IP konfiguriert werden. Detaillierte Informationen finden Sie unter: https://github.com/elan-ev/studip-moodle-connect#readme\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/2168ec86129f1d2b99b0ca261828d310\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/2f80dcdff2e418067af5e2119828435d\">\n    <release version=\"1.0.0\" studipMinVersion=\"4.2\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b26ab89c6b4eac3e087b260f3c3d918a\"/>\n    <release version=\"0.2.2\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ff0e25d2724943b715fd5e385ff019aa\"/>\n  </plugin>\n  <plugin displayname=\"MoveMe - Aktionen Teilnehmerverwaltung\" name=\"MoveMe\" homepage=\"https://develop.intelec.uni-passau.de/gitlab/stud-ip-plugins/moveme.git\" short_description=\"Neue Aktionen zur Teilnahmeliste von Veranstaltungen hinzu\" description=\"Dieses Plugin fügt neue Aktionen zur Teilnahmeliste von Veranstaltungen hinzu: - Verschieben/kopieren in andere Veranstaltung Falls es eine Warteliste gibt und automatisches Nachrücken abgeschaltet ist: - An den Anfang der Warteliste verschieben - Ans Ende der Warteliste verschieben Pluginversion 1.1, falls es eine Warteliste gibt: - Neue Personen auf Warteliste eintragen\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/0d8e16a9d26a8a7bb698a9f829797590\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/a702f465f8be016b9e01ea7ef7295e98\">\n    <release version=\"1.2\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/39fb212a530e6505b15ace15c3af4ea9\"/>\n    <release version=\"1.0\" studipMinVersion=\"2.4\" studipMaxVersion=\"3.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f0ee63cc8297ed435b6ce5dce0cd158e\"/>\n  </plugin>\n  <plugin displayname=\"MultipleAccounts\" name=\"MultipleAccounts\" homepage=\"\" short_description=\"MultipleAccounts ist eine mächtige Accountverwaltung. Kurz beschrieben ermöglicht es das Plugin, dass ein Nutzer, der zentral authentifiziert wurde, mehrere Stud.IP-Accounts zur Verfügung hat und somit bequem z.B. zwischen Studenten-Rolle und Administratoren-Rolle für seine / ihre HiWi-Tätigkeit wechseln kann.\" description=\"****Hinweis für alle meine Plugins: Getestet bis Stud.IP 2.3.1, Support für künftige Versionen ungeklärt****&#10;&#10; Das Plugin verfügt über sämtliche Verwaltungswerkzeuge wie:&#10;&#10;- Suche und Übernahme eines Accounts per entsprechendem Verifikationscodes&#10;- Neuerstellung eines Accounts nach erstmaligem Einloggen per Wizzard&#10;- Beantragung von Dozenten- und Admin-Accounts für Angestellte&#10;- Weitergabe eines Accounts&#10;- Synchronisation von Accountdaten, damit Basis-Daten (wie bspw. E-Mail) nicht in allen unterschiedlichen Nutzerprofilen gepflegt werden müssen&#10;- Verschiedene Accountmodi wie Dummy oder Fremdverwaltet, um diese automatische Synchronisation bei Testaccounts zu vermeiden&#10;- Definition von Pflichtfeldern im Profil: Bspw. müssen Studierende zwingend ihre Matrikelnummer angeben&#10;- Löschroutine: Per Webservice wird eine Datenbanktabelle mit zentralen Nutzerkennungen gefüllt. Beim Löschen einer Nutzerkennung werden sämtliche damit verbundene Accounts entfernt und eine entsprechende Mail versendet&#10;- automatische Befüllung eines freien Benutzer-Datenfelds, um schnell eine Übersicht über weitere Accounts eines Nutzers erhalten zu können&#10;- Schnellwechsel zwischen verschiedenen Accounts per Javascript&#10;- Wahl eines Stud.IP-Accounts beim Login oder Login mit einem Standard-Account&#10;- (nicht fertig implementiert) Unterstützung für weitere Systeme außer Stud.IP möglich&#10;&#10;  &#10;&#10;**Installation**&#10;&#10; Im Plugin WebAuth befindet sich eine ausführliche Installationsanleitung, um das Plugin zusammen mit WebAuth (oder einer Dummy-WebAuth-Authentifizierung) zu testen und zu nutzen. Auch die nötigen Auth-Plugins sind darin enthalten.&#10;&#10; Andere zentrale Authentifizierungsmechanismen müssen im Prinzip nur das Auth-Plugin einrichten und die Funktion getUserUniqueId() in der ma_config.inc.php neu implementieren. Diese muss eben die Kennung des derzeit zentral eingeloggten Users zurückliefern (nicht die des Stud.IP-Accounts!). Beispiele: [nutzer001@uni-x](mailto:nutzer001@uni-x) , student00007&#10;&#10;  &#10;&#10;**Abhängigkeiten**&#10;&#10; StudipOutputHelper&#10;&#10; CachePlugin&#10;&#10; Optional: WebauthPlugin\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/2ad7ed6c73487aa10dd2a2f1675c9e0d\" score=\"2\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/be105162b4a4f0784493abf45eaec866\">\n    <release version=\"0.8.7\" studipMinVersion=\"2.3\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/36e476155df5c8bdb4ac7bfa310b711b\"/>\n  </plugin>\n  <plugin displayname=\"MUMIE-Task\" name=\"MUMIE Task\" homepage=\"https://github.com/integral-learning/StudIP-MumieTask\" short_description=\"Fügen Sie mit nur wenigen Klicks bewertete Aufgaben der MUMIE-Lernplattform ihren Veranstaltungen hinzu.\" description=\"MUMIE ist eine E-Learning-Plattform zum Lernen und Lehren von Mathematik und Informatik. Sie wurde ursprünglich entwickelt, um das praxisorientierte Unterrichten an der Schnittstelle zwischen Gymnasium und Universität zu verbessern. Die MUMIE zeichnet sich durch ihr hohes Maß an Flexibilität aus und kann unkompliziert in andere Lern- und Content-Management-Systeme eingebunden werden. MUMIE-Kurse und deren hochwertige Kursmaterialien können ganz nach Ihren Wünschen an Ihre pädagogischen Anforderungen angepasst werden. Sie bietet Lern- und Trainingsumgebungen und Wiki-artige soziale Netzwerke für virtuelle Tutorien und selbstorganisiertes Lernen und zur Verbesserung von kognitiven und metakognitiven Fähigkeiten. Leistungsstarke Autorenwerkzeuge ermöglichen die Erstellung von neuen Inhalten. Dies öffnet die Tür für neue, herausfordernde und effizientere pädagogische Szenarien.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/d953cfc63a04b8f3f18aabf5e4024df2\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/a2b1e5cc2e59b1924c03403a6f8c2148\">\n    <release version=\"1.5\" studipMinVersion=\"\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/9e93aee47998928fb7673aac9a9bb7ab\"/>\n    <release version=\"1.4\" studipMinVersion=\"\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/03f63ae7e531dca8192e912bd8c07b5c\"/>\n    <release version=\"1.3\" studipMinVersion=\"\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/dcd1a871579a5d7ef7b8f0a61b21b077\"/>\n    <release version=\"1.2\" studipMinVersion=\"\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a87fd681c6bfaa332145cbc7934361ff\"/>\n    <release version=\"1.1\" studipMinVersion=\"\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2790589d50bea507bc3ba62974ecb433\"/>\n  </plugin>\n  <plugin displayname=\"Murmeln\" name=\"Murmeln\" homepage=\"http://www.magierlehrling.de/\" short_description=\"\" description=\"\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/7526fdba1f80d5ae21fb0b730e5b701d\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/829994e92962c274de1212c425eb7170\">\n    <release version=\"2.2.3\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/92738a7926cdc0972f17dd0f1a8e0bbb\"/>\n    <release version=\"2.2.1\" studipMinVersion=\"2.5\" studipMaxVersion=\"3.2.9\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/856875650eec689a632585cb69dfe0be\"/>\n  </plugin>\n  <plugin displayname=\"MyCoursesWidget\" name=\"MyCoursesWidget\" homepage=\"\" short_description=\"Liste der aktuellen Lehrveranstaltungen eines Nutzers als Widget für die Startseite\" description=\"Dieses Widget zeigt eine Liste der aktuellen Lehrveranstaltungen eines Nutzers (wie sie auch unter &amp;quot;Meine Veranstaltungen&amp;quot; zu sehen sind) auf der Startseite an. Die Einstellungen für die Anzeige und Gruppierung werden von &amp;quot;Meine Veranstaltungen&amp;quot; übernommen und können vom Nutzer dort geändert werden.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/c15749b1d0370eefef99687815d54de7\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/ba1bf75e65b8911d56272140530544de\">\n    <release version=\"0.5.1\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2aae1784f6f41bc92ce252ba1ad76d8b\"/>\n    <release version=\"0.5\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/20f50edf81119ff349fe4e1b3aab7fa2\"/>\n    <release version=\"0.4\" studipMinVersion=\"3.4\" studipMaxVersion=\"4.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8d46b994d6c16e4f6b7a2211bc2edd20\"/>\n    <release version=\"0.3.2\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/14916f22e5db3689759dcbbf06a86d2b\"/>\n  </plugin>\n  <plugin displayname=\"MyCSS\" name=\"MyCSS\" homepage=\"https://github.com/Krassmus/MyCSS\" short_description=\"Ändern des Designs von Stud.IP zu Testzwecken\" description=\"Der Nachfolger von MeinCSS bzw. CustomCSS.&#10;&#10;- SCSS-Support anstelle von Less&#10;- Mehrere Designs sind parallel nutzbar&#10;- Auf jeder Seite gibt es eine Möglichkeit, zwischen den Designs in Echtzeit hin- und her zuwechseln.&#10;- Es gibt zudem einen Marktplatz, wo man Designs öffentlich bereitstellen kann bzw. von dem man Designs importieren kann.&#10;- Root-User können zudem Designs global für alle Nutzer anschalten.&#10;&#10;  &#10; Dies Plugin ist nicht geeignet, um ein Produktivsystem umzudesignen. Aber zu Testzwecken ist es super.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/2c48646cf8c63b7b60cb37af5d5f464b\">\n    <release version=\"1.0\" studipMinVersion=\"\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/adbef1d010abfef8f3a659087d09af11\"/>\n  </plugin>\n  <plugin displayname=\"MyPhotos\" name=\"MyPhoto\" homepage=\"\" short_description=\"Mit MyPhotos können sehr schnell Fotoalben angelegt werden. Jedes Album und jedes Foto kann individuell beschrieben werden. Mit der integrierten Kommentarfunktion werden Eindrücke ausgetauscht. Jedes Album kann separat sichtbar oder unsichtbar für andere geschaltet werden. Der Eigentümer eines Album entscheidet selbst, ob Kommentare zu einzelnen Fotos erlaubt sein sollen. Über die ZIP-Uploadfunktion werden Bildersammlungen bequem hochgeladen.\" description=\"Eine umfangreichere Online-Hilfe mit dem aktuellen Funktionsumfang ist hier: http://hilfe.studip.de/index.php/Basis/LokalePluginsMyPhotos?setstudiplocationid=uhb zu finden. Diese Version von MyPhoto ist zudem mit englischer Übersetzung ausgestattet.&#10;&#10;Beschreibung&#10;------------&#10;&#10; Mit MyPhotos können sehr schnell Fotoalben angelegt werden. Jedes Album und jedes Foto kann individuell beschrieben werden. Mit der integrierten Kommentarfunktion werden Eindrücke ausgetauscht. Jedes Album kann separat sichtbar oder unsichtbar für andere geschaltet werden. Der Eigentümer eines Album entscheidet selbst, ob Kommentare zu einzelnen Fotos erlaubt sein sollen. Über die ZIP-Uploadfunktion werden Bildersammlungen bequem hochgeladen. Über einen zentralen Konfigurationsschalter kann eine für einen Benutzer maximal zur Verfügung stehende Speichermenge für Fotos angegeben werden.&#10;&#10; Weitere Funktionen sind u.a.:&#10;&#10;- die Möglichkeit der Sortierung von Fotos in Alben per *Drag and Drop* mit der Maus.&#10;- einige Bedienelemente werden jetzt nur noch bei Bedarf dargestellt, wenn der Benutzer mit der Maus über einen entsprechenden Link fährt.&#10;- die Darstellung der für andere Benutzer veröffentlichten Alben auf der Homepage ist um die Funktion einer Diashow erweitert worden. Gestartet wird diese mit einer Mausbewegung über das Startbild eines Albums.&#10;- das Blättern in Alben ist jetzt komfortabel machbar.&#10;&#10; Die genannten Erweiterungen sollten mit allen modernen Browsern (Internet Explorer, Firefox, Opera, Netscape) funktionieren. Daneben gibt es umfangreiche Detailverbesserungen im Bereich Optik und Bedienung. Die Quotagrößen habe ich zudem wie folgt angepasst:&#10;&#10;- **5 MB** pro einzelne Datei&#10;- **40 MB** pro ZIP-Datei\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/fdb690c36fb8652f3b8293d8aae9e6df\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/36a9658d52def520e10a27ac22b4aed4\">\n    <release version=\"1.12\" studipMinVersion=\"2.0\" studipMaxVersion=\"2.0\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/df9430af5d3b46fbd3e3a80ceced2f2d\"/>\n  </plugin>\n  <plugin displayname=\"Nachrichten an Nutzergruppen\" name=\"InstGroupMessagesPlugin\" homepage=\"\" short_description=\"Ermöglicht das Verfassen von internen Nachrichten an Rechtegruppen in Einrichtungen (z.B. alle Dozenten von Einrichtung A,B und C). Mögliche Empfänger können vorher tabellarisch angezeigt werden und als csv Datei exportiert werden (z.B. für das Serienbrief Plugin).\" description=\"\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/e919b8977f86b0511bc38440e2ab4ce6\">\n    <release version=\"2\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/15d682cb3ef5b9014ab63dd337378808\"/>\n  </plugin>\n  <plugin displayname=\"Newsletter Verwaltung\" name=\"NewsletterPlugin\" homepage=\"\" short_description=\"Mit diesem Plugin können auf einfache Weise themenbasierte Newsletter innerhalb von Stud.IP erzeugt und von dort aus als Email versandt werden. Der Abonnent benötigt als angemeldeter Stud.IP Nutzer nur einen Klick, um sich an einem Newsletter anzumelden oder abzumelden. Newsletter können bequem in WYSIWYG-Art, mit Stud.IP-Formatierung oder als Plaintext erzeugt und versandt werden. Neu in Version 1.2: manuelles Hinzufügen weiterer Mailadressen von Personen, die nicht in Stud.IP registriert sind\" description=\"\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/7451eae2ce8161090f984241ec69f1b7\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/130fadd1710b334d2ed3082e815b9f76\">\n    <release version=\"1.4\" studipMinVersion=\"1.4\" studipMaxVersion=\"2.1\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a9f553c05bd756bea7fa491a6408b806\"/>\n  </plugin>\n  <plugin displayname=\"Newsletter-Plugin für Einrichtungen\" name=\"InstGroupNewsletterPlugin\" homepage=\"www.hs-rm.de\" short_description=\"Derzeit bieten nur Lehrveranstaltungen an die Teilnehmer oder Einrichtungen an seine Mitarbeitenden die Möglichkeit Rundmails zu verschicken. Mit dem Plugin ist es möglich zum einen Rundmails an alle, die der Einrichtung zugeordnet sind abzuschicken. Desweiteren verfügt es über eine Benutzersperre, damit nur bestimmte Benutzer der Einrichtung und Admins das Plugin benutzen können.\" description=\"***Hinweis:***&#10;&#10; Das Plugin baut auf dem InstGroupMessagesPlugin von André Noack auf. Es wurde um die Fähigkeit erweitert einer Einrichtungen auch von Dozenten in Einrichtungen genutzt zu werden.&#10;&#10;***Beschreibung:***&#10;&#10; Nur Lehrveranstaltungen bieten derzeit die Möglichkeit Informationen in Form von Nachrichten an die eingetragenen Teilnehmer zu verschicken. Innerhalb von Einrichtungen kann man nur an die Mitarbeiter Rundmails verschicken. Es war wünschenswert Newsletter an die Studierenden der Einrichtung zu verschicken. Dies sollte nicht nur von den Administratoren möglich sein, sondern es sollte auch NewsletterautorInnen aus den in der Einrichtung eingetragenen Dozenten, geben, die dann auch auf das Plugin zugreifen können.&#10;&#10; Ab der Version 0.3 werden die User (Studierende) im Eintrag mit ausgewiesen.&#10;&#10;![Startseite](?dispatch=download&amp;amp;file_id=d7a8fa1db42a68dd116dee68790d9909)&#10;&#10; Der User und die nicht eingetragenen AutorInnen sehen den Reiter *Newsletter an Nutzergruppen* nicht. NewsletterautorInnen sehen den Reiter und die Eingabemaske, aber nicht den Verweis *Hinzufügen von Newsletteroutoren*.&#10;&#10; Eingetragene Autoren sehen auch nur die Einrichtung in der Anzeige. Administratoren der Einrichtung sehen alle Einrichtungen, die sie betreuen und Root-Admins sehen alle Einrichtungen des Systems.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/8887c2ba5827133c9df08b283d2baaba\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/efa8a34d5f79d4062ccc525e8410e30d\">\n    <release version=\"0.3\" studipMinVersion=\"\\&amp;quot;1.6\\&amp;quot;\" studipMaxVersion=\"\\&amp;quot;1.10\\&amp;quot;\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/444c744758e9b3a9b8aedcb32853ee15\"/>\n  </plugin>\n  <plugin displayname=\"NextcloudPlugin\" name=\"NextcloudPlugin\" homepage=\"https://gitlab.studip.de/studip/plugins/NextcloudPlugin\" short_description=\"Mit diesem Plugin kann man ab der Stud.IP-Version 5.0 eine Nextcloud (oder OwnCloud) als persönlichen Dateibereich einbinden.\" description=\"Mit diesem Plugin kann man ab der Stud.IP-Version 5.0 eine Nextcloud (oder OwnCloud) als persönlichen Dateibereich einbinden und von und zu der Nextcloud Dateien nach oder von Stud.IP kopieren.&#10;&#10;Installation&#10;------------&#10;&#10;1. Das Plugin wird wie jedes gewöhnliche Stud.IP-Plugin installiert. Falls das OwnCloudPlugin im Stud.IP bereits installiert ist, wird dessen Konfiguration bei der Installation übernommen, sowohl die systemweite, als auch die persönliche. Bereits angebundene Nextcloud-Installationen können somit weiterhin mit Stud.IP genutzt werden, ohne dass sie neu in Stud.IP eingerichtet werden müssen.&#10;2. Für OAuth in der Nextcloud hinter einem Apache braucht man das mod_rewrite und mod_env Modul, das die Regel RewriteRule .* - [env=HTTP_AUTHORIZATION:%{HTTP:Authorization}] umsetzt. Wenn das nicht aktiv ist, kann OAuth nicht funktionieren, weil der Apache alle Authorization-Header entfernt.&#10;3. Es muss in Nextcloud ein Client angelegt werden: Dazu öffnet man „Verwaltungs-Einstellungen“ -&amp;gt; „Sicherheit“ und trägt unter „OAuth 2.0-Clients“ einen Client für Stud.IP ein. Im Feld „Weiterleitung“ trägt man die Redirect-URI ein, mit der das NextcloudPlugin das Zugriffstoken von Nextcloud erhält. Sie ist in der folgenden Form: https://meinstud.ip/plugins.php/nextcloudplugin/oauth/receive_access_token „meinstud.ip“ muss durch den Basispfad (oft die Domain) des Stud.IP ersetzt werden.&#10;4. Nachdem der OAuth2-Client in Nextcloud erstellt wurde, müssen das Client-Identifikationsmerkmal und das Geheimnis in Stud.IP eingetragen werden. Dafür gibt es zwei Möglichkeiten: Zentral (eine Nextcloud für das gesamte Stud.IP) oder individuell (jede Person bindet eine eigene Nextcloud an).&#10;&#10;Zentral:&#10;&#10;1. Melde Dich im Stud.IP als Root an und gehe unter Admin -&amp;gt; System -&amp;gt; Konfiguration -&amp;gt; Nextcloud.&#10;2. Trage das oben gewonnene Client-Identifikationsmerkmal in die Einstellung NEXTCLOUD_CLIENT_ID ein.&#10;3. Trage das oben gewonnene Geheimnis in die Einstellung NEXTCLOUD_CLIENT_SECRET ein.&#10;&#10;Individuell:&#10;&#10;1. Personen müssen alleine die obigen Schritte durchführen bzw. deren Nextcloud-Administration fragen, ob diese das für ihn tun kann und die Zugangsdaten zurücksenden kann.&#10;2. Im persönlichen Dateibereich von Stud.IP 5.0 gibt es in der Seitenleiste den Punkt &amp;quot;Nextcloud konfigurieren&amp;quot;. Dieser muss ausgewählt werden, um die Nextcloud zu konfigurieren.&#10;3. Im sich öffnenden Dialog muss die Adresse der Nextcloud eingetragen werden (z.B. https://meineuni/nextcloud). Bei App-ID wird das Client-Identifikationsmerkmal eingetragen, bei Secret das Geheimnis. Sobald der Haken bei „Aktiviert“ gesetzt wurde und auf „Speichern“ geklickt wurde, ist die Nextcloud mit Stud.IP verknüpft.&#10;&#10;Die nächsten Schritte sind für beide Wege wieder dieselben:&#10;&#10;1. Wer es individuell eingestellt hat, kennt es schon: Im persönlichen Dateibereich von Stud.IP 5.0 gibt es in der Sidebar den Punkt &amp;quot;Nextcloud konfigurieren&amp;quot;. Da muss man drauf klicken.&#10;2. Man muss das Häkchen für &amp;quot;aktiviert&amp;quot; setzen und speichern.&#10;3. Das Fenster lädt sich neu und ein Button erscheint oben &amp;quot;Nextcloud für Stud.IP freigeben&amp;quot;. Dort klicken.&#10;4. Dann landet man in der Nextcloud und wird aufgefordert sich anzumelden. Vergewissern Sie sich in solchen Situationen immer (nicht nur jetzt), dass die URL stimmt und Sie Ihre Passwörter nicht einer anderen Seite als genau Ihrer Nextcloud zusenden.&#10;5. Die Nextcloud fragt Sie, ob Stud.IP in Ihrem Namen Daten abrufen und verändern darf. Klicken Sie auf &amp;quot;Authorisieren&amp;quot;.&#10;6. Jetzt landen Sie wieder in Stud.IP und die Schnittstelle zwischen Stud.IP und Nextcloud sollte eingerichtet sein.&#10;&#10;Probleme?&#10;&#10;- Manchmal scheint fast alles zu funktionieren. OAuth-Access-Token ist da, Refresh-Token ist da und der Refresh scheint auch zu klappen, aber es werden keine Dateien und Ordner angezeigt. Es erscheint stattdessen eine Fehlermeldung: &amp;quot;No &amp;#039;Authorization: Basic&amp;#039; header found. Either the client didn&amp;#039;t send one, or the server is misconfigured, No &amp;#039;Authorization: Basic&amp;#039; header found. Either the client didn&amp;#039;t send one, or the server is misconfigured, No &amp;#039;Authorization: Bearer&amp;#039; header found. Either the client didn&amp;#039;t send one, or the server is mis-configured&amp;quot;. In dem Fall muss man vermutlich in die Datei .htaccess die Zeile einbauen SetEnvIf Authorization &amp;quot;(.*)&amp;quot; HTTP_AUTHORIZATION=$1\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/ae3c8228d691ca7786eb309dc96487dd\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/b4a36c23a78b418dc0109af23c550399\">\n    <release version=\"3.1.0\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/29893b6b4041ae505a4cf04d90f7bb20\"/>\n    <release version=\"3.0\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5bf72a160a2324f0111be5ea1794fdf8\"/>\n  </plugin>\n  <plugin displayname=\"NicePhrase\" name=\"Nice Phrase\" homepage=\"\" short_description=\"Ein Plugin, welches auf der Startseite zufällig gewählte nette Sprüche anzeigt.\" description=\"Wer bekommt nicht gerne Komplimente? Mit diesem Plugin wird eine kurze, zufällig gewählte freundliche Nachricht auf der Startseite angezeigt.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/7d5639df0e7e823daecb2b7e9a338b8c\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/dd48a7a293b2317476cc90511ec07b23\">\n    <release version=\"1.0\" studipMinVersion=\"3.3\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/837553438eb1aef7467dc3f703676742\"/>\n    <release version=\"1.0\" studipMinVersion=\"\" studipMaxVersion=\"3.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/dc9990981eef217b07eb783c4feca5e5\"/>\n  </plugin>\n  <plugin displayname=\"NoDetailsPlease\" name=\"NoDetailsPlease\" homepage=\"https://gitlab.data-quest.de/studip-plugins-oeffentlich/NoDetailsPlease\" short_description=\"Verstecken der Detailseite von Veranstaltungen für nobody\" description=\"Schon öfter ist es vorgekommen, dass Betreiber von Stud.IP erschrocken festgestellt haben, dass die Detailseite von Veranstaltungen öffentlich einsehbar ist. Das ist an sich nicht schlimm, aber an einigen Standorten ist das nicht gewünscht so.  &#10;  &#10;Dieses Plugin verbirgt die Detailsseite der Veranstaltungen für unangemeldete Nutzer wie Google, chinesische Bots oder accountlose Hasardeure. Man kann dennoch den Link zu der Detailseite an Freunde verschicken. Klickt ein*e unangemeldete*r Nutzer*in auf den Link, wird er/sie aufgefordert, sich anzumelden an Stud.IP, und danach kann man die Detailseite wieder sehen und sich zu der Veranstaltung anmelden.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/9f6ccf4a853c58067145ed1915409862\">\n    <release version=\"1.1\" studipMinVersion=\"\" studipMaxVersion=\"6.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/73060f1feaf2abe3b23e7018a25b83ea\"/>\n    <release version=\"1.0\" studipMinVersion=\"\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4931818c85d55ff48eea1a54ba438627\"/>\n  </plugin>\n  <plugin displayname=\"Notenspiegel\" name=\"Notenspiegel\" homepage=\"\" short_description=\"Baut auf die FszNotenVerwaltung auf und liefert Studierenden einen Notenspiegel.\" description=\"Zur Abfrage der persönlichen Noten, die mithilfe des Plugins FSZNotenverwaltung: https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/0e57d54dae39f8a3f22e724a13d099e0 gespeichert wurden, müssen Studierende in die jeweilige Lehrveranstaltung navigieren, für die sie ihre Note sehen wollen. Eine Auflistung aller Noten in Form eines Notenspiegels bietet die FszNotenVerwaltung nicht an.  &#10;**Dieses Plugin erweitert die FszNotenVerwaltung um einen Notenspiegel für Studierende, der direkt von der Startseite aufgerufen werden kann.  &#10;  &#10; Achtung: **Dieses Plugin kann nicht ohne das** **Plugin FSZNotenverwaltung: https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/0e57d54dae39f8a3f22e724a13d099e0 benutzt werden.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/875a5b2652447208367f231550d27ce8\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/a7bb724a92a7e59bbf651ce29949b294\">\n    <release version=\"1.0.1\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fc96701cd973ca95e2f0d00f23b304dc\"/>\n    <release version=\"1.0\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/7d2e73b5d52a9ddbfff55f95f6e8414e\"/>\n  </plugin>\n  <plugin displayname=\"Notenverwaltung\" name=\"FszNotenVerwaltungPlugin\" homepage=\"\" short_description=\"Ermöglicht die Eingabe von beliebig vielen Einzelnoten mit Gewichtung, Endnote wird berechnet, Teilnehmerliste mit Noten kann als Excel Tabelle exportiert werden.(im Plugin stecken weitere auskommentierte Funktionalitäten des Fachsprachenzentrums der LUH. D.h. spezielle vorgesehene Eingabefelder für Sprachniveau, bestanden ja/nein, Bescheinigung und ein spezielles Exportformat zum Erzeugen der Scheine)\" description=\"\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/69a9650f902000c20c762c2c1108ec48\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/0e57d54dae39f8a3f22e724a13d099e0\">\n    <release version=\"0.81\" studipMinVersion=\"4.0\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/450ecce36b680edc9162ae175c5ef5f3\"/>\n    <release version=\"0.73\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/be0884430e68bcedb06a9f7797a15acf\"/>\n    <release version=\"0.63\" studipMinVersion=\"3.3\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8d5031e99df4c432da04792834929325\"/>\n    <release version=\"0.49\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c1218518a06a84fafac7bfb7ba54d4eb\"/>\n    <release version=\"0.47\" studipMinVersion=\"2.2\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/d671306463ae0e56ac657c49e5af1d01\"/>\n  </plugin>\n  <plugin displayname=\"Notifications-Metriken\" name=\"Metrics4Notifications\" homepage=\"\" short_description=\"Mit diesem Plugin werden alle Notifications des NotificationCenters auch an installierte MetricsPlugins weitergeleitet.\" description=\"Werden im PHP-Code Notifications über das NotificationCenter verschickt, werden diese zusätzlich als Metriken an die MetricsPlugins wie das Statsd-Plugin: https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/7930e0c760b11ab34075efd27260e598 verschickt.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/fe826dde712963dbadeac4cabaf73eb3\">\n    <release version=\"1.1.1\" studipMinVersion=\"3.1\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ba615ef9b5c10c7a59b1e3fcef2d6a0e\"/>\n    <release version=\"1.1.0\" studipMinVersion=\"3.1\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/1e64731f60578c1bcf14f1ec50dae08b\"/>\n  </plugin>\n  <plugin displayname=\"Nutzer-Import\" name=\"UserImportPlugin\" homepage=\"https://gitlab.studip.de/studip/plugins/userimportplugin\" short_description=\"Ermöglicht den massenweisen Import von Nutzern aus einer csv Datei\" description=\"\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/69801b06c5a9472d0de6ad09dc8bff06\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/90f15512c46fdd3851cc7bdbec0a55fa\">\n    <release version=\"0.81\" studipMinVersion=\"4.0\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4be416e49e8e97aff21620851402057e\"/>\n    <release version=\"0.8\" studipMinVersion=\"4.0\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ccf5b3e5df886e43a32b8c63ff4e0daa\"/>\n    <release version=\"0.66\" studipMinVersion=\"4.0\" studipMaxVersion=\"5.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/7566b967febe21b0dff58f9f622e0fdf\"/>\n    <release version=\"0.65\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/cd9d288cbd67401ed108b396a11d4fde\"/>\n    <release version=\"0.51\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8d9410c01fccef59953d891f692026f6\"/>\n    <release version=\"0.41\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.1\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/25fa76f3ac20426604ee7770843417c1\"/>\n  </plugin>\n  <plugin displayname=\"Nutzerstatistik / UserStats\" name=\"UserStats\" homepage=\"\" short_description=\"Dieses Plugin bietet eine einfache Übersicht über die Historie der eingeloggten und insgesamt registrierten Nutzer.\" description=\"****Hinweis für alle meine Plugin: Getestet bis Stud.IP 2.3.1, Support für künftige Versionen ungeklärt****&#10;&#10; Das Plugin fängt selbstständig mit Datensammeln an, somit sind die Kurven initial relativ leer. Hat man selbst noch Daten über bspw. Nutzer online gespeichert, so können diese in die neue Tabelle userstat_online eingetragen werden.&#10;&#10;  &#10;&#10;**Installation:**&#10;&#10; 1. Für Stud.IP 2.2 oder kleiner ist eine kleine Änderung des Kerns nötig wie beim Plugin markItUp beschrieben: http://plugins.studip.de/?dispatch=show_plugin_details&amp;amp;plugin_id=872edb9f2703f9cb34778eb2e3ea9740&#10;&#10;  &#10;&#10; 2. Zur Installation des Plugins bitte die Datei  &#10; INSTALLATION/INSTALLATION  &#10; lesen\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/09ff19ef5b2437d77589a4bc7baee0ab\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/5067131fa201479eb9f846483e5f8d9b\">\n    <release version=\"1.0.2\" studipMinVersion=\"2.3\" studipMaxVersion=\"2.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/7584df9cd2290174a532b984fbd8d388\"/>\n    <release version=\"1.0.1\" studipMinVersion=\"2.3\" studipMaxVersion=\"2.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/603bf22105826a8bf54488c3b8acd2b4\"/>\n    <release version=\"0.9.9\" studipMinVersion=\"2.0\" studipMaxVersion=\"2.2.1\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c71d72f229ac830e43c21a913bd6866e\"/>\n  </plugin>\n  <plugin displayname=\"OERCampus\" name=\"LernMarktplatz\" homepage=\"https://github.com/Krassmus/LernMarktplatz/\" short_description=\"Ein kleiner Marktplatz für freie Lernmaterialien losgelöst von Veranstaltungen.\" description=\"**Der OER Campus ist seit Stud.IP 5.0 im Kern eingebaut und muss nicht mehr als Plugin installiert werden. Das Plugin in der letzten Version für Stud.IP 5.x dient lediglich dazu, dass die alten Links weiterhin funktionieren (falls man denn Inhalte irgendwo verlinkt hat).**  &#10;  &#10;  &#10; Und hier die alte Beschreibung des alten Lernmarktplatzes:  &#10;  &#10; Übungszettel, Musterlösungen, Vorlesungsskripte, Lernkarteikarten, Prüfungsprotokolle werden öfter mal im Studium erstellt und verschwinden dann meistens wieder in der Versenkung. Aber wäre es nicht schön, wenn man als Student oder Dozent in der Lage wäre, sich der alten Materialien zu bedienen, um sich auf Prüfungen oder Vorlesungen besser vorbereiten zu können, oder auch nur um einen Einblick davon zu bekommen, welche Themen/Module man in den kommenden Semestern gerne belegen möchte? Deshalb gibt es diesen Marktplatz für Lernmaterialien, auf den jeder Studierende und jeder Lehrende alle möglichen Materialien hochladen und damit mit allen teilen können.  &#10;  &#10; Im Hochschulkontext wird das meist als Repository für Open Educational Resources bezeichnet - kurz OER. Dieses Plugin kann man als OER-Marktplatz bezeichnen. Durchsuchbarkeit&#10;----------------&#10;&#10; Durchsuchbar werden die Materialien über die Themenwolke, bei der man sich von einem Thema zu den verwandten Themen durchhangeln kann. Diese Themenwolke muss nicht moderiert werden, sondern berechnet sich automatisch aus den Materialien, die schon hochgeladen sind, sodass die relevantesten Themen oben stehen und man sich so von Thema zu Unterthema durchklicken kann. Aber natürlich kann man auch einfach nach einem Text suchen. Austausch von Meinungen und Gedanken und Ideen&#10;----------------------------------------------&#10;&#10; Zu den bestehenden Lernmaterialien kann man Reviews verfassen, andere Leute können ein Review auch wieder kommentieren, damit man sich zu den einzelnen Materialien umfassend austauschen kann. !! Multimedia Videos und Bilder können sofort angezeigt werden, ohne dass man sie sich erst herunterladen muss. Damit ist der Marktplatz auch gleich eine Art YouTube für Vorlesungsmitschnitte und Begleitvideos. Von ZIP-Dateien wird die Datei- und Ordnerstruktur angezeigt, bevor man sich das ZIP runterladen muss, damit man gewissermaßen nicht die Katze im Sack downloaded. Föderation!&#10;-----------&#10;&#10; Manche Stud.IP-Instanz mag zu klein sein, um eine kritische Masse für den Lernmaterialienmarktplatz zu bekommen. Deshalb gibt es die Möglichkeit (aber nicht den Zwang), dass sich der eigene Marktplatz mit einem sogenannten Indexserver verbindet, um Lernmaterialien anderer Stud.IPs ebenfalls anzuzeigen. Für die Nutzer ändert sich nichts - für sie fühlt es sich an, als ob sie ihr Stud.IP nie verlassen würden. Aber auch Reviews von Materialien von fremden Stud.IPs werden übertragen, ebenso wie die Kommentare zu den Reviews. Das Ganze passiert natürlich in Echtzeit, sodass man das Gefühl bekommt, mit einem Nutzer eines anderen Stud.IPs blubbern zu können. Und das ist ja auch der Fall.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/da101eba76c0715f8eaf298a1416f6d5\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/0a0b32104d5c29cfa90d2699779642ad\">\n    <release version=\"5.0\" studipMinVersion=\"5.0\" studipMaxVersion=\"6.0\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c1e8ad88653d6449d884826308693848\"/>\n    <release version=\"4.8\" studipMinVersion=\"4.5.99\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/6d82781cdd3d6de59c99435ec852e454\"/>\n    <release version=\"4.7\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5753e285dc8f07ed394940e218fa4285\"/>\n    <release version=\"4.6.4\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/68a2e00951c943d44daebdf982c25152\"/>\n    <release version=\"4.5.2\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5b0a8c1315df4bdaf8407e2313bcce2b\"/>\n    <release version=\"4.3.1\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2999827f29e0c0179b19dd949dd7c5a7\"/>\n    <release version=\"4.0.3\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c991a85cb7b72b5fff398bd922c0444b\"/>\n    <release version=\"3.5.2\" studipMinVersion=\"3.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/82b4eb3b196b7ceaae808d24a999784b\"/>\n    <release version=\"1.0.2\" studipMinVersion=\"3.2\" studipMaxVersion=\"3.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5a935fa5e7a6d1c1711fbec0d29b8923\"/>\n  </plugin>\n  <plugin displayname=\"Opencast\" name=\"OpenCast\" homepage=\"https://elan-ev.github.io/studip-opencast-plugin/\" short_description=\"Mit dem Opencast-Plugin kann eine Verbindung zwischen einer Opencast-Installation und dem Lernmanagementsystem Stud.IP hergestellt werden\" description=\"Stud.IP-Opencast-Plugin&#10;-----------------------&#10;&#10;*Deprecated*&#10;------------&#10;&#10;Es gibt eine neue Version dieses Plugins hier: &#10;&#10;https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/bda1aed56c644d98cc9c5cc70cfc6fbc&#10;&#10;Diese Version wird nicht mehr aktiv weitergepflegt.&#10;&#10;  &#10;*This plugin serves as a connection between **Opencast*: http://opencast.org* and the LMS **Stud*: http://studip.de*.IP.*  &#10;  &#10;Alle Versionen und Änderungslisten sind zu finden unter:  &#10;https://github.com/elan-ev/studip-opencast-plugin/releases  &#10; &#10;&#10;**Nach jedem Update von Opencast oder dem Plugin unbedingt in den Opencast-Einstellungen auf &amp;quot;Übernehmen&amp;quot; klicken**!&#10;&#10;  &#10;**Beachten Sie die INSTALL.md, diese Pluginversion benötigt Konfigurationseinstellungen in Opencast!**&#10;&#10;Installationsanweisungen&#10;------------------------&#10;&#10; https://github.com/elan-ev/studip-opencast-plugin/blob/master-v2/INSTALL.md: https://github.com/elan-ev/studip-opencast-plugin/blob/master/INSTALL.md\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/f7ba259865743a29bf52a2c4f7ac6452\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/dfd73b3d67c627be493536c1ae0e27c9\">\n    <release version=\"2.9\" studipMinVersion=\"5