velop.studip.de/studip/plugins.php/pluginmarket/presenting/download/eca1b051f7ebbf0f16a091eb1274e06c\"/>\n    <release version=\"1.2.99\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/13fcbe9d7a874844a858522173503fa6\"/>\n    <release version=\"1.2.98\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/665e0b96fed6e44f2404be11f25d9071\"/>\n    <release version=\"1.2.161\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/676314b6605e938b1b7374e9cd561bdd\"/>\n    <release version=\"1.2.112\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a6a78d9f7161b321c411ed306a8df458\"/>\n    <release version=\"1.2.103\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/777d950923b3ee209de82df89a3c0875\"/>\n    <release version=\"1.14\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/41a44b694e1ecf4f543db8cce4fd4b59\"/>\n    <release version=\"1.12\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/0a30d020d7b6cb80a236114f4fc8e255\"/>\n    <release version=\"1.1.18\" studipMinVersion=\"3.5\" studipMaxVersion=\"4.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/3ab5a921bcaaed109a251e0ef1b0731e\"/>\n    <release version=\"1.1.16\" studipMinVersion=\"3.5\" studipMaxVersion=\"4.2\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a87f1ac065e0a1b5084ea7d3bf2b9862\"/>\n    <release version=\"1.1.13\" studipMinVersion=\"3.5\" studipMaxVersion=\"4.2\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/42932b61180cf51af0b2d70d0f2b7ab4\"/>\n    <release version=\"1.1.12\" studipMinVersion=\"3.5\" studipMaxVersion=\"4.2\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/288749f0b5221b16d97cddcbce3b453f\"/>\n  </plugin>\n  <plugin displayname=\"Opencast - V3\" name=\"OpencastV3\" homepage=\"https://github.com/elan-ev/studip-opencast-plugin\" short_description=\"Mit dem Opencast-Plugin kann eine Verbindung zwischen einer Opencast-Installation und dem Lernmanagementsystem Stud.IP hergestellt werden\" description=\"*This plugin serves as a connection between **Opencast*: http://opencast.org* and the LMS **Stud*: http://studip.de*.IP.*  &#10;*This is version 3 of the plugin and replaces the older version 2!*  &#10;  &#10;Alle Versionen und Änderungslisten sind zu finden unter:  &#10;https://github.com/elan-ev/studip-opencast-plugin/releases  &#10; &#10;&#10;**Nach jedem Update von Opencast oder dem Plugin unbedingt in den Opencast-Einstellungen auf &amp;quot;Übernehmen&amp;quot; klicken**!&#10;&#10;  &#10;**Beachten Sie die INSTALL.md, diese Pluginversion benötigt Konfigurationseinstellungen in Opencast!**  &#10;  &#10;Mit dem Opencast-Plugin kann eine Verbindung zwischen einer  &#10;Opencast-Installation und dem Lernmanagementsystem Stud.IP hergestellt werden.  &#10;Dies ermöglicht die Erstellung, Verwaltung und Veröffentlichung von  &#10;Vorlesungsaufzeichnungen direkt in Stud.IP.  &#10;  &#10;Der Fokus der Entwicklung liegt bei einer möglichst intuitiven und einfachen  &#10;Bedienung. Somit ist für dis Verwendung des Plugins kaum Vorwissen nötig.  &#10;Außerdem wurde sichergestellt, dass das Plugin folgende  &#10;Anforderungen erfüllt:  &#10;  &#10;*Transparenz der Aufzeichnungstechnik*: Die DozentInnen können in ihren  &#10;Veranstaltung direkt erkennen, ob der gebuchte Veranstaltungsraum mit  &#10;entsprechender Aufzeichnungstechnik ausgerüstet ist. Dies wird im Plugin durch  &#10;die Verknüpfung von Stud.IP-Ressourcen mit Aufzeichnungsgeräten in Opencast  &#10;sichergestellt. DozentInnen benötigen dafür kein technisches Vorwissen über  &#10;die verwendete Aufzeichnungstechnik.  &#10;  &#10;*Einfache Aufzeichnungsplanung*: Vorlesungsaufzeichnungen können direkt in dem  &#10;Stud.IP-Kurs von den DozentInnen geplant werden. Dabei werden im Kurs  &#10;verfügbare Metadaten bei der Planung berücksichtig. Möglich ist dies mit einer  &#10;eigenen Planungsansicht. Hiermit entfällt die mehrfache Eingabe von Metadaten.  &#10;  &#10;*Kontrolle der Sichtbarkeit*: Die DozentInnen können die Sichtbarkeit jeder  &#10;Aufzeichnung in Stud.IP individuell festlegen.&#10;&#10;Installationsanweisungen&#10;------------------------&#10;&#10; https://github.com/elan-ev/studip-opencast-plugin/blob/master/INSTALL.md: https://github.com/elan-ev/studip-opencast-plugin/blob/master/INSTALL.md\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/bda1aed56c644d98cc9c5cc70cfc6fbc\">\n    <release version=\"3.30\" studipMinVersion=\"5.3\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/16f7e6f22c94bb0347d7944f4b414333\"/>\n    <release version=\"3.29\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/d0b1fff55b9e7c352941d48268f87685\"/>\n    <release version=\"3.28\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b096a27b865e2d1b36b661e90b555018\"/>\n    <release version=\"3.27\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/09023bf8a03feb7aed203bb930857c7e\"/>\n    <release version=\"3.26\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fea93ac74d54d4d36adc9fa78e7fb3c5\"/>\n    <release version=\"3.25\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a8fc33e72c195e7835a25b078af5bcb1\"/>\n    <release version=\"3.24.1\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/d82b299ef877fa45ef49b4031b0732d5\"/>\n    <release version=\"3.24\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/41d11ed23a21755f9cfb6cc66121814c\"/>\n    <release version=\"3.23.2\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8a46986f3472e60e2a9c6cdb58156d05\"/>\n    <release version=\"3.23.1\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/030d53c12e0a010353a352f3759b5256\"/>\n    <release version=\"3.23\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/51f32799cf87444e56d2003d8e9fa2ca\"/>\n    <release version=\"3.22\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/71d2e65c65afe89d3e6e688846307bf3\"/>\n    <release version=\"3.21\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a334fb79cde82cf14c0bb6927dad25bf\"/>\n    <release version=\"3.20\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/11a3f3123a5366d754c47f0ac04a65d6\"/>\n    <release version=\"3.19\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/6e70afeaa9c36ce47c9093d90040cb8f\"/>\n    <release version=\"3.18\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/6d3a3ebc168b756db1e3d974ea4f7922\"/>\n    <release version=\"3.17.1\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/075c8eb8d3fb99c457d9ea6fef75f4cf\"/>\n    <release version=\"3.17\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a127710a71e40f65695ac6415576933c\"/>\n  </plugin>\n  <plugin displayname=\"OpenstreetmapEmbedder\" name=\"OpenstreetmapEmbedder\" homepage=\"\" short_description=\"Erweitert das Markup von Stud.IP um die Möglichkeit, in Forenbeiträgen und Wikiseiten zoombare Karten aus Openstreetmap.org einzubinden.\" description=\"Erweitert das Markup von Stud.IP um die Möglichkeit, Openstreetmap.org Karten in Forenbeiträge, Wikiseiten, persönliche Kategorien, freie Informationsseiten von Veranstaltungen und Instituten einzubinden. Die Karten sind zoombar per Javascript. Das Markup sieht folgendermaßen aus:&#10;&#10;[osmap]latitude;longitude;zoomfactor[/osmap]&#10;&#10; Man braucht also nur die Position in Form von Latitude und Longitude und kann den Zoomfaktor frei wählen (meistens um die 10 bis 14).&#10;&#10; Da Openstreetmap nicht wie GoogleMaps keine Cookies setzt, ist der Einsatz von Openstreetmap datenschutzrechtlich nicht bedenklich.&#10;&#10; Weitere Optionen:&#10;&#10;- Breite des Kartendivs ist Variabel anpassbar durch Angabe einer mit Doppelpunkt abgetrennten Zahl im öffnenden Tag. Beispiel: [osmap:600].... würde die Karte auf 600 Pixel vergrößern.&#10;- Man kann hinter dem Zoomfaktor einen Text angeben, um einen Pin auf die Karte zu stecken (bei der angegebenen Position). Den Text sieht der Nutzer, wenn er die Maus auf den Marker bewegt.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/74d2d26a604cc3ee75a9b0d6fc335a48\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/eb209d283b78b825d64f7434c481b5b5\">\n    <release version=\"0.1\" studipMinVersion=\"2.3\" studipMaxVersion=\"2.666\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ab5eb124180f41ce62d0510a82521e6e\"/>\n  </plugin>\n  <plugin displayname=\"Organizer\" name=\"Organizer\" homepage=\"https://github.com/derfl0/Organizer\" short_description=\"Studententeams Selbstverwaltung\" description=\"In vielen Veranstaltungen sollen sich Studierende in Selbstverwaltung in Teams definierter mindest und Maximalgröße zusammenfinden und dann Projekte oder ähnliches zuteilen. Dieses Plugin ermöglicht genau das.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/f6c57fa4e2a666e279b75c489d6af2d5\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/4ce4f6e6c7970f54160f3ef8371579d5\">\n    <release version=\"1.0.1\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/42fe9d7d880a327cf43f3a2ae08935e8\"/>\n    <release version=\"1.0\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ca89aa77594f2661397d6a2e5843cc2d\"/>\n  </plugin>\n  <plugin displayname=\"OwnCloudPlugin\" name=\"OwnCloudPlugin\" homepage=\"https://gitlab.data-quest.de/studip-plugins-oeffentlich/OwnCloudPlugin\" short_description=\"Plugin zum Einbinden einer OwnCloud oder Nextcloud in Stud.IP 4\" description=\"OwnCloud-Plugin für Stud.IP&#10;===========================&#10;&#10;Mit diesem Plugin kann man ab der Stud.IP-Version 4.0 eine Owncloud (oder Nextcloud) als persönlichen Dateibereich einbinden und von und zu der Owncloud Dateien nach oder von Stud.IP kopieren.&#10;&#10;Installation&#10;------------&#10;&#10;1. Das Plugin wird ganz normal in Stud.IP per Drag&amp;amp;Drop installiert.&#10;2. Die OwnCloud braucht die OAuth2-App: https://github.com/owncloud/oauth2/releases, die installiert und aktiviert werden muss. Wer nur Stud.IP gewohnt ist: OAuth2 heißt im Owncloud-Kontext zwar &amp;quot;App&amp;quot;, ist aber das gleiche wie bei Stud.IP ein Plugin. Die Dateien müssen in das Owncloud-Verzeichnis unter `./apps/oauth2` abgelegt werden.&#10;3. Für OAuth in der OwnCloud hinter einem Apache braucht man das mod_rewrite und mod_env Modul, das die Regel `RewriteRule .* - [env=HTTP_AUTHORIZATION:%{HTTP:Authorization}]` umsetzt. Wenn das nicht aktiv ist, kann OAuth nicht funktionieren, weil der Apache alle Authorization-Header entfernt.&#10;4. Die OAuth2 &amp;quot;App&amp;quot; muss als Admin im Webinterface von Owncloud aktiviert werden unter &amp;quot;Einstellungen&amp;quot; (oben rechts unter dem Nutzernamen) -&amp;gt; Apps -&amp;gt; &amp;quot;Deaktivierte Apps anzeigen&amp;quot; -&amp;gt; &amp;quot;aktivieren&amp;quot;.&#10;5. Es muss in Owncloud ein Client angelegt werden. Unter Administration -&amp;gt; &amp;quot;Additional&amp;quot; einen neuen Client anlegen. Name ist dabei egal (vielleicht ja Stud.IP).&#10;6. Jetzt hat man einen OAuth2-Client erstellt und kopiert Client-ID und das Secret. Wichtig ist dabei, dass man die korrekte Redirect-URI angibt. Owncloud überprüft diese URI penibel. Sie sollte in etwa lauten `https://meinstud.ip/plugins.php/owncloudplugin/oauth/receive_access_token`. Auch sollte HTTPS aktiv sein.&#10;&#10;Jetzt muss man sich überlegen, wie das Owncloud-Plugin genutzt werden soll in Stud.IP. Gibt es eine zentrale OwnCloud für alle Stud.IP-Nutzer oder kümmern sich die Nutzer selbst um eine eigene OwnCloud?&#10;&#10;Zentral:&#10;&#10;1. Melde Dich im Stud.IP als Root an und gehe unter Admin -&amp;gt; System -&amp;gt; Konfiguration -&amp;gt; Owncloud.&#10;2. Trage die oben gewonnene Client-ID beim Parameter `OWNCLOUD_CLIENT_ID` ein.&#10;3. Trage das oben gewonnene Secret beim Parameter `OWNCLOUD_CLIENT_SECRET` ein.&#10;&#10;Individuell:&#10;&#10;1. Der Nutzer muss dann alleine die obigen Schritte durchführen bzw. seinen OwnCloud-Admin fragen, ob er das für ihn tun kann und die Credentials übergibt.&#10;2. Im persönlichen Dateibereich von Stud.IP 4.0 gibt es in der Sidebar den Punkt &amp;quot;OwnCloud konfigurieren&amp;quot;. Da muss er drauf klicken. Ein Dialog öffnet sich.&#10;3. Man muss die Adresse der OwnCloud eintragen (z.B. `https://meineuni/owncloud`) und App-ID und Secret von oben eintragen und die OwnCloud aktiv schalten und speichern.&#10;&#10;Die nächsten Schritte sind für beide Wege wieder dieselben:&#10;&#10;1. Wer es individuell eingestellt hat, kennt es schon: Im persönlichen Dateibereich von Stud.IP 4.0 gibt es in der Sidebar den Punkt &amp;quot;OwnCloud konfigurieren&amp;quot;. Da muss man drauf klicken.&#10;2. Man muss das Häkchen für &amp;quot;aktiviert&amp;quot; setzen und speichern.&#10;3. Das Fenster lädt sich neu und ein Button erscheint oben &amp;quot;OwnCloud für Stud.IP freigeben&amp;quot;. Dort klicken.&#10;4. Dann landet man in der OwnCloud und wird aufgefordert sich anzumelden. Vergewissern Sie sich in solchen Situationen immer (nicht nur jetzt), dass die URL stimmt und Sie Ihre Passwörter nicht einer anderen Seite als genau Ihrer OwnCloud zusenden.&#10;5. Die OwnCloud fragt Sie, ob Stud.IP in Ihrem Namen Daten abrufen und verändern darf. Klicken Sie auf &amp;quot;Authorisieren&amp;quot;.&#10;6. Jetzt landen Sie wieder in Stud.IP und die Schnittstelle zwischen Stud.IP und OwnCloud sollte eingerichtet sein.&#10;&#10;Probleme?&#10;&#10;- Manchmal scheint fast alles zu funktionieren. OAuth-Access-Token ist da, Refresh-Token ist da und der Refresh scheint auch zu klappen, aber es werden keine Dateien und Ordner angezeigt. Es erscheint stattdessen eine Fehlermeldung: &amp;quot;No &amp;#039;Authorization: Basic&amp;#039; header found. Either the client didn&amp;#039;t send one, or the server is misconfigured, No &amp;#039;Authorization: Basic&amp;#039; header found. Either the client didn&amp;#039;t send one, or the server is misconfigured, No &amp;#039;Authorization: Bearer&amp;#039; header found. Either the client didn&amp;#039;t send one, or the server is mis-configured&amp;quot;. In dem Fall muss man vermutlich in die Datei .htacess die Zeile einbauen `SetEnvIf Authorization &amp;quot;(.*)&amp;quot; HTTP_AUTHORIZATION=$1`\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/bd9f6a2cee41a56e2ea4ce4a9fdd638d\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/9f2571e2b987416c61748cb174d680ea\">\n    <release version=\"2.1.1\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c7f9aaf387eb8dd28e5afb7335acd3c3\"/>\n    <release version=\"2.0.2\" studipMinVersion=\"4.6\" studipMaxVersion=\"5.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/aa5af3d059ca64d48c417b87cca31b3a\"/>\n    <release version=\"1.2.1\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/26271bd84a173d18c9bf46bdbae08c5b\"/>\n    <release version=\"1.0\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/83520d5d041e54f021c90a252312fcff\"/>\n  </plugin>\n  <plugin displayname=\"PasswordFolderPlugin\" name=\"PasswordFolderPlugin\" homepage=\"https://gitlab.data-quest.de/studip-plugins-oeffentlich/PasswordFolderPlugin\" short_description=\"Ein Ordner für Stud.IP, dessen Inhalte von einem Passwort geschützt werden können\" description=\"Mit diesem Plugin kann man in dem Dateibereich einer Veranstaltung einen Ordner hinzufügen, dessen Inhalte mit einem Passwort geschützt sind.&#10;&#10;Der Lehrende kann ein Passwort festlegen. Wenn ein normales Mitglied der Veranstaltung (Status autor) in den Ordner wechselt, wird er oder sie aufgefordert, ein Passwort einzugeben. Nur wenn das Passwort korrekt ist, werden die Inhalte angezeigt. Pro Session in Stud.IP und pro Ordner muss das Passwort natürlich nur einmal eingegeben werden.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/379d6480c8b7f12d81deb8b61ed58719\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/156e3229ad41f54139e73de695797f6d\">\n    <release version=\"1.1\" studipMinVersion=\"\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/de8b4d50db2f876122eed0fe56f0bb29\"/>\n    <release version=\"1.0\" studipMinVersion=\"\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c6b85232c0da4f81785cf041a22fe8b9\"/>\n  </plugin>\n  <plugin displayname=\"PersonalFilesPlugin\" name=\"PersonalFilesPlugin\" homepage=\"https://github.com/Krassmus/PersonalFilesPlugin\" short_description=\"In Blubber kann man Dateien leicht per Drag&amp;amp;Drop hochladen. Einige dieser Dateien werden nicht in einer Veranstaltung hochgeladen, sondern einfach einem Nutzer zugeordnet. Noch gibt es keine Möglichkeit, alle eigenen Dateien oder die Dateien anderer auf einen Blick zu sehen. Das soll dieses Plugin ändern. Die Dateien werden in einer kleinen Galerie dargestellt. Möglichkeiten zum Bearbeiten oder Löschen gibt es noch nicht.\" description=\"In Blubber kann man Dateien leicht per Drag&amp;amp;Drop hochladen. Einige dieser Dateien werden nicht in einer Veranstaltung hochgeladen, sondern einfach einem Nutzer zugeordnet. Noch gibt es keine Möglichkeit, alle eigenen Dateien oder die Dateien anderer auf einen Blick zu sehen. Das soll dieses Plugin ändern. Die Dateien werden in einer kleinen Galerie dargestellt. Möglichkeiten zum Bearbeiten oder Löschen gibt es noch nicht.&#10;&#10; Ist das Plugin aktiviert, taucht es im Profil eines Nutzers auf im Reiter &amp;quot;Dateien&amp;quot;. Dort bekommt man eine kleine Galerie zu gesicht. Man kann die Dateien auch herunterladen per Klick auf den Titel. Es gibt keine Möglichkeit, neue Dateien hochzuladen, die bestehenden Dateien zu bearbeiten oder zu löschen. Das wären Punkte einer möglichen zukünftigen Version dieses Plugins.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/4e919abeccbfc29ca6371a5cfb927e14\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/8d592cb11abc4d1f57ada8510b905b68\">\n    <release version=\"1.0\" studipMinVersion=\"2.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/1625a31f96aa79e46325cc1efee33cb3\"/>\n  </plugin>\n  <plugin displayname=\"Persönliche News\" name=\"Neo-Persoenliche-News\" homepage=\"neo.hfwu.de\" short_description=\"Dieses Plugin sammelt alle Ankündigungen von Einrichtungen und Veranstaltungen des angemeldeten Users und zeigt auf der Startseite die letzten 30 Stück an.\" description=\"Mit diesem Portalplugin erhalten die User eine Übersicht über die letzten 30 News seiner Einrichtigungen und seiner Vorlesungen.  &#10;&#10;  &#10;&#10; In dieser Version fehlt die Anzeige ob der User die News schon gelesen hat und die Einstellmöglichkeiten für den User.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/e2437d810c4f3f729cfed3763b3f023e\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/f3e72f8453e28e297fa6060c414e59db\">\n    <release version=\"0.9\" studipMinVersion=\"2.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c524aa15d978ce799da0bea10fd98025\"/>\n  </plugin>\n  <plugin displayname=\"Persönlicher-Lern-Dialog (&amp;quot;PerLe&amp;quot;)\" name=\"Persönlicher-Lern-Dialog\" homepage=\"https://develop.studip.de\" short_description=\"Das Plugin ermöglicht das Führen eines Lerntagebuches im Dialog mit dem Lehrenden.\" description=\"\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/cb74a52bc8fc143b35cb9d6a1b09dfb6\" score=\"2\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/d2545095fee6c6722ffbc43663f971af\">\n    <release version=\"0.80.0\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/79599cf3c69b490455a45d3a1863d9f8\"/>\n    <release version=\"0.73\" studipMinVersion=\"4.1\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/71e8628b5b7a80ef59ba2670d696074b\"/>\n    <release version=\"0.62\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c5b4d8f286ac504d910b948936cfbec4\"/>\n    <release version=\"0.54\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b2ac21de27d07bc184ae4039be011ddc\"/>\n    <release version=\"0.53\" studipMinVersion=\"2.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e7cd0e7dbc7cb7e2d7e90399f7ec683c\"/>\n  </plugin>\n  <plugin displayname=\"PlagScan\" name=\"PlagScan\" homepage=\"\" short_description=\"Das Plugin integriert PlagScan zur Erkennung von Plagiaten und falsch zitierten Passagen in Stud.IP.\" description=\"PlagScan Plagiatserkennung&#10;--------------------------&#10;&#10; PlagScan (https://plagscan.com) ist ein Service zur Überprüfung von Dokumenten auf Passagen, die aus anderen Quellen stammen. Dieses Plugin erweitert den Dateibereich einer Veranstaltung um Funktionen zur komfortablen Nutzung des PlagScan-Services. Nahtlose Integration im Dateibereich&#10;------------------------------------&#10;&#10; Ein spezieller Ordnertyp ermöglicht das Überprüfen der darin enthaltenen Dokumente. Die Überprüfung kann durch die Lehrenden für jedes Dokument einzeln vorgenommen werden oder völlig automatisch bereits beim Hochladen des Dokuments in den Order erfolgen. So wie beim Hausaufgaben-Ordner sehen Studierende nur ihre eigenen Dokumente.  &#10;  &#10; Lehrende können die Sichtbarkeit des Ordners zeitlich festlegen und angeben, ob die Auswertungen für Studierende sichtbar sein sollen. Umfangreicher Report&#10;--------------------&#10;&#10; Die Dokumente werden an den PlagScan-Service zur Auswertung übertragen. Sobald ein Ergebnis vorliegt, wird Der &amp;quot;PlagLevel&amp;quot; am Dokument angezeigt und die Auswertung (Report) kann in einem neuen Fenster geöffnet werden. Dieser wird direkt vom PlagScan-Service generiert und enthält neben der umfangreichen Analyse der Quellen auch eine Kommentarfunktion mit deren Hilfe Lehrende und Studierende den Bericht gemeinsam erschließen können (https://www.plagscan.com/de/plagiatberichte). Installation und Nutzung&#10;------------------------&#10;&#10; Zur Nutzung ist der kostenpflichtige Plagscan-Service nötig, den es als mietbaren Service oder als On-premises-Lösung mit einem Server an der Hochschule gibt. Bei Interesse kontaktieren Sie bitte Marco Bohnsack, 0551 38198-51, [bohnsack@data-quest.de](mailto:bohnsack@data-quest.de?subject=PlagScan%20Plugin).  &#10; Bei der Einrichtung des Plugins ist data-quest gerne behilflich. History&#10;-------&#10;&#10;### 2.1.2&#10;&#10;- Root-Administrator:innen können Dateien immer löschen (unabhängig vom Status).&#10;- Client-Timeout kann konfiguriert werden.&#10;&#10;### 2.0.1&#10;&#10;- Anpassungen an geänderten Dateibereich ab Stud.IP 4.6.&#10;- Sortierung der Datei-Tabelle verbessert.&#10;&#10;### 1.1.1&#10;&#10;- Der Cronjob startet automatisch eine Auswertung, falls diese für ältere Dateien noch nicht vorliegt. Sollte die Auswertung durch PlagScan nicht möglich sein, wird die Datei auf den Status &amp;quot;Fehler&amp;quot; gesetzt (rotes !-Icon). Der Fehler wird als Tooltip angezeigt.&#10;- Löschen von mehreren Dateien (Bulk-Funktion) jetzt immer möglich, außer die Datei wird gerade von PlagScan überprüft.&#10;&#10;### 1.1.0&#10;&#10;- Der Status der Dateien kann per Cronjob vom PlagScan-Server abgerufen werden. Das ist z.B. bei Verbindungsproblemen sinnvoll, da der Status jetzt automatisch von Stud.IP aus aktualisiert wird.&#10;- Löschen der Dateien auch möglich, wenn noch keine Auswertung vorliegt.&#10;- Root-Administrator:innen können Dateien immer löschen (unabhängig vom Status).&#10;- Client-Timeout kann konfiguriert werden.&#10;- Dateiliste kann nach Status und PlagLevel sortiert werden.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/e3e23972fe11da9293e227dff4f41fd9\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/6327415607274073b542cecd16f4cb93\">\n    <release version=\"2.3.1\" studipMinVersion=\"5.3\" studipMaxVersion=\"5.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e2011daeb2db1bb96af5c990ecbb6bee\"/>\n    <release version=\"2.2.2\" studipMinVersion=\"4.6\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/007ee5aefd0b2468fcdb3e1429c95b2d\"/>\n    <release version=\"2.1.3\" studipMinVersion=\"4.6\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/62436d76bd4031f675b1ae77cb0a3495\"/>\n    <release version=\"2.1.2\" studipMinVersion=\"4.6\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5953b35dd1058740243d976c0a1625e3\"/>\n    <release version=\"2.0.1\" studipMinVersion=\"4.6\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/edbbcdfc4bdd51be784e18b798563bb0\"/>\n    <release version=\"1.1.1\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/1336841ea4a28c57e6ad8f990d0fe7eb\"/>\n    <release version=\"1.1.0\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5814cf29758b6579aa22167c058ab437\"/>\n    <release version=\"1.0.3\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2f58e2909c04fea589dc965c0c16e79b\"/>\n    <release version=\"1.0.2\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8c18e09a5a3ee5c345480cc1795d917d\"/>\n    <release version=\"1.0.1\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/07f71ca6317b57c80481b16659050957\"/>\n    <release version=\"1.0.0\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/358ea327a523114ae94cce6db327205d\"/>\n  </plugin>\n  <plugin displayname=\"PlanerPlugin\" name=\"Planer\" homepage=\"\" short_description=\"Kombiniert Stundenplaner und Terminkalender in einer Ansicht.\" description=\"Das PlanerPlugin vereint die Ansichten für den Stundenplaner und den Terminkalender auf eine Seite. Die Wochen werden als Kalenderblätter in einem Reiter dargestellt, so dass schnell zwischen den Wochen und dem Stundenplaner, bzw. der Semesteransicht geblättert werden kann. Die Funktionen sind weitestgehend identisch mit dem Stundenplaner und dem Terminkalender. Neu hinzugekommen ist eine Schnellsuche nach Veranstaltungen, und eine neue Details-Seite für Veranstaltungstermine. Das Plugin stellt zwei Plugins zur Verfügung. Das PlanerPlugin ersetzt den Stundenplaner und stellt die neue Ansicht unter dem Navigationspunkt &amp;quot;Planer&amp;quot; bereit.. Das PlanerWidget kann aktiviert werden, damit der Planer auch als Widget auf der Startseite angezeigt werden kann.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/c7d4363dcd44c345c51d6444ddc2b6ab\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/b8d9f40402af1dbfad970cdb517a03a1\">\n    <release version=\"2.8.0\" studipMinVersion=\"5.1\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8068bc30166f71e6b0d558d6e3f61bc8\"/>\n    <release version=\"2.3.2\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/cc08b49bfe19422eb4ce30436f1c2b00\"/>\n    <release version=\"2.2.3\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/dd4b10be3b462efa7b1e2b577689a433\"/>\n    <release version=\"2.2.2\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2ee84f6fa4b73a5bc95c1071566b2bb9\"/>\n    <release version=\"2.2.1\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/bb4d07b961a45e072fe3982176700cbf\"/>\n    <release version=\"2.2\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.3\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/839111f7fbd489f13b564ac28f8cb444\"/>\n    <release version=\"2.0\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b8ed5412e48a927bd9f84a2948a91ae5\"/>\n    <release version=\"1.3.1\" studipMinVersion=\"3.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/0a20a0308b725698dab83b73ef7519a0\"/>\n    <release version=\"1.1.3\" studipMinVersion=\"3.3\" studipMaxVersion=\"3.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/32b05c289e4939da99a46846482115d9\"/>\n  </plugin>\n  <plugin displayname=\"PluginsOverviewPlugin\" name=\"PluginsOverviewPlugin\" homepage=\"\" short_description=\"Dieses Plugin zeigt eine Übersicht aller Plugins und die Veranstaltungen an, in denen diese aktiviert sind.\" description=\"\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/e5df40e8c19c260bb9f654df6b83e7cc\">\n    <release version=\"0.1\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4067ab6988ecaa98d1636422a910b47c\"/>\n  </plugin>\n  <plugin displayname=\"Plus1Minus1Plugin\" name=\"Plus1Minus1Plugin\" homepage=\"https://github.com/tthelen/Plus1Minus1Plugin\" short_description=\"Das Plugin ermöglicht kleine, in den Text eingebettete Abstimmungen im Sinne von &amp;quot;Gefällt mir&amp;quot;-Angaben.\" description=\"\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"8\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/0ee22df504ee928b2c07563c5369dea7\">\n    <release version=\"0.2.1\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/64fb7973478e7f61a33b58e474872e5f\"/>\n  </plugin>\n  <plugin displayname=\"Podium\" name=\"Podium\" homepage=\"\" short_description=\"Suche war gestern\" description=\"Das Podium ist eine Weiterentwicklung des QuickfilePlugin.  &#10; Es benötigt keine Indextabellen und funktioniert direkt nach der Installation.  &#10; **ACHTUNG! Dieses Plugin funktioniert NICHT zusammen mit Quickfile**&#10;&#10; Öffnen mittels STRG + Leertaste oder über das Suche Icon  &#10; Per Klick auf eine Kategorie oder durch drücken der Alt Taste, wird in dieser Kategorie mehr Suchergebnisse angezeigt.  &#10;  &#10; Für Entwickler:  &#10; Hinzufügen einer weiteren Suchkategorie durch eine Klasse, die das Interface PodiumModule implementiert.  &#10; Laden der Klasse durch ##Podium::registerPodiumModule(&amp;#039;Klassenname&amp;#039;)##\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/7d4e3f0f05a8e5e5ff3aa0f53d2b8956\" score=\"9.3235570064456\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/857547056c84bf079eb5172c056806f3\">\n    <release version=\"1.6\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/6e5a714c8f2df37596225966ca0de308\"/>\n    <release version=\"1.5.2\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c9bac68257f3a5289e64a9d4e1fb25f5\"/>\n    <release version=\"1.5.1\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/084137f5d3276f56f8fb76e772dde581\"/>\n    <release version=\"1.5\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/25c0bb59dad28a44a2f678cf2ef036d5\"/>\n    <release version=\"1.4\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ae699e465cf44221759863221bc7892a\"/>\n    <release version=\"1.3\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a633b9cddded37704fb1c97bb1fc4240\"/>\n    <release version=\"1.2\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/baf9c38938d18c6e785953e78a19db96\"/>\n    <release version=\"1.1.4\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/6c9d944657a365dbcc00eae4b66360ba\"/>\n    <release version=\"1.1.3\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/dcff1c1d8336452d817c62ca48ddb38d\"/>\n    <release version=\"1.1.1\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8714dbd0601c9e96ce16098c96f2ac29\"/>\n    <release version=\"1.1\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/6dd46f2a721a44decb839a7a3cc10768\"/>\n    <release version=\"1.0\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/7d672567485bab24a71a12c811695c26\"/>\n    <release version=\"0.9\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/62b9a8a8dbe0cb880d4c8f988bc75f3e\"/>\n  </plugin>\n  <plugin displayname=\"portaLE\" name=\"portaLE\" homepage=\"http://www.uni-trier.de/index.php?id=33410\" short_description=\"Die virtuelle Arbeitsumgebung „portaLE“ bietet für die Lehre vielfältige und leicht zugängliche Gestaltungsmöglichkeiten von virtuellen Arbeitsräumen. Sie integriert diverse Nutzungsmöglichkeiten in den Bereichen der Studierendenbetreuung sowie des wissenschaftlichen Austausches in Forschungsprojekten. Neben den Möglichkeiten der Organisation von virtuellen Vorlesungen und der Durchführung der Online-Seminare bietet die Schnittstelle eine Forschungsinfrastruktur zur Durchführung von Konferenzen.\" description=\"Die virtuelle Arbeitsumgebung „portaLE“ bietet für die Lehre vielfältige und leicht zugängliche Gestaltungsmöglichkeiten von virtuellen Arbeitsräumen. Sie integriert diverse Nutzungsmöglichkeiten in den Bereichen der Studierendenbetreuung sowie des wissenschaftlichen Austausches in Forschungsprojekten. Neben den Möglichkeiten der Organisation von virtuellen Vorlesungen und der Durchführung der Online-Seminare bietet die Schnittstelle eine Forschungsinfrastruktur zur Durchführung von Fachkonferenzen und zusätzlich eine Arbeitsumgebung zur Planung virtueller Sprechstunden.   &#10;  &#10;**Wichtig:** „portaLE“ ist kein in Stud.IP eigenständig laufendes Plugin. Idealerweise sollte daher auf einem externen Server eine Openmeetings-Installation aufgesetzt werden. Anschließend müssen beide Systeme portaLE und Openmeetings konfiguriert werden. Die Firma data-quest bietet für diese ungewohnt komplexen Arbeiten einer Plugin-Installation eine spezielle Supportunterstützung an (Ansprechpartner: Marco Bohnsack, bohnsack@data-quest.de).   &#10;  &#10;Unter http://demo.studip.de kann das Plugin in einer restriktiven Version getestet werden.   &#10;  &#10;Eine ausführliche Hilfe zu Bedienung und Funktionsumfang des Plugins findet sich unter: http://hilfe.studip.de/index.php/Basis.portaLE?setstudipview=root&amp;amp;setstudiplocationid=utr   &#10;  &#10;Neuigkeiten, weiterführende Informationen und Kontakt zur Entwickler-Community der Openmeetings-Plattform finden sich unter: http://code.google.com/p/openmeetings\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/2fa421ae33a9946a2b7c1406d679c28b\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/873a55e728d4489bff6bcaff4d22e4d8\">\n    <release version=\"1.2.0\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/880aaa32edf44abb00d2ac1851907d70\"/>\n  </plugin>\n  <plugin displayname=\"PortalInfos\" name=\"PortalInfos\" homepage=\"\" short_description=\"PortalInfos fügt lediglich eine kleine Box mit Informationen auf der Startseite ein.\" description=\"****Hinweis für alle meine Plugins: Getestet bis Stud.IP 2.3.1, Support für künftige Versionen ungeklärt****&#10;&#10; Ist das Plugin WordpressBlog installiert, so bindet es automatisch die Newsletter-Plugin-Funktion von Wordpress ein und ermöglicht eine Twitter-Anbindung.&#10;&#10; Informationen über Kontakt bezieht dieses Plugin aus dem Plugin Support.&#10;&#10;  &#10;&#10;**Kein Ready-To-Use-Plugin**&#10;&#10; Der Code muss vor Einsatz überarbeitet werden:&#10;&#10; Der Text fürs Wartungsfenster ist hardcoded und der Twitter-Username müsste verändert werden.&#10;&#10;**Das Plugin sollte für nobody freigegeben werden.**\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/4a11557b2304bcced116a1292b6d97d5\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/ea20dc2736e04c1f63b5491ff93e65ea\">\n    <release version=\"0.8.5\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/6c92fb4571f1c3df37f1201b436b864a\"/>\n    <release version=\"0.8.1\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5b5c29f1b2f5a7899ffbbd63bf088553\"/>\n    <release version=\"0.8\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fd8a313eb077b05fb26cf95b43ba4489\"/>\n  </plugin>\n  <plugin displayname=\"PortalWidgetsPlugin\" name=\"PortalWidgetsPlugin\" homepage=\"\" short_description=\"Stellt einige Widgets zur Verfügung, die auf einer beliebigen Seite eingebettet werden können. Darunter: Aktuelle Anmeldungen meiner Lehrstühle, Neue Veranstaltungen, meine Veranstaltungen, News meiner Lehrstühle, neue Nachrichten.\" description=\"****Hinweis für alle meine Plugins: Getestet bis Stud.IP 2.3.1, Support für künftige Versionen ungeklärt****&#10;&#10; Ein Beispiel dieser Widgets in Aktion sieht man, wenn man zunächst das Plugin CustomStart installiert. Die Widgetss sind dabei frei verschiebbar und die Sortierung wird userabhängig gespeichert.&#10;&#10; Basiert auf der Template-Engine Smarty.&#10;&#10; Verschiedene Ordner müssen deshalb für den Webserver beschreibbar sein.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/75e1b78c3e1c001cd6a1e10e75f6c219\" score=\"2\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/0b41f3d88bf23f5a428dda4c483b0ea8\">\n    <release version=\"0.5.1\" studipMinVersion=\"2.3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f7facf924fc80047d83fec91719a5c47\"/>\n  </plugin>\n  <plugin displayname=\"PreliminaryParticipantsNewsPlugin\" name=\"PreliminaryParticipantsNewsPlugin\" homepage=\"https://github.com/noackorama/PreliminaryParticipantsNewsPlugin\" short_description=\"Anzeige der Ankündigungen einer Veranstaltung für vorläufige Teilnehmer\" description=\"Anzeige der Ankündigungen einer Veranstaltung für vorläufige Teilnehmer und für Wartende. Es wird ein Icon eingeblendet, wenn Ankündigungen verfügbar sind. Die Anzeige der Ankündigungen passiert in einem modalen Fenster. Auf der Detailseite wird eine Anzeigebox mit den Ankündigungen oben eingeblendet. Ankündigungen können auch kommentiert werden.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/b7d47ac8b8602dd200e03029261a3368\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/345b0fcf98c092fa8ffa30315f56436e\">\n    <release version=\"7\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/79e324b8350acd180dc2fcad6c651b62\"/>\n    <release version=\"6\" studipMinVersion=\"3.2\" studipMaxVersion=\"3.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e2282cd0b4fd19b953b91f9f4e10000b\"/>\n    <release version=\"5\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e537cff253b1a4259f42a11de09bfd7f\"/>\n    <release version=\"4\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/40aad8f450801e6d2bf2abbb12647098\"/>\n  </plugin>\n  <plugin displayname=\"PrometheusMetrics\" name=\"PrometheusMetrics\" homepage=\"https://gitlab.studip.de/uni-osnabrueck/plugins/prometheusmetrics\" short_description=\"Mit diesem Plugin können die Metriken aus Stud.IP von Prometheus ausgelesen werden.\" description=\"Dieses Plugin stellt eine URL zum Export von Metriken aus Stud.IP im OpenMetrics-Format bereit, das u.a. von Prometheus verwendet werden kann. Die Datenabfrage ist über ein Passwort geschützt, das in der Stud.IP-Konfiguration gesetzt werden kann (PROMETHEUS_AUTH).\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/5df0fa6c10ce23320e5507ee7fed9e1a\">\n    <release version=\"0.4\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/38fb6a1f0811a540f314635956e43ea5\"/>\n  </plugin>\n  <plugin displayname=\"QIS-Export\" name=\"HISExport\" homepage=\"\" short_description=\"Das Plugin überträgt Raumbuchungen über einen Webservice an die lokale QIS-Installation (Raumbuchungssystem) der Firma HIS.\" description=\"****Hinweis für alle meine Plugins: Getestet bis Stud.IP 2.3.1, Support für künftige Versionen ungeklärt****&#10;&#10;  &#10;&#10; Ein Cronjob tätigt dabei kontinuierlich Buchungen, so dass der Stand im QIS immer möglichst aktuell ist. Der Webservice auf QIS-Seite wird nicht mitgeliefert, so dass das Plugin eher als Vorlage dienen kann.&#10;&#10;  \" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/86205af7a47ad9bf783b4dc02918f93c\">\n    <release version=\"0.8.1\" studipMinVersion=\"2.3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4bb5b22ed24984a8185b800e592e99de\"/>\n  </plugin>\n  <plugin displayname=\"QRCourse\" name=\"QRCourse\" homepage=\"\" short_description=\"Ermöglicht das Anzeigen eines QR-Codes für Dozenten in ihren Veranstaltungen.\" description=\"Innerhalb einer Veranstaltung kann sich ein Dozent einer Veranstaltung einen QR-Code zur aktuellen Seite in Stud.IP als QR-Code anzeigen lassen. Damit lässt sich aus allen Veranstaltungsseiten schnell ein Audience-Response Werkzeug bauen. Die Studenten müssen dann nur noch das Handy zücken und schon kann instatan zu einem Thema live geblubbert werden oder live eine Umfrage in Stud.IP beantwortet werden oder eine DoIt-Aufgabe bearbeitet werden (gerne auch mit dem Tablet statt dem Smartphone), Evaluationen per EvaSys oder Unizensus können schnell dargestellt werden. Der Dozent bekommt sofort Rückmeldungen bzw. Ergebnisse.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/a6d58c06da54f9786895281014516dd5\" score=\"8\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/886e5033b74585235cc6009c64eb9da5\">\n    <release version=\"1.2.6\" studipMinVersion=\"4.0\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/53ef3716c66c4ea7816fd5f9b2de3197\"/>\n    <release version=\"1.2.5\" studipMinVersion=\"4.0\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/040cd49a7e11fb39413cb5c4f153eec8\"/>\n    <release version=\"1.2.4\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/9221ec62b5242bab1466e9401453579a\"/>\n    <release version=\"1.2\" studipMinVersion=\"3.2\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a17e1df5166ed5e34169b3e2acd2ef55\"/>\n    <release version=\"1.1\" studipMinVersion=\"3.2\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ab034ac4385973209c745a2e36366047\"/>\n    <release version=\"1.0\" studipMinVersion=\"3.1\" studipMaxVersion=\"4.0\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a8cdda422c1468bdb4ac466260b6b30b\"/>\n  </plugin>\n  <plugin displayname=\"QuickCounter\" name=\"QuickCounterPlugin\" homepage=\"http://docs.studip.de/help/2.2/de/Basis/VerschiedenesFormatQuickCounter\" short_description=\"Manchmal möchte man einfach etwas zählen. Ein einfaches Interface soll das Zählen leicht machen, ein flexibler Weg Zähler einzurichten dafür sorgen, dass Auswertung und Darstellung genau zur Aufgabe passen.Die QuickCounter-Schnellformatierungsbefehle sollen genau dies leisten. Sie wurden ursprünglich entwickelt, um Papierstrichlisten, die von Mitarbeitern des Stud.IP-Supports an der Uni Osnabrück gepflegt wurden, durch Stud.IP-Formulare abzulösen.\" description=\"Genauere Beschreibung und Anwender-Dokumentation unter http://docs.studip.de/help/2.2/de/Basis/VerschiedenesFormatQuickCounter&#10;&#10; Versionsverwaltung bei Github: https://github.com/tthelen/QuickCounterPlugin&#10;&#10; Updates:&#10;&#10;- Version 0.2.3 - Behebt Fehler bei Zeitstempel-Darstellung in der Listenansicht\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/36644311525f33f27fa1ffaba2bfcbe6\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/237d63dd445138f19f9f314eb96266bf\">\n    <release version=\"0.2.3\" studipMinVersion=\"2.2\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/df7d1cf1a9e21b2020c34d623e62f6a3\"/>\n    <release version=\"0.2.0\" studipMinVersion=\"2.2\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a452c67a90bfc06ee4b6c680d653a5bd\"/>\n  </plugin>\n  <plugin displayname=\"QuickLinkPlugin\" name=\"QuickLinkPlugin\" homepage=\"https://gitlab.data-quest.de/studip-plugins-oeffentlich/QuickLinkPlugin\" short_description=\"Dieses Plugin stellt ein Widget auf der Startseite bereit, in dem URLs untergebracht werden können.\" description=\"QuickLinkPlugin&#10;===============&#10;&#10;Dieses Plugin stellt ein Widget auf der Startseite bereit, in dem URLs zu Stud.IP-Veranstaltungen oder externen Webseiten untergebracht werden können, sodass ein Schnellzugriff möglich ist.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/4b55eeb4f0412c0ee7385b3c99a5ffc9\">\n    <release version=\"1.0\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/1247ab69d7bef49164c57d161e57ab56\"/>\n  </plugin>\n  <plugin displayname=\"Quickscope\" name=\"QuickScope\" homepage=\"https://github.com/derfl0/quickscope\" short_description=\"Schnellübersicht für Veranstaltungen und Nutzer\" description=\"Das Quickscope Plugin gibt einen schnellen Überblick über Veranstaltungen und Nutzer, wenn die Maus über einen Link bewegt wird. Außerdem wird ein HTML5 Kontextmenü (Rechtsklickerweiterung) an den Punkt angehängt.  &#10;  &#10; Anzeige bei Veranstaltungen:  &#10; - Avatar  &#10; - Name  &#10; - Dozenten  &#10; - Zeiten  &#10; - Teilnahmestatus  &#10; - Kollision im Stundenplan  &#10; - Aktion: Eintragen in die Veranstaltung  &#10; - Aktion: Im Stundenplan vormerken  &#10;  &#10; Anzeige bei Benutzern:  &#10; - Avatar  &#10; - Name  &#10; - Email  &#10; - Aktion: Zu Kontakten hinzufügen  &#10; - Aktion: Stud.IP Nachricht schreiben  &#10;  &#10; Info: Das HTML5 Kontextmenü ist derzeit nur für den Firefox verfügbar  &#10;  &#10; Durch die einfache Pluginstruktur ist sowohl der Text als auch die Aktionen sehr einfach erweiterbar.  &#10; Auch neue Linkobjekte können mit nur einer Zeile Code initialisiert werden.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/a16588207bbd4c9d62138dcaa9f66131\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/9cb1eabf8c20b844de1ca16244d79f4f\">\n    <release version=\"1.1.2\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a0fd9fadca9597e6f70fe955c3260757\"/>\n    <release version=\"1.1.1\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ceed665f7d2df6047df02661f025ccfd\"/>\n    <release version=\"1.1\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/acfff4d735d031d13a6ac5585d69a840\"/>\n    <release version=\"1.0\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5526b46aa0f697f7423ba43ad29e444d\"/>\n  </plugin>\n  <plugin displayname=\"Raumbelegung\" name=\"Raumbelegung\" homepage=\"\" short_description=\"Anzeige für Raumbelegung pro Tag\" description=\"Das Raumbelegungsplugin zeigt alle belegten Räume eines Tages an. Dabei können zwei Anzeigen gewählt werden: Liste oder Tabelle.  &#10; Für jede Gruppierung (Campus, Gebäude, Raum etc) wird anhand der Untergruppierungen die Belegungszeit errechnet.  &#10;  &#10; Prinzipiell werden nur Räume und Ressourcen, in denen sich Räume befinden angezeigt. Root verfügt über die Möglichkeit, bestimmte Ressourcen (und deren Kinder) von der Anzeige auszuschließen. (Diese Funktionalität erfordert Javascript)&#10;&#10;Die Erweiterung auf Zeitspannen und Benutzerfilter auf Gebäude wie beim [Raumbelegungen](?dispatch=show_plugin_details&amp;amp;plugin_id=4ab5648f59baf0abab517595871b802e) Plugin von [Johannes Stichler](?dispatch=show_profile&amp;amp;username=finix&amp;amp;plugin_id=4ab5648f59baf0abab517595871b802e) wäre ohne Probleme möglich. Bei Bedarf bitte einfach melden.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/35cd6a8eaece7eae18e246c3352b4bb5\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/5eccd9207e57e64938a25af95d7b771c\">\n    <release version=\"1.0\" studipMinVersion=\"1.11\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/6d24976f9ad035bb88a7c12a706f7ba1\"/>\n  </plugin>\n  <plugin displayname=\"Raumbelegungen\" name=\"Raumbelegungen\" homepage=\"neo.hfwu.de\" short_description=\"Gibt eine Liste mit Raumbelegungen in einem bestimmten Zeitraums und in einem bestimmten Gebäude aus.Das ganze kann als PDF oder in einer Druckansicht ausgegeben werden\" description=\"Gibt eine Liste mit Raumbelegungen in einem bestimmten Zeitraums und in einem bestimmten Gebäude aus.  &#10; Das ganze kann als PDF oder in einer Druckansicht ausgegeben werden&#10;&#10;  &#10;&#10; GitHub: https://github.com/cranus/Raumbelegungen\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/a79d3d8a668f53c4dd16d30272e89039\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/4ab5648f59baf0abab517595871b802e\">\n    <release version=\"1.9\" studipMinVersion=\"2.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/64abfaba63e86708ea532a0741886d73\"/>\n  </plugin>\n  <plugin displayname=\"Raumbewertung\" name=\"Raumbewertung\" homepage=\"\" short_description=\"Plugin zur Bewertung von Veranstaltungsräumen bzwgl. Über-/Unterfüllung, Sauberkeit, Defekte, sonstige Misstände. Unterstützt die lokale Raumadministration bei der Instandhaltung und Pflege universitärer Räume. Der Plugin-Teil zur Bewertung wird in allen Veranstaltungen per Default aktiviert, die Raumadministration hat eine Oberfläche zur Bearbeitung der Nutzerangaben und Rückfragemöglichkeiten an den Anfrager.\" description=\"\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/7098c9d3b0be3ea811b370fb4065a7cd\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/9e4686aa1237d7c91dd111e3f6b2016c\">\n    <release version=\"1.0\" studipMinVersion=\"2.0\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/6c0d68f9e04681b843eb4ab6b6773335\"/>\n  </plugin>\n  <plugin displayname=\"ResourceRepairPlugin\" name=\"ResourceRepairPlugin\" homepage=\"https://gitlab.data-quest.de/studip-plugins-oeffentlich/ResourceRepairPlugin\" short_description=\"\" description=\"Das Plugin ermöglicht die Reparatur von Ressourcen in der Raumverwaltung. Zurzeit ist es mit dem Plugin möglich, Kategorien für Ressourcen neu einzustellen.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/9b2c1fa6f7f53d81c43dcb5254c84836\">\n    <release version=\"0.1.1\" studipMinVersion=\"4.5\" studipMaxVersion=\"5.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/787f3cf113935fbd61e81346c22ae243\"/>\n  </plugin>\n  <plugin displayname=\"Rest.IP\" name=\"REST.Ip\" homepage=\"http://github.com/studip/studip-rest.ip\" short_description=\"Testing\" description=\"\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/7a1627dd9550167137da81bc5216ed1c\">\n    <release version=\"0.9.9.7\" studipMinVersion=\"2.3\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c0278e20425fddb12b68bdbe622c2375\"/>\n    <release version=\"0.9.9.6\" studipMinVersion=\"2.3\" studipMaxVersion=\"3.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/0991dbea596e53acb8ee953645729dc5\"/>\n    <release version=\"0.9.9.15\" studipMinVersion=\"2.3\" studipMaxVersion=\"3.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8e3f576db3dd68c2727e77fced80ae35\"/>\n    <release version=\"0.9.9.14\" studipMinVersion=\"2.3\" studipMaxVersion=\"3.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f7e51aa355c0b5eff2fbfee3683c5056\"/>\n    <release version=\"0.9.9.10\" studipMinVersion=\"2.3\" studipMaxVersion=\"3.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/0cd59473a62633456d8557264b559fe1\"/>\n    <release version=\"0.9.11\" studipMinVersion=\"2.3\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/3249df32db143de09ea85bc19c423b84\"/>\n    <release version=\"0.9.10\" studipMinVersion=\"2.3\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/1bff23f3cddcb51db8052b9f114e41fd\"/>\n    <release version=\"0.7.9.3\" studipMinVersion=\"2.3\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/7d186bb1cf998998a02cb24d548ced02\"/>\n  </plugin>\n  <plugin displayname=\"RSS Feeds Widget\" name=\"RSSFeedsWidget\" homepage=\"https://develop.intelec.uni-passau.de/gitlab/stud-ip-plugins/rssfeedswidget\" short_description=\"Zeigt News aus RSS Feeds auf der Startseite. Diese können sowohl global vorgegeben als auch User-spezifisch hinzugefügt werden.\" description=\"Zeigt News aus RSS Feeds auf der Startseite. Diese können sowohl von Roots global vorgegeben als auch User-spezifisch hinzugefügt werden. Global vorgegebene Feeds können aber auch pro User ausgeblendet werden.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/0e286f94d8dd2f4305e5d88e346989ae\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/9b9ae2114178f50b334210f27706a508\">\n    <release version=\"1.0\" studipMinVersion=\"3.1\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c9fe5e7b8cd7dd6cb4ae0f58eb904609\"/>\n  </plugin>\n  <plugin displayname=\"Schulungsplugin\" name=\"Schulungsplugin\" homepage=\"\" short_description=\"Regelmäßige Fort- und Weiterbildungen in und mit Stud.IP\" description=\"Mit dem Schulungsplugin können Sie regelmäßige Fort- und Weiterbildungen in und mit Stud.IP durchführen. Das Schulungsplugin arbeitet ideal mit dem Gradebook in Stud.IP, der Ilias-Schnittstelle, dem Lernmoduleplugin und VIPS zusammen.&#10;&#10;Einrichtung&#10;-----------&#10;&#10;- Installieren Sie das Plugin.&#10;- Erstellen Sie eine Veranstaltung und tragen Sie dort alle Personen mit Status &amp;quot;autor&amp;quot; ein, die geschult werden sollen.&#10;- Im Gradebook erstellen Sie je eine manuelle Leistung für jeden zu schulenden Inhalt wie &amp;quot;Brandschutz&amp;quot;, &amp;quot;Datenschutz&amp;quot; oder &amp;quot;Erste-Hilfe&amp;quot;.&#10;- Aktivieren Sie das Schulungsplugin in dieser Veranstaltung. Dort sehen Sie die soeben definierten Leistungen und können ihnen eine Gültigkeit zuweisen. Nach Ablauf der Gültigkeit muss eine Schulung wiederholt werden.&#10;- Erstellen Sie die Inhalte in Ilias, dem Lernmoduleplugin oder VIPS und stellen Sie sicher, dass diese Module nach erfolgreicher Absolvierung einen Eintrag in das Gradebook vornehmen. Passiert das, so wird auch automatisch ein Zertifikat im Schulungsplugin erstellt.&#10;- Fügen Sie nach Bedarf auf der Profilseite einer Person einen Vorgesetzten oder mehrere untergebene Mitarbeiter hinzu. Diese haben dann auch in ihrem Arbeitsplatz eine Übersicht über den Schulungsstand ihrer Mitarbeitenden.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/a947fc1c19f9ce42194649ca4c3f9a0b\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/5d05b3fc1628634490384d840f90b421\">\n    <release version=\"1.1.5\" studipMinVersion=\"\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/897cc445ac0e5d5b939ea1f11103fc04\"/>\n  </plugin>\n  <plugin displayname=\"Schwarzes Brett\" name=\"SchwarzesBrett\" homepage=\"\" short_description=\"Ein einfaches kleines Plugin, welches einen Marktplatz für Kleinanzeigen öffnet. So eignet sich dieses Plugin hervorragend als Anzeigenbörse für Lehrbücher, WG-Zimmer, Nachhilfe- oder Lerngruppen, Fahrgemeinschaften, studentische Hilfskraftsjobs oder für Angebote zu Studien-, Master- und Diplomarbeitsthemen. Die Themen sind frei gestaltbar, ebenso die Angebotsdauer (default: 30 Tage, per Systemkonfiguration einstellbar).\" description=\"Das Schwarze Brett verfolgt den Ansatz der &amp;quot;realen&amp;quot; Schwarzen Bretter in den Fluren, eine große Wand, auf der man sofort erkennen kann, was angeboten oder gesucht wird. Hier führen wenige Klicks schnell zum Ziel.&#10;&#10; Dieses Plugin ist nicht an Veranstaltungen oder Einrichtungen gebunden und für jeden Nutzer zugänglich. Jede einzelne Kategorie läßt sich zum Beschreiben an bestimmte Nutzergruppen binden (z.B. nur für Tutoren oder Dozenten beschreibbar).&#10;&#10;**Neue Funktionen:**&#10;&#10;- Tag-Cloud&#10;- Schnelleinsprünge&#10;- Spruchauswahl&#10;- Unterkategorien\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/27800ef53ce532dab91dc8560196b1b3\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/f58468aa0f18030b74e1d883ef022bd7\">\n    <release version=\"1.12\" studipMinVersion=\"2.0\" studipMaxVersion=\"2.1\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/622980da3e6416d0d912f0bf8dacf53c\"/>\n  </plugin>\n  <plugin displayname=\"Schwarzes Brett (UOL-Edition)\" name=\"SchwarzesBrettPlugin\" homepage=\"https://gitlab.studip.de/uol/plugins/SchwarzesBrettPlugin\" short_description=\"Ein einfaches kleines Plugin, welches einen Marktplatz für Kleinanzeigen öffnet. So eignet sich dieses Plugin hervorragend als Anzeigenbörse für Lehrbücher, WG\" description=\"**Es wird empfohlen, das Plugin bei einem Update zu deaktivieren und nach dem Update wieder zu aktivieren, wenn Sie eine Version &amp;lt;= 3.20 aktualisieren. Ansonsten kann es zu einem Problem mit Migration 22 kommen.**&#10;&#10;Dies ist eine Weiterentwicklung des originalen &amp;quot;Schwarzes Brett&amp;quot;-Plugin, welches für die Neuerungen in Stud.IP ab Version 3.1 angepasst wurde.&#10;&#10;Dazu zählen:  &#10;  &#10; - Sidebar  &#10; - Dialoge  &#10; - Startseiten-Widget  &#10;  &#10; Folgend die Beschreibung des Original-Plugins:  &#10;  &#10; Das Schwarze Brett verfolgt den Ansatz der &amp;quot;realen&amp;quot; Schwarzen Bretter in den Fluren, eine große Wand, auf der man sofort erkennen kann, was angeboten oder gesucht wird. Hier führen wenige Klicks schnell zum Ziel.  &#10;  &#10; Dieses Plugin ist nicht an Veranstaltungen oder Einrichtungen gebunden und für jeden Nutzer zugänglich. Jede einzelne Kategorie läßt sich zum Beschreiben an bestimmte Nutzergruppen binden (z.B. nur für Tutoren oder Dozenten beschreibbar).&#10;&#10; &#10;&#10;### Changelog&#10;&#10; 4.2 (3. September 2018) - Bilderupload und Galleriedarstellung&#10;&#10;  &#10; 3.14.1 (16. Januar 2017) - Bug bzgl. der Standardlaufzeit eines Artikels behoben (betrifft Stud.IP &amp;gt;= 3.4)&#10;&#10;  &#10; 3.14 (10. Januar 2017) - Logging der erstellten und gelöschten Anzeigen&#10;&#10;  &#10; 3.12 (27. Oktober 2016) - Fehlerbehebung im Cronjob&#10;- Erweiterter Garbage Collector im Cronjob&#10;&#10;  &#10; 3.11 (24. Oktober 2016) - Merkliste&#10;- Fehlerbehebung im Zusammenhang von versteckten Inhalten und der Suche&#10;&#10;  &#10; 3.8 (3. Juli 2015) - HomepagePlugin, das die aktuellen Anzeigen des Nutzers anzeigt&#10;- Verbesserte Suche (Suche auch in Anzeigentext, nicht nur Titel; Hervorhebung des Suchbegriffs in den gefundenen Anzeigen)&#10;- Beim Melden einer Anzeige wird der *Reply-To*-Header gesetzt, so dass man dem Nutzer einfacher antworten kann&#10;&#10;  &#10; 3.7.1 (24. Juni 2015) - Fehler bei deaktiviertem RSS-Export behoben&#10;&#10;  &#10; 3.7 (4. Juni 2015) - &amp;quot;Weitere Anzeigen&amp;quot; - Funktion (im Dialog neben dem Namen der einstellenden Person)&#10;- Übersichtlichere HTML-Mails&#10;- &amp;quot;Bad Words&amp;quot;-Liste, um bei Anzeigen mit bestimmten Begriffen eine Mail an die eMail zu schicken, an die auch Verstöße gemeldet werden&#10;- Anzeigen eines gesperrten Nutzers werden beim Vorgang des Sperrens versteckt&#10;&#10; \" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/ea866a6b4e9fba0c0d16019ae6e8bb6a\" score=\"9.5199428358233\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/2a4909b8b731c4980fb65814160dbaf2\">\n    <release version=\"4.9.2\" studipMinVersion=\"5.0\" studipMaxVersion=\"6.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/083e22d459ecc9c2ce00da775dd30ac9\"/>\n    <release version=\"4.9.1\" studipMinVersion=\"5.0\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b73d600cf67698380d60bb7833047759\"/>\n    <release version=\"4.8.8\" studipMinVersion=\"4.5\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/627de09bab8c32b024525a9690b534ed\"/>\n    <release version=\"4.8.7\" studipMinVersion=\"4.5\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/d417df5c0cd88d0b3077b758092a6f44\"/>\n    <release version=\"4.8.5\" studipMinVersion=\"4.5\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/165ae84881f09cd27f95c9746f2944de\"/>\n    <release version=\"4.8.3\" studipMinVersion=\"4.5\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e4532e17adce7cb8d8dd70e4e5753793\"/>\n    <release version=\"4.8.2\" studipMinVersion=\"4.5\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/25181560f149fd67ad38c0e45c3e