eingeschränkt werden, die Tabelle kann sortiert werden und als Excel Datei exportiert werden. Die tägliche Liste steht als rss-feed zur Verfügung.  &#10;  &#10; Ab 0.8 werden auch Ausfalltermine mit angezeigt, farblich gekennzeichnet.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/c5990fa58e50c968cff410da528e87ff\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/ec6b621966054a86865e2bc7fd542bdc\">\n    <release version=\"1.6.4\" studipMinVersion=\"4.4.99\" studipMaxVersion=\"5.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/24d1d8fb13cae7c987d780c38f9874ab\"/>\n    <release version=\"1.6.2\" studipMinVersion=\"4.4.99\" studipMaxVersion=\"5.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5311ee4109a3d04018627a0d161c958b\"/>\n    <release version=\"1.4.8\" studipMinVersion=\"4.4.99\" studipMaxVersion=\"5.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/64b8d06ad3c18a1d7081eeddd7aa5e48\"/>\n    <release version=\"1.4.2\" studipMinVersion=\"4.4.99\" studipMaxVersion=\"4.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/3868844e43af3910edd5a5116f6a8e1f\"/>\n    <release version=\"1.3.1\" studipMinVersion=\"4.4.99\" studipMaxVersion=\"4.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c27bac2f6f918775a65bcf750df2941d\"/>\n    <release version=\"1.2.6.2\" studipMinVersion=\"4.1\" studipMaxVersion=\"4.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f334da9296a0914e55bfc036c798e665\"/>\n    <release version=\"0.8\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/068560f0f4f21ff919ae77bf20c41c6b\"/>\n    <release version=\"0.6\" studipMinVersion