plugins.php/pluginmarket/presenting/download/a3d2c0a1c886dd494edef23bdc84b105\"/>\n    <release version=\"1.1.0\" studipMinVersion=\"4.0\" studipMaxVersion=\"5.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/91e935aaa6f172ce994ce4692abe760b\"/>\n    <release version=\"1.0.2\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.99.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5c1cbd47fc8e648292fa35d51f55ae14\"/>\n    <release version=\"0.9.1\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/9625520dfedf7cf575ac722a0a4b1e40\"/>\n    <release version=\"0.9.0-studip3.5\" studipMinVersion=\"3.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/66eee4082e836c807d3594c33789f771\"/>\n    <release version=\"0.9.0\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/0827bcc7dd5d37bddb0e0a422b10bc2f\"/>\n    <release version=\"0.9.0\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a450cab75c3221d41dd8a3ef97fb849a\"/>\n    <release version=\"0.8-studip3.5\" studipMinVersion=\"3.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fafddb354db6e2c8565520d3f1f23b6b\"/>\n    <release version=\"0.8\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/867b783459eea03eed3de65a923f0fe9\"/>\n    <release version=\"0.5.3\" studipMinVersion=\"3.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/d1b143f98a7f90d16203cffacc9e2061\"/>\n  </plugin>\n  <plugin displayname=\"TestsystemStylePlugin\" name=\"TestsystemStylePlugin\" homepage=\"https://gitlab.data-quest.de/studip-plugins-oeffentlich/TestsystemStylePlugin\" short_description=\"\" description=\"Dieses Plugin färbt die blauen Balken oben und unten ein und fügt optional einen Streifeneffekt hinzu. Dies dient dazu, Testsysteme von Produktivsystemen farblich unterscheidbar zu machen.  &#10;  \" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/50df694ec2d69ea1875e34fea97faa08\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/9770f79244a21022ca5bbdb965a86339\">\n    <release version=\"1.1.1\" studipMinVersion=\"4.3\" studipMaxVersion=\"5.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/1ae984005f931cc7b79cf42e923070aa\"/>\n    <release version=\"1.1\" studipMinVersion=\"4.3\" studipMaxVersion=\"5.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/9a4a00f0511eb433503e302da4158481\"/>\n  </plugin>\n  <plugin displayname=\"Tetris\" name=\"Tetris\" homepage=\"\" short_description=\"Ein kleines Tetris-Plugin\" description=\"Tetris gibt es jetzt auch in Stud.IP\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/d856afea3ca9bfc1fec64d61b4b6cb78\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/9bff64b1d0b0d28663caa1183a1d49e8\">\n    <release version=\"1.0\" studipMinVersion=\"2.1\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4b0cc984f88305db386976e88dd3c096\"/>\n  </plugin>\n  <plugin displayname=\"Themenschieber\" name=\"Themenschieber\" homepage=\"\" short_description=\"Ermöglicht es, die Themen auf der Terminseite einer Veranstaltung mittels Drag&amp;amp;Drop zu verschieben\" description=\"Auf Anregung eines Dozenten ermöglicht es dieses Plugin, die zu einem Termin zugeordneten Themen mittels Drag&amp;amp;Drop zu einem anderen Termin zu verschieben.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/b92f9f820a38028d1fa590bd3887c7e3\">\n    <release version=\"1.0\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/84710522f2e5080155157569425e260e\"/>\n  </plugin>\n  <plugin displayname=\"Themenverwaltung für Bachelorarbeiten\" name=\"ThesisManager\" homepage=\"https://gitlab.data-quest.de/studip-plugins-oeffentlich/thema\" short_description=\"Erstellung und Verwaltung von Themen für Bachelorarbeiten\" description=\"Diese Plugin erlaubt die Definition von Phasen und Betreuungspersonen für Bachelorarbeitsthemen in Stud.IP-Veranstaltungen. Themen werden je nach Einstellungen der jeweiligen Phase von den Studierenden oder den Betreuungspersonen erstellt und können zu einem definierten Zeitpunkt auch automatisch verteilt werden. Exporte (diese werden an jedem Phasenende automatisch erstellt) werden ebenso wie die jeweiligen Exposés zu den Themen in eigenen Ordnern im Dateibereich abgelegt.&#10;&#10;Berechtigungen in der entsprechenden Veranstaltung bedeuten:&#10;&#10;- autor: Teilnehmende, können sich auf Themen bewerben oder selbst welche einreichen (je nach Phaseneinstellungen)&#10;- tutor: Betreuen bis zu x Themen, sehen die für sie eingereichten Themen und können sie zu einem in der Phase festgelegten Zeitpunkt annehmen oder ablehnen&#10;- dozent: voller administrativer Zugriff auf alle Themen und Einstellungen in dieser Veranstaltung&#10;&#10;Pro Phase werden auch zu definierten Zeitpunkten automatische Erinnerungen oder Statusmails an Betreuungspersonen und Studierende verschickt.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/b9552c65da374107bfe2ea8efbd18a60\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/0671c42fe5f1ad33153f7ce549e24241\">\n    <release version=\"1.10\" studipMinVersion=\"4.4\" studipMaxVersion=\"5.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a90df7f501b1b3000ad961b63c4d75e2\"/>\n  </plugin>\n  <plugin displayname=\"TmpCleanerPlugin\" name=\"TmpCleanerPlugin\" homepage=\"\" short_description=\"Bereinigt das tmp Verzeichnis mit einem cronjob\" description=\"TmpCleanerPlugin&#10;================&#10;&#10;Diese Plugin installiert einen Cronjob, der regelmäßig den in TMP_PATH hinterlegten Ordner von temporären Dateien bereinigt, die älter als 60 Minuten sind. In der Stud.IP Konfiguration kann unter TMP_CLEANER_WHITELIST angegeben werden, welche Dateien nicht entfernt werden sollen, die studip.log Datei z.B. Unterverzeichnisse werden nicht berücksichtigt.&#10;&#10;Hinweis zu Systemen mit systemd&#10;-------------------------------&#10;&#10;Wenn der Webserver mit systemd gesteuert wird, kann es sein, dass dort ein privates tmp Verzeichnis aktiviert ist. (PrivateTmp=true) In diesem Fall schreibt der Webserver in einen speziellen Ordner, diese heissen üblicherweise so ungefähr /tmp/systemd-private-652727091e81431fbb51771e978adf20-apache2.service ... Die Inhalte aus diesen Verzeichnissen kann der Stud.IP Cronjob nicht löschen. In diesem Fall kann man nur über die Weboberfläche die Aufgabe manuell ausführen.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/cacb621a9f539389fbec7328aea07287\">\n    <release version=\"3\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.5\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/1d856e70beef3e5bccbbb08e1745902e\"/>\n  </plugin>\n  <plugin displayname=\"ToDo\" name=\"ToDo\" homepage=\"https://github.com/derfl0/todoplugin\" short_description=\"Ein ToDo Startseiten Widget\" description=\"Jeden Tag gibt es viel zu tun. Damit man nie den Überblick verliert, gibt es die :studip: todo Liste. Auch Freunden kann man leicht Aufgaben aufbürden: [todo +7 days]Ein neues Studip Plugin entwerfen[/todo] In der globalen Konfiguration können unter TODO_DEFAULT Standardaufgaben für jeden neuen Nutzer erstellt werden. So kann man Quietschies auf ihr hartes Studium bestens vorbereiten\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/dfb8bf9b3eb761fe235655302b27d1f6\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/66049e8c1ae936315b79a8111888150c\">\n    <release version=\"1.1\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a59592ee8a82e73b65325cef5cb4aab7\"/>\n    <release version=\"0.8\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fcb3c58e8baa8d98384236921b5d8134\"/>\n  </plugin>\n  <plugin displayname=\"Toolbox\" name=\"Toolbox\" homepage=\"https://gitlab.data-quest.de/studip-plugins-oeffentlich/Toolbox\" short_description=\"Zeigt Links zu kuratierten externen Tools im Arbeitsplatz an\" description=\"Einige Standorte haben neben Stud.IP noch weitere Tools im Angebot für ihre Lehrenden oder Studierenden. Externe Fragebogentools, QR-Codes, URL-Shortener, Clouddienste und und und. Da ist die Frage, wo man diese in Stud.IP sichtbar macht. &#10;&#10;Dieses Plugin gibt einem Admin die Möglichkeit, diese Tools unter Admin → Standort → Toolbox einzupflegen. Die anderen Accounts sehen diese Toolbox dann in ihrem Arbeitsplatz.&#10;&#10;Version 2.0&#10;-----------&#10;&#10;Die Tools können jetzt mit Drag &amp;amp; Drop sortiert werden. Das Plugin ist auf Barrierefreiheit geprüft und ausgebessert worden. Man kann Favoriten markieren, und diese Favoriten können auf der Startseite angezeigt werden. Man kann jetzt noch Zusatzinformationen zu den Tools bereitstellen. Und falls ein Icon im Iconset von Stud.IP fehlen sollte, kann man ein eigenes Icon für das Tool hochladen.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/b2ec57c334ccbe83a5bc6e9b26fbbdbb\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/ceb8db938d0424c625499f00e075b1d5\">\n    <release version=\"2.1.2\" studipMinVersion=\"\" studipMaxVersion=\"6.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/abe4626dbcd424d3eec4fa013447436f\"/>\n    <release version=\"2.1.1\" studipMinVersion=\"\" studipMaxVersion=\"6.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/cc8fe0fd476fc51d061ea6c26c84fb28\"/>\n    <release version=\"2.0\" studipMinVersion=\"\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b41b908aaceb54dd436ba5552c271154\"/>\n    <release version=\"1.0\" studipMinVersion=\"\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a2eaa940c83b325b7001c410d5749fc5\"/>\n  </plugin>\n  <plugin displayname=\"TouchPunch\" name=\"TouchPunchPlugin\" homepage=\"https://github.com/Krassmus/TouchPunch\" short_description=\"Fehlende Touch-Unterstützung für Drag&amp;amp;Drop in Smartphones und Tablets.\" description=\"Auf Tablets und Smartphones ist es unmöglich, sich in Prioritätslisten-Anmeldeverfahren anzumelden, weil man damit einfach nicht drag&amp;amp;drop ausführen kann. Dieses kleine Plugin behebt diesen Fehler.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/bb9038883014d01a031ecbf1c2177061\">\n    <release version=\"1.0\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/640ab0ff3d87d88783513f8e2bb8832b\"/>\n  </plugin>\n  <plugin displayname=\"Tresor\" name=\"Tresor\" homepage=\"https://github.com/Krassmus/Tresor\" short_description=\"Datenablage für Veranstaltungen in Stud.IP, die Ende-zu-Ende verschlüsselt ist.\" description=\"Tresor bietet eine sichere Ablage für Texte. Die Texte werden auf dem Stud.IP-Server verschlüsselt gespeichert. Nicht einmal ein Admin des Stud.IP kann die Texte mitlesen - nicht einmal mit Datenbankzugriff! Nur die Teilnehmer der Veranstaltung können die Texte lesen. Die Verschlüsselung und Entschlüsselung funktioniert im Browser der Nutzer mit PGP in Javascript. Die Nutzer müssen nur ein zusätzliches Passwort eingeben und bekommen von der ganzen Technik unter der Haube kaum etwas mit.&#10;&#10; &#10;&#10;Tresor-Plugin für Stud.IP und die Sicherheit&#10;--------------------------------------------&#10;&#10;Das Tresor-Plugin für Stud.IP ist gebaut worden, um Ende-zu-Ende-Verschlüsselung so gut wie möglich in Stud.IP zu ermöglichen. Das Plugin lässt sich als ein weiteres Inhaltselement in Veranstaltungen anschalten. Um den Tresor nutzen zu können, muss man sich zuerst ein PGP-Schlüsselpaar (Pretty Good Privacy aus dem Jahr 1991, das bis heute als sicher gilt) erzeugen. Das geschieht mit der Bibliothek OpenGPG.js in Javascript. Das Schlüsselpaar besteht aus einem privaten Schlüssel und einem öffentlichen Schlüssel. Der öffentliche Schlüssel wird direkt nach Stud.IP übertragen. Der private Schlüssel wird selbst noch einmal mit einer Passphrase, die der Nutzer in Stud.IP eingeben muss, synchron per AES-Verschlüsselung gesichert. Dieser mit Passphrase gesicherte Schlüssel wird dann ebenfalls zum Stud.IP-Server geschickt und dort gespeichert.&#10;&#10; &#10;&#10;Sind die Schlüssel erstellt, kann man in Stud.IP Dateien oder Texte in den Tresor „legen“, das bedeutet schreiben oder hochladen. Dateien und Texte werden dabei stets mit mit PGP verschlüsselt und zwar für alle Teilnehmer*innen der Veranstaltung. Jede*r Teilnehmer*in, der/die zuvor selbst ein Schlüsselpaar erzeugt hat, kann dann in der Veranstaltung in Stud.IP im Tresor die neuen Inhalte sehen und mit dem eigenen privaten Schlüssel dekryptifizieren und dann ansehen bzw. herunterladen. Dieses Entschlüsseln passiert dabei nicht auf dem Stud.IP-Server, sondern indem die verschlüsselten Daten und der gesicherte private Schlüssel des Nutzers zum Browser ausgeliefert werden, der Nutzer dann mit der Passphrase den eigenen privaten Schlüssel bereitstellt, womit er/sie dann die verschlüsselten Inhalte entschlüsseln kann. Das Ganze ist benutzerfreundlich in dem Sinne, dass der Nutzer den Tresor besucht und lediglich einmal nach der Passphrase gefragt wird und danach die Inhalte genauso sehen kann wie alle anderen Inhalte in Stud.IP auch.&#10;&#10; &#10;&#10;Aus Sicht der Nutzer*innen bedeutet das nur, dass man neben dem Passwort zu Stud.IP eine weitere Passphrase für den Tresor erzeugen und sich merken muss. Aus Sicht der Sicherheit ist es Ende-zu-Ende-Verschlüsselung per PGP mittels der Bibliothek OpenGPG.js . Wenn ein Angreifer die Datenbank von Stud.IP und alle Dateien des Dateisystems stiehlt, erhält diese Person noch immer keinen Zugriff auf die im Tresor verschlüsselten Daten, weil dem Angreifer die Passphrasen fehlen. Auch die Administratoren von Stud.IP - egal ob sie Zugriff auf Datenbank, das Dateisystem, den höchsten Nutzerstatus von Stud.IP oder alle diese drei Bereiche haben - können die Daten, die im Tresor gespeichert sind, nicht einsehen.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/146478713cd14261f6ac4a6d0b726c68\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/aa7ba8943fc953143146e0e41dd8fd2d\">\n    <release version=\"1.4.5\" studipMinVersion=\"\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/99d0095b82101381fc97e03f1513f769\"/>\n    <release version=\"1.3.1\" studipMinVersion=\"\" studipMaxVersion=\"4.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/143ddb28e8b4ff584467e2aa94b6e35c\"/>\n  </plugin>\n  <plugin displayname=\"Twitter Plugin\" name=\"Twitter\" homepage=\"\" short_description=\"Twitter-Plugin für den Einsatz auf der Homepage, der persönlichen Startseite und in Veranstaltungen.\" description=\"Twitter für die eigene Homepage&#10;-------------------------------&#10;&#10; Auf der eigenen Homepage werden die persönlichen Twitter-Einträge dargestellt, die für den eingetragenen Twitter-Account getätigt werden.&#10;&#10; Sobald die Accountdaten eingerichtet und verifiziert wurden, kann der Twitter-Dienst innerhalb von Stud.IP genutzt werden. Auf dem Reiter \\&amp;quot;Twitter\\&amp;quot; innerhalb der Homepage ist zudem einstellbar, ob die Tweets der eigenen Follower (Twitter-Freunde) auf der persönlichen Startseite angezeigt werden sollen.&#10;&#10; Sowohl auf der Homepage, als auch auf der Startseite und in Veranstaltungen können direkt Twitter-Nachrichten versandt werden. Hier gibt es zudem eine schnelle Suche in Twitter nach Stichworten.&#10;&#10; Aufgrund von Limitationen innerhalb der Twitter-API ist die Abfrage nach neuen Inhalten in einem Cache abgelegt. Eingetragene Twitter-Nutzer (deren Accountdaten in Stud.IP hinterlegt sind), bekommen eine hörere Refreshrate als nichteingetragene. Nachrichten können erst dann versandt werden, sobald ein gültiger Twitter-Account vorliegt.&#10;&#10;Twitter auf der persönlichen Startseite&#10;---------------------------------------&#10;&#10; Die persönliche Startseite zeigt die Tweets der eigenen Follower an und ermöglicht die Einrichtung persönlicher Twitter-Walls.&#10;&#10;Twitter in Veranstaltungen&#10;--------------------------&#10;&#10; Das Twitter-Plugin kann lehrbegleitend im Rahmen einer Veranstaltung mitgenutzt werden. In diesem Fall wäre eine eigene Twitter-Wall (Hashtag) für die Veranstaltung zu bestimmen, auf der alle Beiträge der Teilnehmer auflaufen. So können in der Veranstaltung zusätzlich asynchron schnell Fragen, Anregungen und Kommentare ausgetauscht werden.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/a238f1bc87981bc3f06806c44921dc19\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/81e82f0e3294723ec7946073662296bf\">\n    <release version=\"1.5.3\" studipMinVersion=\"1.9\" studipMaxVersion=\"2.0\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/70796424d9f8a23cc603fdf01ba0922d\"/>\n  </plugin>\n  <plugin displayname=\"Unizensus\" name=\"UniZensusPlugin\" homepage=\"https://gitlab.data-quest.de/studip-plugins-oeffentlich/UniZensusPlugin\" short_description=\"Stud.IP Plugin für die Verknüpfung mit der Evaluationssoftware Unizensus\" description=\"UniZensusPlugin&#10;===============&#10;&#10;Stud.IP Plugin für die Verknüpfung mit der Zensus Evaluationssoftware: https://www.blubbsoft.de/. &#10;&#10;Funktionsbeschreibung&#10;---------------------&#10;&#10;Grundsätzlich findet man unter dem Punkt &amp;quot;Lehrevaluation-Administration&amp;quot; eine Liste mit Veranstaltungen, die nach Einrichtungen/Semester usw. gefiltert werden kann. In der Tabelle kann man nun sehen, ob die Veranstaltung zur Evaluation vorgesehen ist und wie der aktuelle Status ist. Dazu muss man für die Veranstaltung im Stud.IP das Zensus-Plugin aktivieren. Man kann auf dieser Seite die gewüsnchten Veranstaltungen markieren und mit dem Punkt &amp;quot;Evaluationsplugin für ausgewählte Veranstaltungen ein/ausschalten:&amp;quot; das Plugin aktivieren. Danach wird für diese Veranstaltungen in der Spalte &amp;quot;Zensus Status&amp;quot; der Stand der Evaluation im Zensus angezeigt. Wenn im Zensus keine Evaluation vorgesehen ist, ist das einfach &amp;quot;error not found&amp;quot;. Wird im Zensus für diese Veranstaltung eine Evaluation aktiviert, so bekommen die Teilnehmer in der Veranstaltung einen weiteren Reiter zur Evaluation angezeigt. Darüber bekommen sie eine Link, mit dem sie einmalig im Zensus an der Evaluation teilnehmen können. Die Dozenten können hier den Stand einsehen, und evtl. nach Auswertung hier zur Auswertung gelangen. Die weiteren Möglichkeiten diene der Auswahl eines Zeitraums zur Evaluation. Das muss man nicht nutzen, solange hier keine Einschränkung gewünscht ist, ansonsten kann man hier Start- und Endzeitpunkte für eine oder mehrere Veranstaltungen setzen. Diese Einschränkungen gelten *nur* für den Zugang von Stud.IP aus.&#10;&#10;Aktiviert man zusätzlich das enthaltene Plugin *UniZensusNagScreen*, so wird Studierenden auf der Seite &amp;quot;Meine Veranstaltungen&amp;quot; einmal pro Session ein Dialogfenster eingeblendet wenn in der Veranstaltungsliste noch Veranstaltungen sichtbar sind, die vom Studierenden noch nicht evaluiert wurden. \" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/0c8d95439eae7629cfc7346575ab3859\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/72d83c942fda431cadf27bc5f3711bec\">\n    <release version=\"1.995\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f6437d4b7bb4d0e4c6e0642d0ba7c25d\"/>\n    <release version=\"1.992\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b82ccb17a6fdea7500faf4013923e312\"/>\n    <release version=\"1.99\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/6f5edf31b2c2567243ba181ffb30e7ac\"/>\n    <release version=\"1.96\" studipMinVersion=\"4.4\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/228b585fb229b0b3fdad83e7f259a5f3\"/>\n    <release version=\"1.95\" studipMinVersion=\"4.4\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/65f637fe00a73f9a809920d2a3a819bf\"/>\n    <release version=\"1.94\" studipMinVersion=\"4.4\" studipMaxVersion=\"5.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/feadcded7d1624244b21e6a2561729a0\"/>\n    <release version=\"1.93\" studipMinVersion=\"4.2\" studipMaxVersion=\"4.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/3bb11c8d492cf84f5fde04e06e2612f0\"/>\n    <release version=\"1.92\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/7f9bc19b9c898e41d903e7f32514611d\"/>\n  </plugin>\n  <plugin displayname=\"Unterrichtsplanung\" name=\"Unterrichtsplanung\" homepage=\"https://github.com/virtUOS/studip-unterrichtsplanung\" short_description=\"Erlernen von Strukturplanung des Unterrichts und erstellen von Unterrichtsentwürfen\" description=\"Das Plug-in „Unterrichtsplanung“ ermöglicht Anwender*innen, die Strukturplanung von Unterricht zu erlernen und eigene Unterrichtsentwürfe anzulegen. Diese Entwürfe können anschließend in verschiedene Dateiformate exportiert werden.&#10;&#10;Anwender*innen können berücksichtigte Zusammenhänge (Interdependenzen) zwischen den Planungsbereichen markieren, damit sie jederzeit den Überblick darüber behalten, welche Zusammenhänge sie schon bedacht haben. Außerdem werden im Plug-in Informationsbausteine mit wichtigen Hinweisen zu den Elementen von Unterrichtsentwürfen angeboten.&#10;&#10;Weitere Informationen zum theoretischen Hintergrund und der Funktionalität des Plug-ins:  &#10;https://www.youtube.com/watch?v=Mb6J3ub-DNs&#10;&#10;  &#10;Eine Vorlage für die Informationstexte finden Sie unter:  &#10;https://github.com/virtUOS/studip-unterrichtsplanung-infotexte  &#10;  &#10;**Ab Version 1.0 für Stud.IP 5 ist das Tool im Arbeitsplatz zu finden.**  &#10;  &#10; ---&#10;&#10;Das Plug-in wurde im DU-Projekt („Digitales Unterrichtscoaching im Bachelor Combined Studies mit Lehramtsoption“) an der Universität Vechta unter der Leitung des Arbeitsbereichs für Schulpädagogik und Allgemeine Didaktik (Prof. Dr. Daniel Scholl, Simon Küth, Dr.in Kathrin Rheinländer &amp;amp; Dr. Christoph Schüle) in Kooperation mit dem Zentrum für Lehrerbildung (ZfLB – Universität Vechta), dem ELAN e.V. und den Fachdidaktiken Mathematik (Prof. Dr. Björn Schwarz), Sport (Prof.in Dr.in Petra Wolters) und Geographie (Prof.in Dr.in Martina Flath &amp;amp; Hannah Lathan) entwickelt. Die Finanzierung erfolgte durch Qualität Plus – Programm für gute Lehre in Niedersachsen (Niedersächsisches Ministerium für Wissenschaft und Kultur).\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/9138068929a0dfaf418ded76b1a63d8b\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/1735e6cdee5eade376801a0f887c1701\">\n    <release version=\"1.1.0\" studipMinVersion=\"5.3\" studipMaxVersion=\"5.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/92600857212eea42739564f54b0ad011\"/>\n    <release version=\"1.0.1\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8d93f5389770a3d1b9b3e70154375f52\"/>\n    <release version=\"1.0\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/17572889dd91d5e34e5e1f780a744ac8\"/>\n    <release version=\"0.1.3\" studipMinVersion=\"4.2\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/098b2eaa8b534fbedb326fed2d35c512\"/>\n    <release version=\"0.1.2\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/805a6b5dcfef3f2a4f43159bef839d03\"/>\n  </plugin>\n  <plugin displayname=\"Unterrichtsplanung (data-quest für 6.0)\" name=\"Unterrichtsplanung-DQ\" homepage=\"\" short_description=\"Das Unterrichtsplanung-Plugin angepasst für die 6.0\" description=\"Dies ist das Unterrichtsplanung-Plugin angepasst für die 6.0 von Stud.IP. Viel Spaß!\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/99a411110d4e119f453763d9874b9310\">\n    <release version=\"1.3\" studipMinVersion=\"6.0\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e2431046342be58088e23f7640238372\"/>\n  </plugin>\n  <plugin displayname=\"Unterstützung Studiendekanat\" name=\"Studiendekanat\" homepage=\"\" short_description=\"Mit dem Plugin wird bestimmten Nutzern die Möglichkeit gegeben, gezielt eine Gruppe von Studierenden zu benachrichtigen. Zur Auswahl wird Studiengang/Studiensemester oder Teilnahme an Veranstaltungen einer Einrichtung angeboten. Die Liste mit Studierenden kann als .csv herunter geladen werden, oder man kann direkt in das Stud.IP Nachrichtensystem springen. Man muss im Plugin festlegen, welche Nutzer Zugriff auf Daten für welche Studiengänge/Einrichtungen haben.\" description=\"\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/1f825b3055dfbf0b3cc71b789e86bc32\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/763f3306fce4d3ab44d6bf2a30f5f0aa\">\n    <release version=\"1.3.2\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5b2a604e573e82d3a47f7d8042427271\"/>\n    <release version=\"1.2.4\" studipMinVersion=\"5.1\" studipMaxVersion=\"5.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ec7822c88d682084c6a7094df3b6df27\"/>\n    <release version=\"0.8\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/d2d8774a0942c02be4ee3b4a9652395d\"/>\n    <release version=\"0.76\" studipMinVersion=\"2.5\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b0c840fc2404f3f1d174b75206e290e1\"/>\n  </plugin>\n  <plugin displayname=\"UserAdminArea\" name=\"UserAdminArea\" homepage=\"https://github.com/Krassmus/UserAdminArea\" short_description=\"Admin-Bereich, um mehrere Nutzer per Bulk-Aktion zu bearbeiten\" description=\"\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/84f53b3b5c272a617b1261c66700c6ba\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/3e1c6a9a9b2798feb6d2d0b20c5567d0\">\n    <release version=\"2.3\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/57934381a4544b21e0ecb36ab5390fd2\"/>\n    <release version=\"1.8\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a013ce00f6b583ed34d36e5ab5220bb9\"/>\n    <release version=\"1.6.1\" studipMinVersion=\"4.2\" studipMaxVersion=\"4.3\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/f02ab9ac151f73d2b7a13e3608bae89e\"/>\n    <release version=\"1.5\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.3\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/eb5c591ae8ab7716fdd167e7f82a4511\"/>\n    <release version=\"1.4\" studipMinVersion=\"3.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/31008789003ec206efa4da55cc3a40b8\"/>\n  </plugin>\n  <plugin displayname=\"UserKillPlugin\" name=\"UserKillPlugin\" homepage=\"\" short_description=\"Löscht viele Benutzer gleichzeitig. Funktionalität war vor Version 2.1 im Kern.\" description=\"\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/8e5caa14898bce1419210b317d4201bd\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/32c2294667a5c6343714909c21a73b78\">\n    <release version=\"8.1.1\" studipMinVersion=\"4.2\" studipMaxVersion=\"4.99.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8b949e10ee31e1c458b36594600e4123\"/>\n    <release version=\"8\" studipMinVersion=\"3.4\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/68c4ad7e488df95ef190c9dca517ddcc\"/>\n    <release version=\"7\" studipMinVersion=\"3.0\" studipMaxVersion=\"3.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b71a4b0e9a66a219375bfb8b44ee0e31\"/>\n    <release version=\"5\" studipMinVersion=\"2.3\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/d53f45e0ae6cca9f042f4e91681eb91c\"/>\n    <release version=\"4\" studipMinVersion=\"4\" studipMaxVersion=\"\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ecdbff3d867975d9186844d40bcdd809\"/>\n  </plugin>\n  <plugin displayname=\"VacationMessagePlugin\" name=\"VacationMessagePlugin\" homepage=\"\" short_description=\"Ermöglicht es, eine Abwesenheitsnachricht in Stud.IP einzugeben.\" description=\"Durch dieses Plugin können alle Nutzer eine Abwesenheitsnotiz angeben. Das machen sie unter Nachrichten in der Sidebar unter Aktionen &amp;quot;Abwesenheitsnachricht konfigurieren&amp;quot;. Dort kann man einstellen, von wann bis wann die Nachricht gelten soll. Dafür bietet sich beispielsweise ein Urlaubszeitraum an.  &#10;  &#10; Wird man dann mit einer Stud.IP-Nachricht angeschrieben, so wird automatisch die Abwesenheitsnachricht zurück geschrieben, sodass der Sender weiß, wann er oder sie mit einer Antwort rechnen kann.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/79919de962a04ec2e4ab7c38c2a985c2\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/0052d448346199cd961292580eabc542\">\n    <release version=\"1.0\" studipMinVersion=\"\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8bb2f8e0966fea39197d4e9568d12f75\"/>\n    <release version=\"1.0\" studipMinVersion=\"\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c9bac5690e710eb2610d975e41c79e16\"/>\n  </plugin>\n  <plugin displayname=\"Veranstaltungs-Vervielfältiger\" name=\"SeminarReplicator\" homepage=\"https://github.com/noackorama/SeminarReplicator\" short_description=\"Ein Stud.IP Plugin für Administratoren. Man kann damit beliebig viele Kopien einer vorhandenen Veranstaltung erzeugen. Der Name und die Nummer der Kopien sind änderbar, ebenso die Liste der Dozenten. Bei Bedarf können die Teilnehmer mitkopiert werden.\" description=\"\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/48e1a137c1fd3dba70a54c555192ec8a\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/965c372abf0ca29fbb9cf32931c2f0c8\">\n    <release version=\"4\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2d6bdac67bbdfd9ac7f838a443b890e2\"/>\n    <release version=\"3\" studipMinVersion=\"2.3\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fb5ad428278bf95d7b540e8e327f3b1b\"/>\n    <release version=\"2\" studipMinVersion=\"2\" studipMaxVersion=\"\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a138c5bfeaabf654be8650749d47c0fe\"/>\n  </plugin>\n  <plugin displayname=\"Veranstaltungslisten\" name=\"VeranstaltungsListen\" homepage=\"\" short_description=\"Manchmal gehören Veranstaltungen einfach zusammen. Man möchte schnell auf eine andere Veranstaltung aus einem Verbund wechseln, man möchte zeigen, welche Veranstaltungen ähnlich sind, ähnliche Themen behandeln, vielleicht für das selbe Modul interessant sind.\" description=\"****Hinweis für alle meine Plugin: Getestet bis Stud.IP 2.3.1, Support für künftige Versionen ungeklärt****&#10;&#10;*Manchmal gehören Veranstaltungen einfach zusammen. Man möchte schnell auf eine andere Veranstaltung aus einem Verbund wechseln, man möchte zeigen, welche Veranstaltungen ähnlich sind, ähnliche Themen behandeln, vielleicht für das selbe Modul interessant sind.*&#10;&#10;  &#10;&#10; Dieses Plugin ermöglicht es, diese Veranstaltungen in &amp;quot;Veranstaltungslisten&amp;quot; zu bündeln. Diese stehen dann auch in der entsprechenden Einrichtung zur Verfügung*. *\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/07b00f79ab6161ce27596ea8009f577e\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/6a5b9ab071f5c5a3e28394276b32ae7e\">\n    <release version=\"0.9.4\" studipMinVersion=\"2.3\" studipMaxVersion=\"2.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8bb91fa3edf4509718be35b77d062321\"/>\n    <release version=\"0.9.1\" studipMinVersion=\"2.3\" studipMaxVersion=\"2.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b5cb048c3cd9c4860878481d9704ec21\"/>\n  </plugin>\n  <plugin displayname=\"Veranstaltungsnummern\" name=\"Veranstaltungsnummern\" homepage=\"\" short_description=\"Dieses Plugin generiert automatisch Veranstaltungsnummern basierend auf der Einrichtungshierarchie\" description=\"****Hinweis für alle meine Plugin: Getestet bis Stud.IP 2.3.1, Support für künftige Versionen ungeklärt****&#10;&#10; Dieses Plugin dient dazu, fortlaufende Veranstaltungsnummern zu generieren. Hierzu erhalten Einrichtungen ein &amp;quot;Einrichtungskürzel&amp;quot; als Freitextfeld. Dieses wird von Administratoren gefüllt. Aus dem Baum wird dann durch das Plugin die Veranstaltungsnummer generiert und gespeichert. Beispiel: Eine Veranstaltung im Baum&#10;&#10; Phil.soz. Fakultät =&amp;gt; IMB =&amp;gt; Medienlabor =&amp;gt; Veranstaltung&#10;&#10; erhält eine Nummer in der Form 04 01 03 01&#10;&#10; möglich wäre natürlich auch etwas in der Form psf imb ml 01&#10;&#10; Das Plugin verfügt über eine Konfigurations-Datei, mit der die Form der Nummer beeinflusst werden kann. Zudem besteht ein Vorschaumodus, so dass sich vor dem Speichern kontrollieren lässt, ob die generierten Nummern den eigenen Vorstellungen entsprechen.&#10;&#10; Kurzanleitung:&#10;&#10;- Plugin installieren&#10;- Kopieren, Bearbeiten und Konfigurieren der  veranstaltungsnummern-config.inc.php&#10;- Freitextfeld für Einrichtungen einrichten (z.B. \\\\\\&amp;quot;Einrichtungskürzel\\\\\\&amp;quot; )&#10;- jeweils für Fakultät und Einrichtungen Werte eintragen.&#10;- Plugin aufrufen.&#10;&#10; Bugfixe in 0.8:&#10;&#10;- Anzeige falschen Einrichtungsnamens in der Vorschau&#10;- Limitierung der Einrichtungsauswahlliste auf das Datenfeld Einrichtungskürzel&#10;&#10; Version 0.9.5&#10;&#10;- Diverse Überarbeitungen\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/2d6d3c21f5c8821fd4fc72b8109e2b71\">\n    <release version=\"0.9.9\" studipMinVersion=\"2.0\" studipMaxVersion=\"2.3.1\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/75f01c2d86018b3eb1d7da31d660985c\"/>\n    <release version=\"0.9.8\" studipMinVersion=\"2.0\" studipMaxVersion=\"2.3.1\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/0418e11665f743878d8e34a6e0c3e5a0\"/>\n    <release version=\"0.9.5\" studipMinVersion=\"2.0\" studipMaxVersion=\"2.3\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/94018db973e98a9dff4f6ffb5a9e01d5\"/>\n    <release version=\"0.8\" studipMinVersion=\"2.0\" studipMaxVersion=\"2.3\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/388a85bb0e2fc835d9c2984689091635\"/>\n  </plugin>\n  <plugin displayname=\"Veranstaltungsplanung\" name=\"Veranstaltungsplanung\" homepage=\"https://github.com/Krassmus/Veranstaltungsplanung/\" short_description=\"Verwaltung von Veranstaltungsterminen in einer Wochenansicht. Kann regelmäßige und unregelmäßige Termine mehrerer Veranstaltungen gleichzeitig behandeln.\" description=\"Dieses Plugin will ein inofizieller Nachfolger des oder zumindest eine Alternative zum e-Terminplaner sein. Man kann damit als Admin Veranstaltungen filtern und die Termine dieser Verantaltungen einsehen und Überschneidungen erkennen. Zudem kann man neue Termine anlegen oder bestehende verschieben. Unterstützt die neue Ressourcenverwaltung ab Stud.IP 4.5.  &#10;  &#10; Features:&#10;&#10;- Arbeiten in mehreren Reitern des Browsers.&#10;- Filtern der Veranstaltungen per Freitext-Suche, Semester, Einrichtungen, Studienbereiche und Sichtbarkeit. Weitere Filter wären einfach nachzubauen - sogar per Plugin.&#10;- Benutzerdefinierte Sidebar, damit man nur die Filter sieht, die man wirklich braucht.&#10;- Filter nach Personen, damit man schnell sieht, wann ein Lehrender einer Einrichtung einen freien Termin hat.&#10;- Filtern nach Ressourcen, damit man sehen kann, wann Räume in Gebäude x frei sind.&#10;- Monatsansicht parallel zur Wochenansicht.&#10;- Beim Verschieben von Terminen per Drag &amp;amp; Drop wird einem grau hinterlegt angezeigt, zu welchen Zeitpunkten der Termin nicht verschoben werden kann (weil da der Raum oder der Lehrende schon etwas anderes vor haben).&#10;- Regelmäßige Termine können genau wie unregelmäßige erstellt und bearbeitet werden.&#10;- Im Bearbeitendialog kann man entweder den Einzeltermin oder alle Termine der Terminserie bearbeiten.&#10;- Mit rechter Maustaste kann man im Kontextmenü eines Termins durchführende Dozenten, Gruppen und Themen super schnell bearbeiten.&#10;&#10;  &#10;  &#10; Benutzerhilfe gibt es hier: https://github.com/Krassmus/Veranstaltungsplanung/blob/master/hilfe.md\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/5dff4765843c557be70c8163699d9720\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/38239870191eb6657c08d2e3195f2762\">\n    <release version=\"1.9.3\" studipMinVersion=\"5.3\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/0dc20af86954a89e79f3c2ac80e73750\"/>\n    <release version=\"1.9.3\" studipMinVersion=\"5.3\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/57a248621b49b6664f473c6a1d2394fa\"/>\n    <release version=\"1.8.1\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.4\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fb98f5ec73bf023d11df2ce364e9ee06\"/>\n    <release version=\"1.4.6\" studipMinVersion=\"4.5\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/83e1e5f9be15bf7655d3edc97c902e14\"/>\n    <release version=\"1.4.2\" studipMinVersion=\"4.5\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/1e54b781d6b064919a20029a87ea2271\"/>\n    <release version=\"1.4.1\" studipMinVersion=\"4.5\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/cac354a8b0a5d54a2414cdf3399e97d2\"/>\n    <release version=\"1.3.4\" studipMinVersion=\"4.5\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/20863c008ea6207d56ea1a4ef951a32f\"/>\n    <release version=\"1.3\" studipMinVersion=\"4.5\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/6c31314622c03bf1c6e79c7dafa7a8be\"/>\n    <release version=\"1.1.6\" studipMinVersion=\"4.4.99\" studipMaxVersion=\"4.6.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/bb7596324d9a6ffac6bba99e012a3335\"/>\n  </plugin>\n  <plugin displayname=\"Vips\" name=\"Vips\" homepage=\"\" short_description=\"Online-Erstellung und Durchführung von Übungen, Tests und Klausuren\" description=\"Vips steht für Virtuelles Prüfungssystem. In Vips können Übungen, Tests und Klausuren online vorbereitet und durchgeführt werden. Die Lehrenden erhalten eine Übersicht darüber, welche Studierende eine Übung oder einen Test mit welchem Ergebnis abgeschlossen haben. Im Gegensatz zu herkömmlichen Übungszetteln oder Klausurbögen sind mit Vips alle Texte gut lesbar und sortiert abgelegt. Lehrende erhalten sofort einen Überblick darüber, was noch zu korrigieren ist. Ferner können auch Übungsgruppen verwaltet werden. Ab der Version 1.5 ist es auch möglich, zusätzliche Aufgabentypen als Plugins zu entwickeln.  &#10;  &#10;Änderungshistorie:&#10;&#10;- Version 1.9.9: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.9.9- Fehler beim Speichern des Testblocks in der Courseware korrigiert (ab PHP 8.1)&#10;- Vips kann das Datenfeld für die Matrikelnummer im Kern verwenden (ab Stud.IP 5.5)&#10;- Auswertung der Reihenfolgeaufgabe erlaubt nun auch mehrere Elemente mit identischem Text&#10;- Version 1.9.8: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.9.8- Fehler bei der Auswertung von Multiple Choice Aufgaben mit PHP 8 korrigiert&#10;- Zeichenwähler im Lückentext funktioniert nun wieder (Stud.IP 5.3 und neuer)&#10;- Darstellungsfehler in Multiple Choice Matrix behoben&#10;- Version 1.9.7: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.9.7- Aufgabentyp Reihenfolge ermöglicht das Umsortieren der Antworten beim Erstellen/Bearbeiten&#10;- Anzeigefilter &amp;quot;beendete Klausuren&amp;quot; in der Ergebnisliste zeigt auch komplett leer abgegebene Klausuren an&#10;- Fehlerkorrekturen bei der Lückentextaufgabe&#10;- Version 1.9.6: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.9.6- Lückentext im Modus &amp;quot;Auswahl aus Liste&amp;quot; und &amp;quot;Ziehen und Ablegen&amp;quot; unterstützt LaTeX-Formatierung in Antworten&#10;- Fehlerkorrektur bei Zuordnungs- und Reihenfolgeaufgaben (in Verbindung mit PHP 8.x)&#10;- Editor-Toolbar war in hinzugefügten Antwortoptionen kaputt (Stud.IP 5.3 und neuer)&#10;- Darstellungsfehler im Lückentext behoben (Stud.IP 5.3 und neuer)&#10;- Version 1.9.5: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.9.5- Unterstützung der Stud.IP-Version 5.4&#10;- Selbsttests können nun auch explizit abgegeben werden und erscheinen dann unter &amp;quot;Ergebnisse&amp;quot;&#10;- Fehlerkorrekturen bei der Eingabe und Anzeige formatierter Texte in Antwortoptionen&#10;- Version 1.9.4: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.9.4- Unterstützung von Stud.IP 5.3 und PHP 8.2&#10;- Ausblenden von Vips für Studierende ändert auch die Einstellung auf der &amp;quot;Mehr…&amp;quot;-Seite&#10;- Fehlerkorrektur im Klausurmodus, wenn Vips im Kurs mit der Klausur unsichtbar geschaltet ist&#10;- Version 1.9.3: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.9.3- Persönliche Aufgabensammlung wird nun generell auch Studenten angeboten&#10;- zusätzliche Freigabeeinstellungen für Übungen und Selbsttests (die gleichen wie bei Klausuren)&#10;- Fehlerkorrekturen bei Lückentext und der LTI-Aufgabe (externe Aufgabe)&#10;- Version 1.9.2: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.9.2- Einstellungen eines Aufgabenblatts sind beim Neuanlegen nun immer aufgeklappt&#10;- Fehler beim Anlegen einer Aufgabe in der persönlichen Aufgabensammlung in Stud.IP 5.2 behoben&#10;- Dateien zu Aufgaben werden auch exportiert, wenn SENDFILE_LINK_MODE auf &amp;quot;rewrite&amp;quot; steht&#10;- Version 1.9.1: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.9.1- Einstellung für Selbsttest: Lösungen erst nach Beenden des Tests anzeigen (statt nach drei Versuchen)&#10;- Fehlerkorrekturen bei der Zuordnungsaufgabe und beim Zurücksetzen von Lösungen in Klausuren&#10;- Voreinstellung für &amp;quot;Liste der Dateien unter dem Aufgabentext anzeigen&amp;quot; geändert&#10;- Version 1.9: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.9- Persönliche Aufgabensammlung unabhängig von konkreten Lehrveranstaltungen&#10;- neuer Aufgabentyp Reihenfolge: Anordnung von Elementen in einer Reihenfolge&#10;- verbesserte Dialoge zum Hinzufügen von Aufgaben und Kopieren von Aufgabenblättern&#10;- zusätzlich zur Texteingabe können Dateien als Anhang zur Korrektur hochgeladen werden&#10;- Freigabe der Musterlösung auch für Selbsttests wieder einstellbar und nicht mehr voreingestellt&#10;- Export des Aufgabenblatts in Textformat wurde entfernt (der Import ist weiterhin möglich)&#10;- Version 1.8.8: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.8.8- Version 2.x des Opencast-Plugins läuft nicht mehr in einen Fehler (temporärer Workaround)&#10;- Fehlermeldung beim Aufruf der Verwaltung von Übungsgruppen in Stud.IP 5.2 behoben&#10;- Antwortvorgaben im Lückentext können mit Anführungszeichen umgeben werden, um Steuerzeichen zu maskieren&#10;- Version 1.8.7: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.8.7- Unterstützung der Stud.IP-Versionen 5.1 und 5.2&#10;- neu implementierter Courseware-Block (ab Stud.IP 5.0)&#10;- Titel der Druckansicht enthält den Namen des Aufgabenblatts (und ggf. Teilnehmers)&#10;- Fehlerkorrektur bei Lückentextaufgaben ohne hinterlegte auswertbare Antworten&#10;- Version 1.8.6: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.8.6- Unterstützung von Stud.IP 5.0 - aber noch ohne Courseware-Block&#10;- Sammelaktionen für Aufgaben (Kopieren, Verschieben und Löschen)&#10;- Vorschauansicht der Teilnahmebedingungen zu einer Klausur&#10;- Lösungen können als (noch) nicht fertig korrigiert markiert werden&#10;- Nachricht an alle Teilnehmer eines Aufgabenblatts versenden&#10;- Fehlerkorrekturen bei Lückentext und Multiple Choice Matrix&#10;- Version 1.8.5: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.8.5- Fortschrittsanzeige in der Ergebnisübersicht (gewichtet nach erreichbaren Punkten)&#10;- Abgabe einer Bemerkung zu einer ansonsten leeren Lösung ist wieder möglich&#10;- leere Eingaben im Lückentext werden nicht mehr als numerische Werte ausgewertet&#10;- Version 1.8.4: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.8.4- Zuweisung von Räumen als IP-Zugriffsbereiche für Klausuren&#10;- Klausurmodus erlaubt wieder Zugriff auf aus dem Dateibereich eingebundene Medien&#10;- Fehlerkorrektur in der Auswertung des numerischen Wertevergleichs (Freie Antwort, Lückentext)&#10;- Version 1.8.3: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.8.3- Export aller Antworten zu einem Aufgabenblatt hinzugefügt&#10;- Fehlerkorrektur beim Import von Lückentextaufgaben&#10;- Fehlerkorrektur in der Termauswertung (Aufgabentyp &amp;quot;Algebraischer Term&amp;quot;)&#10;- Version 1.8.2: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.8.2- Freigabe der Lösungen für Übungsblätter bei Abgabe in Übungsgruppen korrigiert&#10;- Korrekturen nicht abgegebener Aufgaben tauchen nicht mehr im Abgabeprotokoll auf&#10;- Voreinstellung für &amp;quot;Liste der Dateien unter dem Aufgabentext anzeigen&amp;quot; geändert&#10;- Erweiterung des Zeichenwählers: Türkisch&#10;- Version 1.8.1: https://gitlab.studip.de/uni-osnabrueck/plugins/vips/-/issues?state=closed&amp;amp;milestone_title=1.8.1- Textaufgaben im Selbsttest zeigen nun nach der ersten Abgabe die Musterlösung an&#10;- unbearbeitete Aufgaben werden für Teilnehmer nicht mehr als korrigiert angezeigt&#10;- Länge der Eingabefelder im Lückentext bei der Einstellung &amp;quot;Feste Breite&amp;quot; reduziert&#10;- Performance-Verbesserung der Punkte- und Notenübersicht&#10;- Version 1.8: https://plugin-dev.studip.de/trac/query?milestone=vips+1.8- Dateianhänge zu Aufgaben (Alternative zum Einbinden aus dem Dateibereich)&#10;- Integration in das Gradebook der Veranstaltung (ab Stud.IP 4.4)&#10;- Erweiterungen verschiedener Aufgabentypen:- Zuordnungsaufgabe: Unterstützung für Mehrfachzuordnungen&#10;- Lückentext: Zuordnung der Lösungen durch Ziehen und Ablegen&#10;- Freie Antwort, Lückentext: Auswertung numerischer Werte als Lösungen&#10;- Textaufgabe: Punktevorschlag basierend auf Textähnlichkeit (im Selbsttest)&#10;- Single Choice: Variante mit Enthaltungsmöglichkeit in den Basistyp integriert&#10;- Multiple Choice: Variante mit Enthaltungsmöglichkeit in neuen Aufgabentyp überführt&#10;- Multiple Choice Matrix: neuer Aufgabentyp mit beliebig vielen Antwortspalten&#10;- verbesserte Funktionen für Klausuren:- Zugriff auf Klausuren kann mit einem Passwort beschränkt werden&#10;- differenziertere Freigabeeinstellungen für Klausuren (z.B. &amp;quot;nur Punkte&amp;quot;)&#10;- manuelle Gewichtung funktioniert nun auch zusammen mit Klausurvarianten&#10;- Klausuren mit vorhandenen Abgaben können nur noch eingeschränkt bearbeitet werden&#10;- neue Funktionen für Selbsttests:- Selbsttests sind nun immer automatisch zur Ergebniseinsicht freigegeben&#10;- Anzahl der Versuche im Selbsttest ist konfigurierbar (analog zur Courseware)&#10;- Punkteübersicht kann auch die Ergebnisse von Selbsttests anzeigen&#10;- Speicherverbrauch beim Sammeldownload großer Dateiabgaben als ZIP reduziert&#10;- einige nicht mehr gepflegte Funktionen entfernt: QTI-Export, ECTS-Grades&#10;- Version 1.7.2: https://plugin-dev.studip.de/trac/query?milestone=vips+1.7.2- Notenverteilung kann jetzt auch mit Bruchteilen von Prozentwerten umgehen&#10;- &amp;quot;Aufgabe im LTI-Tool bearbeiten&amp;quot; funktioniert in der Externen Aufgabe wieder&#10;- Fehlerkorrektur bei allen Textaufgaben bzgl. Ignorieren der Groß-/Kleinschreibung im Textvergleich&#10;- Version 1.7.1: https://plugin-dev.studip.de/trac/query?milestone=vips+1.7.1- Bewertung textuell gleicher Antworten in Zuordnungsaufgaben korrigiert&#10;- Kopieren im Aufgabenpool ermöglicht jetzt, ein Kopierziel auszuwählen&#10;- Erweiterung des Zeichenwählers: Pinyin-Transkription&#10;- Version 1.7: https://plugin-dev.studip.de/trac/query?milestone=vips+1.7- Unterstützung von Stud.IP 4.6 und PHP 7.3&#10;- neuer Abgabemodus für Textaufgabe: keine Texteingabe, nur Upload&#10;- in Klausuren können die Aufgaben in zufälliger Reihenfolge präsentiert werden&#10;- Lösungen können direkt von der Seite &amp;quot;Ergebnisse&amp;quot; gedruckt werden, die separate Seite zum Drucken entfällt&#10;- Übersicht über laufende und geplante Klausuren (unter Admin &amp;gt; System &amp;gt; Vips-Einstellungen)&#10;- Verbesserungen der Verwaltung von Übungsgruppen:- Erstellung von vielen Gruppen auf einmal&#10;- Anzeige von Personen ohne Gruppenzugehörigkeit&#10;- Export der Personenzuordnungen&#10;- Erweiterungen des Zeichenwählers: Griechisch, Tschechisch, Polnisch&#10;- Version 1.6.1: https://plugin-dev.studip.de/trac/query?milestone=vips+1.6.1- Randomisierung der Items kann in Klausuren abgeschaltet werden&#10;- vollständig leere Abgaben (z.B. am Ende einer Klausur) werden nicht mehr gespeichert&#10;- Teilnehmer werden bei Verlassen des Kurses aus Übungsgruppen ausgetragen&#10;- Performance-Verbesserung auf der Korrekturseite bei großen Teilnehmerzahlen&#10;- Zeichenwähler funktioniert in der Courseware auch dann, wenn der Vips-Reiter abgeschaltet ist&#10;- Lösungskommentare werden als Aufklappelemente angezeigt, wenn nur Kommentare freigeschaltet sind&#10;- Version 1.6: https://plugin-dev.studip.de/trac/query?milestone=vips+1.6- Unterstützung der Stud.IP-Versionen 4.0 - 4.5&#10;- Umstellung der Aktionen in Tabellen auf Aktionsmenüs&#10;- Zugriff auf das Archiv alter Lösungsversionen bei der Korrektur&#10;- neue Seite für systemweite Einstellungen in Vips (unter Admin &amp;gt; System)&#10;- Aufgabenblätter in Blöcken können auf Teilnehmergruppen beschränkt werden&#10;- Drucken von Klausuren ist für Teilnehmer nicht mehr möglich&#10;- Erweiterungen für die Textaufgabe:- HTML-Editor (Textformatierungen) für die Abgabe aktivierbar&#10;- Anzeige abgegebener Bilddateien direkt in der Korrektur- und Druckansicht&#10;- Herunterladen aller abgegebenen Dateien als ZIP-Archiv&#10;- neue Funktionen für Klausuren:- Teilnahmebedingungen vor Beginn einer Klausur (systemweit einstellbar)&#10;- Teilnahme eines Studierenden kann vom Dozenten zurückgesetzt werden&#10;- Abgabeprotokoll pro Teilnehmer während/nach der Klausur einsehbar&#10;- Version 1.5.5: https://plugin-dev.studip.de/trac/query?milestone=vips+1.5.5- Suchfunktion beim Kopieren/Verschieben von Aufgabenblättern&#10;- Export von Lückentext-Aufgaben enthält nun auch die Aufgabenstellung&#10;- Fehlerkorrekturen beim Import: Aufgabenblatt konnte nicht freigegeben werden&#10;- Version 1.5.4: https://plugin-dev.studip.de/trac/query?milestone=vips+1.5.4- Antwortmodus im Lückentext kann pro Lücke einzeln gewählt werden&#10;- Autovervollständigung des Browsers ist bei Abgabe von Lösungen deaktiviert&#10;- Fehlerkorrekturen bei der Textaufgabe und der Lückentextaufgabe&#10;- Abstände zwischen den Formularfeldern sind nun einheitlich (in Stud.IP 4.x)&#10;- Version 1.5.3: https://plugin-dev.studip.de/trac/query?milestone=vips+1.5.3- Beschränkung der IP-Adresse für eine Klausur wird in der Druckansicht korrekt angewendet&#10;- Fehlerkorrekturen bei der Textaufgabe und beim Speichern von Bemerkungen zur Lösung&#10;- Version 1.5.2: https://plugin-dev.studip.de/trac/query?milestone=vips+1.5.2- Bearbeitung des Endzeitpunkts beim manuellen Starten eines Aufgabenblatts&#10;- kommentierte Lösung einer Textaufgabe wird nur bei Änderungen gespeichert&#10;- Version 1.5.1: http://plugin-dev.studip.de/trac/query?milestone=vips+1.5.1- Fehlerkorrekturen bei der Einbindung des WYSIWYG-Editors&#10;- fehlende Daten im XML-Export von Aufgabenblättern ergänzt&#10;- verbesserte CSRF-Absicherung der Editierfunktionen&#10;- nicht (in Vips) abgegebene Aufgaben können nun bewertet werden&#10;- Verlängerung der Restzeit beim Unterbrechen einer Klausur&#10;- individueller Zeitbonus für einzelne Klausurteilnehmer möglich&#10;- neue Funktion zum vorzeitigen Abgeben einer Klausur&#10;- Version 1.5: https://plugin-dev.studip.de/trac/query?milestone=vips+1.5- WYSIWYG-Editor von Stud.IP kann beim Erstellen der Aufgaben verwendet werden&#10;- Hinzufügen/Löschen von Antwortoptionen erfordern kein Zwischenspeichern der Aufgabe mehr&#10;- Gruppierung von Aufgabenblättern in Blöcken ist unabhängig von der Notenberechnung möglich&#10;- Vips-Reiter oder Blöcke von Aufgabenblättern können für Teilnehmer unsichtbar gemacht werden&#10;- Sammelaktionen für Aufgabenblätter (Löschen, Verschieben in anderen Kurs usw.)&#10;- komplette Überarbeitung der Seite zur Verwaltung der Übungsgruppen in Vips&#10;- Einbindung von Vips-Aufgaben in PmWiki (über spezielles Markup) wird nicht mehr unterstützt&#10;- Version 1.4.1: https://plugin-dev.studip.de/trac/query?milestone=vips+1.4.1- Klausuren können nun (wie Übungsblätter) auch Blöcken zugewiesen werden&#10;- Sortierung der Aufgabenblätter nach &amp;quot;Titel&amp;quot; führt nicht mehr zu einem SQL-Fehler&#10;- Zuordnungsaufgaben mit Distraktoren werden wieder korrekt gespeichert&#10;- Fehlerkorrekturen in der Druckansicht und im Text-Export&#10;- Version 1.4: https://plugin-dev.studip.de/trac/query?milestone=vips+1.4- Unterstützung der Stud.IP-Versionen 3.4 - 4.3&#10;- Zuordnungsaufgabe mit optionaler Zuordnung und zusätzlichen Distraktoren&#10;- Export der Daten und Dateien eines Nutzers (wird angeboten ab Stud.IP 4.2)&#10;- Löschen von Nutzern oder Veranstaltungen hinterläßt keine Relikte mehr in der Datenbank&#10;- spezielle Gruppierung von Klausuren wird nicht mehr unterstützt&#10;- Version 1.3.3: https://plugin-dev.studip.de/trac/query?milestone=vips+1.3.3- Unterstützung von Stud.IP 4.2 und PHP 7.2&#10;- Fehlerkorrekturen in der Druckansicht und im CSV-Export&#10;- Version 1.3.2: https://plugin-dev.studip.de/trac/query?milestone=vips+1.3.2- Abgabe von Dateien als Lösungen bei Textaufgaben&#10;- Fehlerkorrekturen für den Klausurmodus und die LTI-Aufgabe&#10;- Version 1.3.1: https://plugin-dev.studip.de/trac/query?milestone=vips+1.3.1- Behebung von Anzeigefehlern in den Stud.IP-Versionen 3.1 und 3.3&#10;- Version 1.3: https://plugin-dev.studip.de/trac/query?milestone=vips+1.3- Unterstützung der Stud.IP-Versionen 3.1 - 4.1&#10;- verbesserte Bedienung durch verstärkten Einsatz von Dialogen&#10;- vereinfachte Navig