load/050e45d974d64c9a4713ed9609822ca3\"/>\n  </plugin>\n  <plugin displayname=\"Visualisierung der Mail Queue\" name=\"Visualisierung der Mail Queue\" homepage=\"\" short_description=\"Darstellung der Mail Queue, um nicht zugestellte Mails zu identifizieren\" description=\"Zeigt an, welche Mails sich in der Mailqueue befinden und ob die Zustellung eventuell fehlgeschlagen ist.  &#10; Die Liste lässt sich als CSV exportieren.  &#10;  &#10; Update Ver 1.1:  &#10; - Anzeige der aktuellen Mailqueue und aller Einträge, die mindestens ein halbes Jahr alt sind, auf zwei getrennten Seiten  &#10; - Einträge lassen sich einzeln löschen, Einträge älter als ein halbes Jahr auch komplett\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/f639bf9ac05855c87e7db73d8310ca70\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/21d8ada64d9adbf3e258f5a22db556a0\">\n    <release version=\"2.0\" studipMinVersion=\"5.0\" studipMaxVersion=\"6.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/01a858bddbe95e62e0e3c805d2c37ef6\"/>\n    <release version=\"1.2\" studipMinVersion=\"\" studipMaxVersion=\"5.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/0ead37a3d3cf090f7a66841ad5d2d2e9\"/>\n    <release version=\"1.0\" studipMinVersion=\"\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/679ac35f82291728355f4ed26509e7e0\"/>\n  </plugin>\n  <plugin displayname=\"Vorlesungsverzeichnis\" name=\"Vorlesungsverzeichnis\" homepage=\"\" short_description=\"Öffentliches Vorlesungsverzeichnis\" description=\"Das Plugin liest alle sichtbaren Veranstaltungen aus und bietet Sie (wie man es von der Suche gewohnt ist) als Vorlesungsverzeichnis an.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/ba4fb172bc0ee4875380555e4c18cffe\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/a1469bf3d8be7f8f42f234aeb47b3050\">\n    <release version=\"2.3.1\" studipMinVersion=\"4.5\" studipMaxVersion=\"5.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/29c8064fef801f6679c43cb127c02368\"/>\n    <release version=\"2.2\" studipMinVersion=\"4.3\" studipMaxVersion=\"4.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/26954f63bd8d41f069965af0a2f03aee\"/>\n    <release version=\"2.1\" studipMinVersion=\"4.1\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/3bb15021b0e94873d5dff7d9e6937dd9\"/>\n    <release version=\"1.1\" studipMinVersion=\"3.3\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a44c54849003bde3008be69459af508b\"/>\n    <release version=\"1.0.9\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/b1882254cf4eba56cbbd3fa5481efdfd\"/>\n  </plugin>\n  <plugin displayname=\"VoteCreator\" name=\"VoteCreator\" homepage=\"https://github.com/Krassmus/VoteCreator\" short_description=\"Aus einer Liste im Wiki kann man eine Umfrage mit einem Klick machen.\" description=\"!logo: https://raw.githubusercontent.com/Krassmus/VoteCreator/master/assets/votecreator_logo.png VoteCreator&#10;==============================================================================================================&#10;&#10; Stud.IP-plugin: creates votes from lists in a wiki page.&#10;&#10; This works quite simple:&#10;&#10;- Go to a wiki page with some lists or add some lists there.&#10;- Click on the voteicon on the top-right corner of the list.&#10;- Now you should have jumped into the vote-section of studip with all the dots of the list as options of the upcoming voting.&#10;&#10; Now you can edit the options, set the duration of the voting and start the voting. After you started the voting you are redirected back to the wiki-page you just saw. Sadly you won&amp;#039;t see any success-message, but that is something this plugin can&amp;#039;t provide.&#10;&#10;!screenshot: https://raw.githubusercontent.com/Krassmus/VoteCreator/master/assets/votecreator_screenshot.png\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/2acd82d6b4477f463d99f3b772986a13\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/f692aef12f43a0b15bd6e262bcb2a645\">\n    <release version=\"1.0\" studipMinVersion=\"\" studipMaxVersion=\"\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/74cf71e55fe01120a4d505129260961c\"/>\n  </plugin>\n  <plugin displayname=\"WartungsterminPlugin\" name=\"Wartungstermin\" homepage=\"https://gitlab.studip.de/luh/plugins/WartungsterminPlugin\" short_description=\"Zeigt oben ein Banner für Wartungen an\" description=\"WartungsterminPlugin&#10;====================&#10;&#10;Zeigt oben ein Banner für Wartungen an. Es kann eingestellt werden, wann die Wartung stattfindet und ab wann das Banner angezeigt werden soll, des Weiteren kann zwischen den Farben Gelb, Rot und Blau unterschieden werden. Es kann eingestellt werden dass die Farbe 30 Minuten vor dem Termin automatisch die Farbe ändert. Das Banner verschwindet automatisch nach Ablauf der Wartung. Der Wartungstext kann in allen Sprachen eingestellt werden und wird in der entsprechenden Sprache angezeigt.&#10;&#10;Changelog&#10;=========&#10;&#10;**2024-11-18 v1.3**&#10;&#10;- 6.0-ready&#10;&#10;**2024-04-23 v1.2**&#10;&#10;- Countdown zeigt nun bei unter einer Stunde nicht mehr die Stunden an sondern nur noch die Minuten&#10;&#10;**2024-03-18 v1.1**&#10;&#10;- 5.3-ready&#10;&#10;**2023-06-13 v1.0**&#10;&#10;- Es kann nun eingestellt werden, dass 30 Minuten vor Beginn der Wartung die Farbe automatisch angepasst wird&#10;- Neben Gelb und Rot gibt es nun auch die Farbe Blau&#10;- Das gesamte Plugin wurde auf Englisch übersetzt&#10;- Der Wartungs-Text kann nun auch in allen Sprachen angegeben werden und wird entsprechend den Profileinstellungen in der jewiligen Sprache angezeigt\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/116ef491ac0187d5c9081fcf8f09c0c0\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/ae577d120b30be989bd654cbcbdc1023\">\n    <release version=\"1.3\" studipMinVersion=\"6.0\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/57492d2c48ca4aac6a963cd05fdbb6d6\"/>\n    <release version=\"1.2\" studipMinVersion=\"5.3\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fac1328f117fa265117e8b20bb5c4127\"/>\n    <release version=\"1.1\" studipMinVersion=\"5.3\" studipMaxVersion=\"6.0.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/674fdf9697e4489f3f57792ca3617a46\"/>\n    <release version=\"1.0\" studipMinVersion=\"5.3\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a25ea2169c5e3902291ec5c79bd5cafe\"/>\n    <release version=\"0.9.3\" studipMinVersion=\"5.3\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/d2cb096fb7bc3e960adc23083c59a124\"/>\n  </plugin>\n  <plugin displayname=\"WeatherWidget\" name=\"WeatherWidget\" homepage=\"\" short_description=\"Ein Widget zur Anzeige des Wetters\" description=\"\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/8b91a250707fc75bbc7b766c4d37989d\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/6127a81dcbe0bbf69033d0830166bcc8\">\n    <release version=\"1.0\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8e25f7b570c5e516b0acbc5e298f0991\"/>\n    <release version=\"1.0\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/c3df11ffb36b6250e03617f0fc6841dc\"/>\n    <release version=\"0.8\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/8cd5c61f53a4d8fc1db342d160518934\"/>\n  </plugin>\n  <plugin displayname=\"Wer lehrt wann und wo\" name=\"WerLehrtWo\" homepage=\"\" short_description=\"Mit diesem Plugin können die Veranstaltungen einer Lehrperson in einer bestimmten Woche angezeigt werden\" description=\"\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/03445d50ee4b977ca1a2a41a9cea9481\">\n    <release version=\"1.6.1\" studipMinVersion=\"5.5\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/fd76bba6e5f6d6eaa678a8ebd3d3ec43\"/>\n    <release version=\"1.6.0\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/e5c4314d4491651d020c3db4b4cb5d0f\"/>\n    <release version=\"1.5.0\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/36464e50020a76c181cd732361201f9e\"/>\n    <release version=\"1.4.1\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2d3a8076d48e4bc7a6be3853d2dab23e\"/>\n    <release version=\"1.4.0\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/dec78992122468100f5bc23869861b4e\"/>\n    <release version=\"1.3.7\" studipMinVersion=\"4.2\" studipMaxVersion=\"4.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/97dc00f2145c6d99fd75883a4028796d\"/>\n    <release version=\"1.3.6\" studipMinVersion=\"4.2\" studipMaxVersion=\"4.3.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/5e4ca32f0a7bc473e2cb95bee5a44274\"/>\n    <release version=\"1.1.7\" studipMinVersion=\"3.2\" studipMaxVersion=\"3.99.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/3339616452943bcc57f6853afd4cd0df\"/>\n    <release version=\"1.1.6\" studipMinVersion=\"3.2\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/3e560d3e01472377f13d65b293d72566\"/>\n    <release version=\"1.1.6\" studipMinVersion=\"3.2\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/a688242b1470599c96f78c008b095df7\"/>\n    <release version=\"1.1.5\" studipMinVersion=\"3.2\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/ad4322b7b02bf59d01a116e1939b4749\"/>\n  </plugin>\n  <plugin displayname=\"Wer war wo?\" name=\"WhoWasWhere\" homepage=\"https://gitlab.data-quest.de/studip-plugins-oeffentlich/WhoWasWhere.git\" short_description=\"Zeigt alle Veranstaltungen an, an denen eine Person teilgenommen hat, egal, in welcher Rolle\" description=\"Manchmal möchte man gerne wissen, an welchen Veranstaltungen eine bestimmte Person denn schon so teilgenommen hat, vielleicht auch nur für ein bestimmtes Semester oder einen bestimmten Status. Die Person selbst hat natürlich die Übersicht unter &amp;quot;Meine Veranstaltungen&amp;quot;, aber dann steht plötzlich ein Student im Prüfungssekretariat und behauptet steif und fest, er sei doch in dieser einen Vorlesung gewesen. Natürlich kann man ihn dann nicht einfach an den eigenen Rechner und einloggen lassen, um seine Veranstaltungen zu sehen. Daher gibt es dieses Plugin, das für Roots und Personen mit einer bestimmten Rolle diese Funktionalität bereitstellt. Das Plugin führt keinerlei Änderungen an der Datenbank durch, es wird nur eine neue Rolle &amp;quot;Wer hat wo teilgenommen&amp;quot; angelegt, alle Nutzer, die diese Rolle haben, finden das Plugin unter &amp;quot;Suche&amp;quot;.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/eb57363f7bf8ae997a963080351f2e32\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/1e6a38ee9561f7226ae5c2c05393ecce\">\n    <release version=\"1.8\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/01cb5f06c069e535c461a79f34177283\"/>\n    <release version=\"1.7\" studipMinVersion=\"4.0\" studipMaxVersion=\"4.9.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/95c06e1c0f7cc34353986ed607de7c96\"/>\n  </plugin>\n  <plugin displayname=\"Where is my Plugin?\" name=\"Where is my plugin?\" homepage=\"\" short_description=\"Veranstaltungsfilter, der nach aktiven Plugins filtert\" description=\"Wenn man nach einer Veranstaltung sucht, in der ein bestimmtes Plugin aktiviert ist, ist dieses Plugin genau das Richtige: Es fügt für Admins und Roots einen neuen Veranstaltungsfilter in die Sidebar hinzu.&#10;&#10;&#10;&#10;&#10;&#10; \" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/a54b5c8ba9ed33ef693077c508894375\">\n    <release version=\"0.3\" studipMinVersion=\"5.0\" studipMaxVersion=\"6.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/710916f6a0c3d31204194b6668fef798\"/>\n  </plugin>\n  <plugin displayname=\"Whiteboard-Plugin\" name=\"Whiteboard (Beta)\" homepage=\"https://gitlab.studip.de/uol/plugins/whiteboard-plugin\" short_description=\"Ein Plugin zum Einbinden von Excalidraw (https://excalidraw.com), ein kollaboratives Whiteboard, in Veranstaltungen und als Block für eine Courseware in Stud.IP\" description=\"Whiteboard Plugin für Stud.IP&#10;=============================&#10;&#10;Ein Plugin zum Einbinden von Excalidraw (https://excalidraw.com), ein kollaboratives Whiteboard, in Veranstaltungen und als Block für eine Courseware in Stud.IP. Die in Whiteboards eingetragenen Nutzerdaten können, im Gegensatz zu anderen Produkten wie Miro, datenschutzgerecht auf den eigenen Servern der Universität gespeichert werden.&#10;&#10;Das Plugin stellt unter der Kategorie &amp;quot;Aufgaben und Interaktion&amp;quot; einen neuen Courseware-Block zur Verfügung, dass ein Whiteboard darstellt. Es gibt außerdem pro Veranstaltung ein geteiltes Whiteboard, dass über den Reiter &amp;quot;Whiteboard&amp;quot; in der Veranstaltung aufgerufen werden kann.  &#10; &#10;&#10;Dokumentation&#10;=============&#10;&#10;Die Dokumentation für Betreiber*innen und Entwickler*innen befindet sich auf der Projekt-Seite in Gitlab: https://gitlab.studip.de/uol/plugins/whiteboard-plugin.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/4c99434d10d7ef8fb1dafc5b766774a1\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/d123480565839755cbcb58676fa036eb\">\n    <release version=\"0.1\" studipMinVersion=\"5.0\" studipMaxVersion=\"5.1\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/666c1c77eae36aa00aee949a98488b83\"/>\n  </plugin>\n  <plugin displayname=\"Wo ist mein Dozent\" name=\"WoIstMeinDozent\" homepage=\"https://github.com/Krassmus/WoIstMeinDozent\" short_description=\"Übersicht über die Veranstaltungstermine eines Dozenten. Damit man sehen kann ob der Dozent im Haus bzw. in einer Veranstaltung ist.Für die Auskunftsmöglichkeit für einen Bestimmten Personenkreis.Die Persönlichen Termine werden nicht berücksichtigt.\" description=\"Übersicht über die Veranstaltungstermine eines Dozenten. Damit man sehen kann ob der Dozent im Haus bzw. in einer Veranstaltung ist.Für die Auskunftsmöglichkeit für einen Bestimmten Personenkreis. Die Persönlichen Termine werden nicht berücksichtigt.&#10;&#10;Das Plugin stammt ursprünglich von Johannes Stichler von der HFWU Nürtingen-Geislingen (Account auf dem Develop-Server gelöscht) und wird von data-quest weiter portiert auf neue Versionen und buggefixt.\" image=\"https://develop.studip.de/studip/assets/images/icons/blue/plugin.svg\" score=\"10\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/93d2e7c64d4a5def6fe7eda7c36f1c25\">\n    <release version=\"2.4.3\" studipMinVersion=\"3.1\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/906c9fb4e6a0caf03d581d9a926744fa\"/>\n    <release version=\"2.0 beta\" studipMinVersion=\"2.2\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/806c1c5625643796c446e9f757659241\"/>\n  </plugin>\n  <plugin displayname=\"WordpressBlog\" name=\"WordpressBlog\" homepage=\"\" short_description=\"Das Plugin WordpressBlog ermoeglicht es, innerhalb eines Stud.IP ein Wordpress zu betreiben. Wordpress ist dabei optisch in Stud.IP integriert und auch an die Ankündigungen-Funktion angekoppelt. Root-Administratoren müssen sich gegenüber Wordpress nicht erneut authentifizieren sondern sind direkt eingeloggt.\" description=\"****Hinweis für alle meine Plugin: Getestet bis Stud.IP 2.3.1, Support für künftige Versionen ungeklärt****&#10;&#10;  &#10; WordPress ist das erfolgreichste  &#10; Publishing-System der Welt!  &#10;  &#10; Den Schwerpunkt bilden Ästhetik, Webstandards und Benutzerfreundlichkeit. WordPress basiert auf PHP und MySQL, ist frei erhältlich, einfach zu installieren und wird allen Ansprüchen an einen professionellen Webauftritt gerecht.&#10;&#10;  &#10;&#10; Und dies kann nun auch innerhalb von Stud.IP genutzt werden. Beispiel-Installation: https://digicampus.uni-augsburg.de/kursverwaltung/blog/&#10;&#10;  &#10;&#10;**Installation**&#10;&#10; Nach der Installation ist das Plugin noch nicht nutzbar!&#10;&#10; Es werden zur Installation benötigt:&#10;&#10; Dateisystem- , Konsolen- und Datenbank-Zugriff.&#10;&#10; Die komplette Anleitung zur Installation befindet sich in der Datei INSTALLATION im Plugin.&#10;&#10;**Hinweis:**&#10;&#10; Getestet und produktiv in Stud.IP 2.3.1 mit Wordpress 3.6\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/8328caa748b14534b85a06a5deeef7ab\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/fecb8848aadfae402d0833afea994220\">\n    <release version=\"0.9.3\" studipMinVersion=\"2.2\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/305926004f6c74d92d0fc58bd884c22a\"/>\n    <release version=\"0.8\" studipMinVersion=\"2.2\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/2ebc4517af27152c0ed5e3dd3669718f\"/>\n  </plugin>\n  <plugin displayname=\"WTF Editor\" name=\"WTF Editor\" homepage=\"https://github.com/derfl0/WTFPlugin\" short_description=\"Ein WYSIWYG Editor für Stud.IP Markup\" description=\"WTF - WYSIWYG Tool by Flo&#10;&#10; Der WTF Editor ist in der Lage, jede Texteingabe in Stud.IP in einen &amp;quot;What you see is what you get&amp;quot; Editor umzuwandeln. Im Hintergrund wird der erzeugte Inhalt automatisch in Stud.IP Markup überführt. Somit kann jeder Nutzer über die Verwendung selbst entscheiden. Sogar Markupsprache kann direkt im WTF geschrieben werden.  &#10; Das Plugin ist jederzeit deaktivierbar, ohne Spuren im System zu hinterlassen.  &#10;  &#10; ACHTUNG!  &#10; Mit dem WYSIWYG Editor im Kern ist er nicht kombinierbar. Sollte dieser bereits aktiviert worden sein, ist eine Verwendung des Plugins nicht zu empfehlen.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/5c5f17ff1839a06ffe772962e05cabd7\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/67f33a8a401ebbecafa66df81e91b4e7\">\n    <release version=\"1.0\" studipMinVersion=\"2.4\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/4a3b232fc9daf05f8e3b35a06881b9f0\"/>\n  </plugin>\n  <plugin displayname=\"Youtube-Einbindung\" name=\"Youtube\" homepage=\"http://develop.studip.de/studip\" short_description=\"Proof of Concept für die neue Möglichkeit die Stud.IP-Formatierungssyntax durch PlugIns zu erweitern.Mit der Syntax[youtube]a1b2c3d4[/youtube]läßt sich das Youtube-Video mit der ID &amp;quot;a1b2c3d4&amp;quot; unmittelbar in Forenpostings, Wiki-Seiten oder auf der eigenen Profilseite einbinden.\" description=\"Einbindung und direktes Abspielen von Youtube-Videos in Stud.IP. Funktioniert im Gegensatz zu opengraph (nur Blubber) auch im Wiki, im Forum, in Ankündigungen oder auf der persönlichen Profilseite.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/712e85f230e610b8150e60f898714ae6\" score=\"4.012241957752\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/92796442bb7462e0bbdb9a1901790fbd\">\n    <release version=\"0.0.5\" studipMinVersion=\"2.3\" studipMaxVersion=\"3.2.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/cb1b0284326b59982e0304045f389c71\"/>\n    <release version=\"0.0.4\" studipMinVersion=\"2.3\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/3e7508b475f58bc28574fc84b90e40bc\"/>\n  </plugin>\n  <plugin displayname=\"Zeitgesteuerte Dateiordner\" name=\"TimedFolders\" homepage=\"https://vcs.zim.uni-passau.de/referat-applikationen/stud.ip/timedfolders\" short_description=\"Erlaubt zeitgesteuerte Anzeige von Dateiordnern\" description=\"Dieses Plugin stellt einen neuen Ordnertyp für den Dateibereich zur Verfügung, der es erlaubt, einen Start- und Endzeitpunkt für die Sichtbarkeit dieses Ordner anzugeben.  &#10;  &#10; Lehrende/Tutoren sehen den Ordner immer, Studierende nur innerhalb des festgelegten Zeitraums. Im Infodialog wird aufgeführt, von wann bis wann der Ordner sichtbar ist.  &#10;  &#10; Es kann auch nur ein Start- oder Endzeitpunkt angegeben werden.  &#10;  &#10; Ebenfalls können Berechtigungen gesetzt werden, sodass dieser Ordnertyp als Hausaufgaben- oder Materialordner verwendbar ist, nur eben noch zusätzlich zeitgesteuert sichtbar.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/ff97d188f250e561e9b2d68a2ffecb08\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/0fea6e0b61147587d5000c350f5d80e4\">\n    <release version=\"1.1\" studipMinVersion=\"4.0.alpha-svn\" studipMaxVersion=\"4.1.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/9d394e4eada2cb4c9d52c08f2096d15b\"/>\n  </plugin>\n  <plugin displayname=\"Zoom-Meetings\" name=\"Zoom-Meetings\" homepage=\"https://gitlab.data-quest.de/studip-plugins-oeffentlich/zoom\" short_description=\"Zoom-Meetings für Stud.IP\" description=\"Zoom für Stud.IP&#10;================&#10;&#10;WICHTIGE ÄNDERUNG!&#10;------------------&#10;&#10;Ab 01.06.2023 unterstützt die Zoom-API die Authentifizierungsmethode &amp;quot;JWT&amp;quot; nicht mehr. Daher verwenden Sie bitte das Plugin in der Version &amp;gt;= 1.5.0 und legen gemäß weiter unten stehender Anleitung eine neue App im Zoom Marketplace an, die &amp;quot;Server-to-Server-OAuth&amp;quot; anbietet. Bereits angelegte Apps im Zoom-Marketplace funktionieren nicht mehr, ebsnso wie dieses Plugin in allen Versionen &amp;lt; 1.5.0!&#10;&#10;Was macht dieses Plugin?&#10;------------------------&#10;&#10;&#10;&#10;Mit diesem Plugin können Sie Ihre Zoom-Meetings direkt von Ihren Stud.IP-Veranstaltungen aus anlegen und verwalten. Schicken Sie nie wieder kryptische Links oder Passwörter per Mail an potenzielle Teilnehmende oder posten Sie diese Daten in Ankündigungen Ihrer Veranstaltungen. Einfach das Meeting in Stud.IP anlegen, dort sehen Sie dann auch den entsprechenden Button, den man einfach nur klicken muss, um am Meeting teilzunehmen.&#10;&#10;Was muss ich tun, um das Plugin nutzen zu können?&#10;-------------------------------------------------&#10;&#10;### Anlegen einer Zoom-App&#10;&#10;Loggen Sie sich mit Ihrem Zoom-Account (der die Rechte haben muss, um Apps anzulegen) unter https://marketplace.zoom.us ein und klicken Sie rechts oben auf &amp;quot;Develop&amp;quot; -&amp;gt; &amp;quot;Build App&amp;quot;. Danach wählen Sie als App-Typ &amp;quot;Server-to-Server-OAuth&amp;quot;. Die App sollte am besten eine &amp;quot;Account Level&amp;quot;-App sein, damit alle Aktionen damit durchführbar sind. Veröffentlichen müssen Sie sie nicht. Der App müssen mindestens die Berechtigungs-Scopes &amp;quot;user:read:admin&amp;quot;, &amp;quot;meeting:write:admin&amp;quot; und (falls Sie auch Webinare nutzen) &amp;quot;webinar:write:admin&amp;quot; zugewiesen sein.&#10;&#10;### Installation in Stud.IP&#10;&#10;Sie brauchen nun die Einträge für ACCOUNT_ID, CLIENT_ID und CLIENT_SECRET aus den App-Daten. Diese Werte fügt Ihr Stud.IP-Root nach Installation des Plugins in Stud.IP einfach ein: Admin -&amp;gt; System -&amp;gt; Konfiguration -&amp;gt; Abschnitt &amp;quot;zoom&amp;quot;. Dort gibt es entsprechende Felder.&#10;&#10;Wenn Sie z.B. SSO für den Login verwenden, bekommen Sie eine eigene URL zum Zoom-Login (https://ihre-einrichtung.zoom.us).&#10;&#10;Am besten überprüfen Sie noch, ob das Plugin auch in den verschiedenen Veranstaltungskategorien verfügbar und/oder aktiviert ist.&#10;&#10;### FERTIG!&#10;&#10;Jetzt können Sie das Plugin in Veranstaltungen aktivieren und Meetings anlegen oder bestehende aus Zoom importieren und mit Ihrer Veranstaltung verknüpfen.&#10;&#10;Weiter haben Sie eine Übersicht neben &amp;quot;Meine Veranstaltungen&amp;quot;: &amp;quot;Meine Zoom-Meetings&amp;quot; listet alle Meetings in Ihren Veranstaltungen auf, filterbar nach Semester.&#10;&#10;Für Veranstaltungen mit mehr als 300 Teilnehmenden ist eine erweiterte Zoom-Lizenz nötig, darauf werden Sie hingewiesen. Falls Sie bereits eine solche Lizenz haben, wird automatisch der größere Typ &amp;quot;Webinar&amp;quot; statt &amp;quot;Meeting&amp;quot; verwendet. &#10;&#10;### Ich brauche Hilfe - was kann oder soll ich alles einstellen?&#10;&#10;Schauen sie sich gerne den Screencast unter https://vimeo.com/412311523/eae4c6fbcf an, der die Nutzung und die einzelnen Optionen erklärt.\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/1563e03363e2b11881ba10086579c8a2\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/b70475a45c4fbad7bc1a21976d8ce016\">\n    <release version=\"1.6.0\" studipMinVersion=\"4.2\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/13e71985b737de9e570527c1b7a4bc64\"/>\n    <release version=\"1.5.2\" studipMinVersion=\"4.2\" studipMaxVersion=\"5.4.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/61d11f4fbf82c04f0e245e2d496196c6\"/>\n  </plugin>\n  <plugin displayname=\"ZWW\" name=\"ZWW\" homepage=\"\" short_description=\"Ein Demo-Plugin. Manchmal sollen gewisse Nutzer ein anderes Design erhalten, um bspw. für gewisse Nutzergruppen eine andere Nutzungserfahrung zu ermöglichen.\" description=\"****Hinweis für alle meine Plugins: Getestet bis Stud.IP 2.3.1, Support für künftige Versionen ungeklärt****&#10;&#10; Dieses Plugin ist noch nicht produktiv in Betrieb, weshalb es als Demo-Plugin hochgeladen wird.&#10;&#10; Andere Institutionen würden dies wohl auch eher als Vorlage denn als direkt einsetzbares Plugin nutzen.&#10;&#10;**Die Idee hinter dem Plugin ist: **&#10;&#10; Unsere Einrichtung ZWW möchte Digicampus zwar nutzen, dem Teilnehmerkreis aber ein anderes Nutzungserlebnis bieten. Dafür wurde dieses Plugin entwickelt. Dieses passt das Design an, reduziert die Funktionalität und ermöglicht es einer gewissen Nutzergruppe, andere Dinge zu sehen als der Normalnutzer.&#10;&#10; Bei Bedarf kann diese Nutzergruppe aber auch das &amp;quot;normale&amp;quot; Layout aktivieren und aus der &amp;quot;Sandbox&amp;quot; ausbrechen.&#10;&#10;  &#10;&#10;**Konfiguration**&#10;&#10; Das Plugin lässt sich komplett über Stud.IP konfigurieren, eine Bearbeitung einer Config-Datei ist nicht nötig.&#10;&#10;- Zunächst muss eine Nutzerrolle existieren, die ein angepasstes Layout erhalten soll.&#10;- Dieser muss nun zunächst mindestens ein Nutzer zugewiesen werden.&#10;- In der globalen Konfiguration muss unter ZWW_USER_ROLE_ID die ID dieser Rolle hinterlegt werden.&#10;- Administratoren, die zugleich Mitglied dieser Nutzerrolle sind, haben die Möglichkeit auf der Startseite kompakte Informationen zu hinterlegen.&#10;&#10;  &#10;&#10;**Screenshots**&#10;&#10; Die Screenshots wurden zusammen mit den Plugins CustomStart, DigicampusHeader, PortalInfos und WordpressBlog produziert. Sind diese Plugins nicht aktiviert, so ist das Ergebnis abweichend.&#10;&#10;  &#10;&#10;**API**&#10;&#10; Wenn andere Plugins wissen möchten, ob ein Nutzer der Rolle angehört &amp;amp; ob er das Custom-Design aktiviert hat, so benötigt man folgenden Codeschnipsel:&#10;&#10;   $ZWW_PLUGIN =  PluginEngine::getPlugin(&amp;#039;ZWW&amp;#039;);  &#10;         if($ZWW_PLUGIN)  &#10;         {  &#10;             $USER_IS_ZWW_USER = $ZWW_PLUGIN-&amp;gt;isCurrUserZWWUser() &amp;amp;&amp;amp; $ZWW_PLUGIN-&amp;gt;isZWWViewEnabled();  &#10;         }&#10;&#10; (das ZWW-Plugin muss natürlich in der Ladereihenfolge vor diesem Plugin stehen)\" image=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/image/2e110cd2df751ab6099e2cce02c2c2bc\" score=\"\" marketplace_url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/details/012968937c7b6d9ec344a3518a07b693\">\n    <release version=\"0.6.1\" studipMinVersion=\"2.2\" studipMaxVersion=\"3.5.99\" url=\"https://develop.studip.de/studip/plugins.php/pluginmarket/presenting/download/7b0e738c819fd38a6375df9e9aad8b99\"/>\n  </plugin>\n</plugins>\n\";',1768407405),
('roles','a:15:{i:2;O:4:\"Role\":3:{s:6:\"roleid\";s:1:\"2\";s:8:\"rolename\";s:17:\"Administrator(in)\";s:10:\"systemtype\";b:1;}i:8;O:4:\"Role\":3:{s:6:\"roleid\";s:1:\"8\";s:8:\"rolename\";s:14:\"DedicatedAdmin\";s:10:\"systemtype\";b:0;}i:4;O:4:\"Role\":3:{s:6:\"roleid\";s:1:\"4\";s:8:\"rolename\";s:11:\"Lehrende(r)\";s:10:\"systemtype\";b:1;}i:15;O:4:\"Role\":3:{s:6:\"roleid\";s:2:\"15\";s:8:\"rolename\";s:15:\"Massenmail-Root\";s:10:\"systemtype\";b:0;}i:3;O:4:\"Role\":3:{s:6:\"roleid\";s:1:\"3\";s:8:\"rolename\";s:15:\"Mitarbeiter(in)\";s:10:\"systemtype\";b:1;}i:9;O:4:\"Role\":3:{s:6:\"roleid\";s:1:\"9\";s:8:\"rolename\";s:8:\"MVVAdmin\";s:10:\"systemtype\";b:0;}i:11;O:4:\"Role\":3:{s:6:\"roleid\";s:2:\"11\";s:8:\"rolename\";s:13:\"MVVEntwickler\";s:10:\"systemtype\";b:0;}i:10;O:4:\"Role\":3:{s:6:\"roleid\";s:2:\"10\";s:8:\"rolename\";s:11:\"MVVFreigabe\";s:10:\"systemtype\";b:0;}i:14;O:4:\"Role\":3:{s:6:\"roleid\";s:2:\"14\";s:8:\"rolename\";s:17:\"MVVLvGruppenAdmin\";s:10:\"systemtype\";b:0;}i:12;O:4:\"Role\":3:{s:6:\"roleid\";s:2:\"12\";s:8:\"rolename\";s:12:\"MVVRedakteur\";s:10:\"systemtype\";b:0;}i:13;O:4:\"Role\":3:{s:6:\"roleid\";s:2:\"13\";s:8:\"rolename\";s:13:\"MVVTranslator\";s:10:\"systemtype\";b:0;}i:7;O:4:\"Role\":3:{s:6:\"roleid\";s:1:\"7\";s:8:\"rolename\";s:6:\"Nobody\";s:10:\"systemtype\";b:1;}i:1;O:4:\"Role\":3:{s:6:\"roleid\";s:1:\"1\";s:8:\"rolename\";s:22:\"Root-Administrator(in)\";s:10:\"systemtype\";b:1;}i:5;O:4:\"Role\":3:{s:6:\"roleid\";s:1:\"5\";s:8:\"rolename\";s:14:\"Studierende(r)\";s:10:\"systemtype\";b:1;}i:6;O:4:\"Role\":3:{s:6:\"roleid\";s:1:\"6\";s:8:\"rolename\";s:9:\"Tutor(in)\";s:10:\"systemtype\";b:1;}}',1768437942),
